        // ===== DRAG & DROP =====
        (function() {
            function initDragDrop() {
                const pc = document.querySelector('.sidebar-photo');
                if (!pc) return;
                pc.addEventListener('dragenter', function(e) { e.preventDefault(); e.stopPropagation(); this.classList.add('drag-over'); });
                pc.addEventListener('dragover', function(e) { e.preventDefault(); e.stopPropagation(); this.classList.add('drag-over'); });
                pc.addEventListener('dragleave', function(e) { e.preventDefault(); e.stopPropagation(); this.classList.remove('drag-over'); });
                pc.addEventListener('drop', function(e) {
                    e.preventDefault(); e.stopPropagation();
                    this.classList.remove('drag-over');
                    var files = e.dataTransfer && e.dataTransfer.files;
                    if (files && files.length > 0 && files[0].type.startsWith('image/')) {
                        var reader = new FileReader();
                        reader.onload = function(ev) {
                            var dataURL = ev.target.result;
                            // Per-person routing — same pattern as handleAvatarUpload.
                            // BUG FIX: previously this only wrote planOwnerPhotoURL,
                            // skipping p.photo/p.album on record-view. So drag&drop
                            // on John's record didn't update John's photo or album,
                            // leaving the avatar stuck on the seed image.
                            if (window.__paIsRecordView) {
                                var p = (typeof window.peopleById === 'function') ? window.peopleById('sj') : null;
                                if (p) {
                                    p.photo = dataURL;
                                    p.cropX = 50; p.cropY = 50; p.scale = 1;
                                    if (!Array.isArray(p.album)) p.album = [];
                                    if (p.album[p.album.length - 1] !== dataURL) p.album.push(dataURL);
                                    window.__paPhotoOverride = dataURL;
                                    if (typeof window.paAutoSave === 'function') window.paAutoSave();
                                }
                            } else {
                                planOwnerPhotoURL = dataURL;
                                planOwnerCropX = 50; planOwnerCropY = 50; planOwnerScale = 1;
                            }
                            applyPlanOwnerPhoto();
                        };
                        reader.readAsDataURL(files[0]);
                    }
                });
            }
            if (document.readyState === 'loading') {
                document.addEventListener('DOMContentLoaded', initDragDrop);
            } else {
                initDragDrop();
            }
        })();

