        window.paVaultRenderPersonDropdown = paVaultRenderPersonDropdown;
        window.paVaultSwitchPerson = paVaultSwitchPerson;
        function paRenderVaultList() {
            var container = document.getElementById('vaultList');
            var empty = document.getElementById('vaultEmpty');
            if (!container) return;
            var allEntries = (window.entriesStore || []).slice();
            // Filter to selected person \u2014 owner OR linked. Per Violetka 2026-05-11:
            // canonical linked-to field is `relatedTo`. `linkedContactIds` kept
            // for backward compat with legacy entries.
            var pid = paVaultSelectedPerson;
            var entries = allEntries.filter(function(e) {
                if (!e || e.archived) return false;
                if (e.ownerId === pid) return true;
                if (Array.isArray(e.relatedTo) && e.relatedTo.indexOf(pid) >= 0) return true;
                if (Array.isArray(e.linkedContactIds) && e.linkedContactIds.indexOf(pid) >= 0) return true;
                return false;
            });
            if (!entries.length) {
                container.innerHTML = '';
                if (empty) empty.style.display = 'block';
                return;
            }
            if (empty) empty.style.display = 'none';
            // Group by life-area domain (the 7 canonical domains).
            // Domain id \u2192 entries[]
            var byDomain = {};
            VAULT_DOMAINS.forEach(function(d){ byDomain[d.id] = []; });
            entries.forEach(function(e) {
                var dom = (e.location && e.location.domain) ||
                          VAULT_CARDKEY_TO_DOMAIN[e.cardKey] ||
                          'me-family-network';
                if (!byDomain[dom]) byDomain[dom] = [];
                byDomain[dom].push(e);
            });
            // Person\u2019s display name (used to rename the first \"Me, Family & Network\"
            // domain to \"{Person}\u2019s Profile\" when the filter is active).
            var person = paVaultGetPeople().find(function(p){ return p.id === pid; });
            var personName = (person && person.name) || 'Profile';
            var html = '';
            // Vault row builder \u2014 extracted so we can call it for owned and linked entries.
            function buildVaultRow(e, isLinked) {
                var hasFile = !!e.file || (e.files && e.files.length);
                var hasLoc  = !!e.location;
                var badgeClass = hasFile && hasLoc ? 'both' : hasFile ? 'digital' : hasLoc ? 'location' : '';
                var badgeText  = hasFile && hasLoc ? 'Digital File &amp; Location' : hasFile ? 'Digital File' : hasLoc ? 'Location' : '';
                var iconClass  = hasFile && hasLoc ? 'passport' : hasFile ? 'license' : hasLoc ? 'birth' : '';
                var dateLine   = (e.dateLabel || 'Updated') + ': ' + (e.date || 'today');
                // Show owner badge \u2014 helps user know whose entry this is.
                var owner = window.peopleById ? window.peopleById(e.ownerId) : null;
                var ownerName = (owner && owner.name) || e.ownerId || '';
                var typeHtml = (e.subcategory || '');
                if (ownerName) {
                    typeHtml = (e.subcategory || '') + ' \u00b7 <span style="opacity:0.5;">' + escHtml(ownerName) + '</span>';
                }
                // Title \u2014 owner prefix added automatically for linked entries
                // (e.g. "John's Driver's License" when filtering Vault by Sarah and John's entry is linked to her).
                var displayTitle = (typeof window.paFormatEntryTitle === 'function')
                    ? window.paFormatEntryTitle(e, pid)
                    : (e.title || '');
                var dataEntry = {
                    id: e.id || '',
                    category: e.subcategory || '',
                    fields: Array.isArray(e.fields) ? e.fields : [],
                    timeline: Array.isArray(e.timeline) ? e.timeline : [],
                    location: e.location || '',
                    locationDetails: e.locationDetails || '',
                    notes: e.notes || ''
                };
                if (e.person) dataEntry.person = e.person;
                // Pass cardKey + ownerId so the expand body can render the
                // canonical "Location in Platform" breadcrumb widget.
                dataEntry.cardKey = e.cardKey || '';
                dataEntry.ownerId = e.ownerId || '';
                // Linked-people ids — same fix as Documents tab. Without
                // these, the .anef-people-section in the Vault entry expand
                // view stays empty and the user doesn't see the linked
                // summary cards (e.g. John on Sarah's Passport).
                if (Array.isArray(e.relatedTo) && e.relatedTo.length) dataEntry.relatedTo = e.relatedTo.slice();
                if (Array.isArray(e.linkedContactIds) && e.linkedContactIds.length) dataEntry.linkedContactIds = e.linkedContactIds.slice();
                if (Array.isArray(e.files) && e.files.length) dataEntry.files = e.files;
                else if (e.file) dataEntry.file = { type: 'PDF', name: e.file.name || (e.title + '.pdf'), uploaded: e.date || '' };
                var dataEntryAttr = JSON.stringify(dataEntry).replace(/"/g, '&quot;');
                var menuHtml = isLinked
                    ? '<div class="doc-menu" onclick="event.stopPropagation();toggleDD(this)"><div class="doc-menu-dots"><span></span><span></span><span></span></div><div class="doc-dropdown"><div class="doc-dropdown-trigger-row"><div class="doc-menu-inner"><div class="doc-menu-dots"><span></span><span></span><span></span></div></div></div><div class="dd-row" onclick="event.stopPropagation();if(typeof openPersonRecord===\'function\')openPersonRecord(\'' + escHtml(e.ownerId || '') + '\')"><span class="dd-row-label">View Source</span></div></div></div>'
                    : '<div class="doc-menu" onclick="event.stopPropagation();toggleDD(this)"><div class="doc-menu-dots"><span></span><span></span><span></span></div><div class="doc-dropdown"><div class="doc-dropdown-trigger-row"><div class="doc-menu-inner"><div class="doc-menu-dots"><span></span><span></span><span></span></div></div></div><div class="dd-row dd-row-edit"><span class="dd-row-label">Edit</span></div><div class="dd-row" onclick="event.stopPropagation();paArchiveEntryRow(this)"><span class="dd-row-label">Archive</span></div><div class="dd-row" onclick="event.stopPropagation();paDeleteEntryRow(this)"><span class="dd-row-label">Delete</span></div></div></div>';
                return '<div class="doc-row entry-row' + (isLinked ? ' is-linked' : '') + '"' + (isLinked ? ' data-linked="true"' : '') + ' data-entry="' + dataEntryAttr + '" onclick="paDocsRowClick(this, event)">'
                      + '<div class="doc-bulk-check" onclick="paVaultToggleRow(this, event)"></div>'
                      + '<div class="doc-icon ' + iconClass + '"><img class="doc-icon-glyph" src="img/document.png" alt=""></div>'
                      + '<div class="doc-info">'
                      +   '<div class="doc-title">' + escHtml(displayTitle) + '</div>'
                      +   '<div class="doc-type">' + typeHtml + '</div>'
                      +   '<div class="doc-meta">' + dateLine + '</div>'
                      + '</div>'
                      + (badgeText ? '<div class="data-right"><span class="data-badge ' + badgeClass + '">' + badgeText + '</span></div>' : '')
                      + menuHtml
                      + '</div>'
                      + '<div class="entry-expand-body' + (isLinked ? ' is-linked' : '') + '"></div>';
            }
            // Render \u2014 per domain, split owned vs linked, insert subtitle separator
            VAULT_DOMAINS.forEach(function(d) {
                var domEntries = byDomain[d.id] || [];
                if (!domEntries.length) return;
                var divLabel = d.id === 'me-family-network'
                    ? personName + '\u2019s Profile'
                    : d.label;
                html += '<div class="vault-domain-divider"><span class="vault-domain-divider-text">' + escHtml(divLabel) + '</span></div>';
                var ownedHere  = domEntries.filter(function(e){ return e.ownerId === pid; });
                var linkedHere = domEntries.filter(function(e){ return e.ownerId !== pid; });
                ownedHere.forEach(function(e) { html += buildVaultRow(e, false); });
                if (linkedHere.length) {
                    html += '<div class="data-group-title data-group-linked-subtitle">Linked Entries</div>';
                    linkedHere.forEach(function(e) { html += buildVaultRow(e, true); });
                }
            });
            container.innerHTML = html;
            if (typeof window.buildAllMedicalEntries === 'function') window.buildAllMedicalEntries();
        }
        function paVaultToggleRow(boxEl, ev) {
            if (ev) ev.stopPropagation();
            var row = boxEl.closest('.doc-row');
            if (row) row.classList.toggle('selected');
            var allRows = document.querySelectorAll('#vaultList .doc-row');
            var selected = document.querySelectorAll('#vaultList .doc-row.selected');
            var circle = document.querySelector('#page-vault .docs-select-all-circle');
            if (circle) circle.classList.toggle('checked', allRows.length > 0 && selected.length === allRows.length);
        }
        function paVaultSelectAll(circleEl) {
            circleEl.classList.toggle('checked');
            var checked = circleEl.classList.contains('checked');
            document.querySelectorAll('#vaultList .doc-row').forEach(function(r) { r.classList.toggle('selected', checked); });
        }
        function paVaultArchiveSelected() {
            var rows = Array.from(document.querySelectorAll('#vaultList .doc-row.selected'));
            if (!rows.length) return;
            var doArchive = function() {
                rows.forEach(function(r) {
                    if (!r.classList.contains('archived')) {
                        r.classList.add('archived');
                        var menuLabel = Array.from(r.querySelectorAll('.dd-row .dd-row-label')).find(function(l){ return /^(Archive|Unarchive)$/.test((l.textContent||'').trim()); });
                        if (menuLabel) menuLabel.textContent = 'Unarchive';
                        var editRow = r.querySelector('.dd-row.dd-row-edit');
                        if (editRow) editRow.style.display = 'none';
                    }
                    r.classList.remove('selected');
                });
                var circle = document.querySelector('#page-vault .docs-select-all-circle');
                if (circle) circle.classList.remove('checked');
            };
            if (typeof window.showArchiveDocumentsPopup === 'function') window.showArchiveDocumentsPopup(doArchive);
            else doArchive();
        }
        function paVaultRemoveSelected() {
            var rows = Array.from(document.querySelectorAll('#vaultList .doc-row.selected'));
            if (!rows.length) return;
            var doRemove = function() {
                rows.forEach(function(r) {
                    try {
                        var entry = JSON.parse(r.getAttribute('data-entry') || '{}');
                        if (Array.isArray(window.entriesStore) && entry.id) {
                            window.entriesStore = window.entriesStore.filter(function(e) { return e.id !== entry.id; });
                        }
                    } catch(e) {}
                    r.remove();
                });
                if (typeof window.paSaveSession === 'function') window.paSaveSession();
                var circle = document.querySelector('#page-vault .docs-select-all-circle');
                if (circle) circle.classList.remove('checked');
                if (typeof window.paRenderVaultList === 'function') window.paRenderVaultList();
                if (typeof window.paRenderDocumentsList === 'function') window.paRenderDocumentsList();
                if (typeof window.paPurgeOrphanedEntryRows === 'function') window.paPurgeOrphanedEntryRows();
            };
            if (typeof window.showDeleteDocumentsPopup === 'function') window.showDeleteDocumentsPopup(doRemove);
            else doRemove();
        }
        function paVaultFilter(q) {
            q = (q || '').toLowerCase().trim();
            document.querySelectorAll('#vaultList .doc-row').forEach(function(row) {
                if (!q) { row.style.display = ''; return; }
                row.style.display = (row.textContent || '').toLowerCase().indexOf(q) >= 0 ? '' : 'none';
            });
            document.querySelectorAll('#vaultList .data-group-title').forEach(function(g) {
                var n = g.nextElementSibling, anyVisible = false;
                while (n && !n.classList.contains('data-group-title')) {
                    if (n.classList.contains('doc-row') && n.style.display !== 'none') { anyVisible = true; break; }
                    n = n.nextElementSibling;
                }
                g.style.display = (q && !anyVisible) ? 'none' : '';
            });
        }
        window.paRenderVaultList = paRenderVaultList;
        window.paVaultToggleRow = paVaultToggleRow;
        window.paVaultSelectAll = paVaultSelectAll;
        window.paVaultArchiveSelected = paVaultArchiveSelected;
        window.paVaultRemoveSelected = paVaultRemoveSelected;
        window.paVaultFilter = paVaultFilter;
        if (document.readyState === 'loading') {
            document.addEventListener('DOMContentLoaded', paUpgradeArchiveButtons);
        } else {
            paUpgradeArchiveButtons();
        }
        if (document.readyState === 'loading') {
            document.addEventListener('DOMContentLoaded', paUpgradeStaticDocRows);
        } else {
            paUpgradeStaticDocRows();
        }
        // Upgrade Family & Relationships member cards \u2014 the seed-emitted
        // `.fr-member-card` elements use `id="fr-card-NAME"` but lack
        // `data-person-id`. Resolve each by matching `.fr-card-name` to a
        // person in peopleStore so other code can look up the record.
        //
        // IMPORTANT (Violetka 2026-05-14): Card click must NEVER navigate.
        // Per F&R spec, clicking a summary card expands it inline (downward)
        // via frToggleMember on the .fr-card-wrap parent. The legacy
        // openPersonRecord click handler that lived here was bypassing the
        // inline-expand behavior and sending users to the other person's
        // record. Removed. Navigation to a person's record is only via the
        // \u22ee dropdown \u2192 \"Open Profile\" menu item or other explicit affordances,
        // never via the card body itself.
        //
        // Idempotent (skips cards already mapped).
        function paUpgradeFrMemberCards() {
            const cards = document.querySelectorAll('.fr-member-card');
            cards.forEach(card => {
                if (card.getAttribute('data-person-id')) return;
                const nameEl = card.querySelector('.fr-card-name');
                const name = nameEl ? nameEl.textContent.trim() : '';
                if (!name) return;
                const all = (typeof window.peopleStore === 'object' && window.peopleStore)
                    ? Object.values(window.peopleStore)
                    : [];
                const match = all.find(p => p && p.name && p.name.toLowerCase() === name.toLowerCase());
                if (!match || !match.id) return;
                card.setAttribute('data-person-id', match.id);
                card.style.cursor = 'pointer';
                // No click handler here \u2014 the .fr-card-wrap parent owns the
                // click (frToggleMember) for inline expansion. Adding a
                // listener on the inner card would race the wrap handler and
                // navigate away before the expand can render.
            });
        }
        window.paUpgradeFrMemberCards = paUpgradeFrMemberCards;
        if (document.readyState === 'loading') {
            document.addEventListener('DOMContentLoaded', paUpgradeFrMemberCards);
        } else {
            paUpgradeFrMemberCards();
        }

        function paDocsRowClick(row, ev) {
            if (!ev) return;
            var t = ev.target;
            if (t.closest && (t.closest('.doc-bulk-check') || t.closest('.doc-menu') || t.closest('.doc-dropdown'))) return;
            var body = row.nextElementSibling;
            if (!body || !body.classList.contains('entry-expand-body')) return;
            var isOpen = body.classList.contains('open');
            // Close any other open expand-body in the Documents list
            document.querySelectorAll('#documentsList .entry-expand-body.open').forEach(function(b) {
                if (b !== body) {
                    b.classList.remove('open');
                    var prev = b.previousElementSibling;
                    if (prev) prev.classList.remove('expanded');
                }
            });
            // Toggle the clicked one — open if closed, close if open
            if (isOpen) {
                body.classList.remove('open');
                row.classList.remove('expanded');
            } else {
                body.classList.add('open');
                row.classList.add('expanded');
            }
        }
        window.paDocsRowClick = paDocsRowClick;
        // Dev helper: wipe stored uploads so only mock files remain.
        function paResetUploads() {
            try { localStorage.removeItem(PA_UPLOADS_KEY); } catch (e) {}
            paRenderDocumentsList();
        }

        // Click on the file's icon wrap — future hook for opening a preview.
        // Leave as a no-op for now so the Default/Hover states render without
        // throwing on click; the XD spec for icon-click behaviour will land later.
        function paOnFileIconClick(id) { /* no-op — spec pending */ }

        // Lookup a file by id across the KYC Step-1 list and stored uploads.
        function paFindFileById(id) {
            var i;
            for (i = 0; i < kycStep1Files.length; i++) {
                if (kycStep1Files[i].id === id) {
                    return { file: kycStep1Files[i], scope: 'kyc' };
                }
            }
            var stored = paGetStoredUploads();
            for (i = 0; i < stored.length; i++) {
                if (stored[i].id === id) {
                    return { file: stored[i], scope: 'stored' };
                }
            }
            // Mock files are seeded in PA_MOCK_FILES — not deletable from storage,
            // but we still allow removing them from the visible Documents list.
            for (i = 0; i < PA_MOCK_FILES.length; i++) {
                if (PA_MOCK_FILES[i].id === id) {
                    return { file: PA_MOCK_FILES[i], scope: 'mock' };
                }
            }
            return null;
        }

        // Trash click → open the "PopUp Delete File" overlay with a dissolve-in
        // (XD spec: Trigger Tap, Action Overlay, Dissolve, Ease Out, 0.2s).
        // Detailed popup design is pending XD handoff — this stub wires the
        // trigger + target + confirm path; swap the popup's visual design when
        // specs land without touching the delete plumbing.
        function paConfirmDeleteFile(id) {
            var found = paFindFileById(id);
            if (!found) return;
            paDeletePopupShow(found.file);
        }

        // Actually remove the file from session + storage, then re-render both
        // lists and re-gate the KYC Continue button (may become inactive again
        // if Step-1 list becomes empty).
        function paDeleteFileById(id) {
            var i;
            // Remove from KYC session list.
            for (i = kycStep1Files.length - 1; i >= 0; i--) {
                if (kycStep1Files[i].id === id) kycStep1Files.splice(i, 1);
            }
            // Remove from persistent uploads.
            var stored = paGetStoredUploads();
            var changed = false;
            for (i = stored.length - 1; i >= 0; i--) {
                if (stored[i].id === id) { stored.splice(i, 1); changed = true; }
            }
            if (changed) paSaveStoredUploads(stored);
            // Remove from mock seed (runtime only — page reload restores them).
            for (i = PA_MOCK_FILES.length - 1; i >= 0; i--) {
                if (PA_MOCK_FILES[i].id === id) PA_MOCK_FILES.splice(i, 1);
            }
            kycRenderStep1Files();
            paRenderDocumentsList();
            if (typeof kycUpdateContinueButton === 'function') {
                kycUpdateContinueButton();
            }
        }

        // --------------------------------------------------------------
        // PopUp Delete File overlay (XD: Trigger Tap, Action Overlay,
        // Destination PopUp Delete File, Dissolve, Ease Out, 0.2 s)
        //
        // Singleton DOM node, lazily created on first call and reused. Works
        // on every page that loads _shared.js without needing per-page markup.
        // The confirm/cancel buttons are wired here; visual polish will be
        // iterated once XD handoff for the popup lands.
        // --------------------------------------------------------------
        var paDeletePopupEl = null;
        var paDeletePopupTarget = null;
        function paDeletePopupEnsure() {
            if (paDeletePopupEl) return paDeletePopupEl;
            var root = document.createElement('div');
            root.className = 'pa-delete-popup';
            root.id = 'paDeletePopup';
            root.setAttribute('role', 'dialog');
            root.setAttribute('aria-modal', 'true');
            root.setAttribute('aria-labelledby', 'paDeletePopupTitle');
            root.innerHTML = '' +
                '<div class="pa-delete-popup__backdrop" data-pa-delete-cancel></div>' +
                '<div class="pa-delete-popup__card" role="document">' +
                    '<span class="pa-delete-popup__gradient" aria-hidden="true"></span>' +
                    '<span class="pa-delete-popup__attention" aria-hidden="true"></span>' +
                    '<h2 class="pa-delete-popup__title" id="paDeletePopupTitle">Delete Document</h2>' +
                    '<button type="button" class="pa-delete-popup__close" aria-label="Close" data-pa-delete-cancel>' +
                        '<span class="pa-delete-popup__close-icon" aria-hidden="true"></span>' +
                    '</button>' +
                    '<p class="pa-delete-popup__desc" id="paDeletePopupDesc">Are you sure you want to delete selected document? This action cannot be undone!</p>' +
                    '<button type="button" class="pa-delete-popup__btn" data-pa-delete-confirm>' +
                        '<span class="pa-delete-btn__pill" aria-hidden="true"></span>' +
                        '<span class="pa-delete-btn__text">Delete</span>' +
                        '<span class="pa-delete-btn__line" aria-hidden="true"></span>' +
                        '<span class="pa-delete-btn__arrow" aria-hidden="true"></span>' +
                    '</button>' +
                '</div>';
            document.body.appendChild(root);
            // Delegated clicks — cancel on backdrop/X/Cancel; confirm on Delete.
            root.addEventListener('click', function(e) {
                var target = e.target;
                while (target && target !== root) {
                    if (target.hasAttribute && target.hasAttribute('data-pa-delete-cancel')) {
                        paDeletePopupHide();
                        return;
                    }
                    if (target.hasAttribute && target.hasAttribute('data-pa-delete-confirm')) {
                        var id = paDeletePopupTarget && paDeletePopupTarget.id;
                        paDeletePopupHide();
                        if (id) paDeleteFileById(id);
                        return;
                    }
                    target = target.parentNode;
                }
            });
            // Esc closes.
            document.addEventListener('keydown', function(e) {
                if (e.key === 'Escape' && root.classList.contains('pa-delete-popup--open')) {
                    paDeletePopupHide();
                }
            });
            paDeletePopupEl = root;
            return root;
        }
        function paDeletePopupShow(file) {
            var root = paDeletePopupEnsure();
            paDeletePopupTarget = file;
            var nameEl = document.getElementById('paDeletePopupFile');
            if (nameEl) nameEl.textContent = file && file.name ? file.name : '';
            // Force reflow so the transition runs when we add the --open class.
            root.offsetHeight;
            root.classList.add('pa-delete-popup--open');
        }
        function paDeletePopupHide() {
            if (!paDeletePopupEl) return;
            paDeletePopupEl.classList.remove('pa-delete-popup--open');
            paDeletePopupTarget = null;
        }

        // Documents tab — "Add Document" button.
        // Switches to Overview tab and opens the Essential Info entry form
        // (canonical default starting category). Subcategory dropdown lets the
        // user pick the right document type within the form.
        function paDocumentsAddNew() {
            // Switch to Overview tab so the form is visible in its source card
            var overviewTab = document.querySelector('.profile-tab[data-tab="overview"]');
            if (overviewTab && typeof overviewTab.click === 'function') overviewTab.click();
            // Defer until tab transition completes
            setTimeout(function() {
                if (typeof window.openEntryForm === 'function') window.openEntryForm('essential');
            }, 80);
        }
        window.paDocumentsAddNew = paDocumentsAddNew;

        // Documents tab — bulk-select / action / filter handlers.
        function paDocsSelectAll(circle) {
            if (!circle) return;
            var checked = circle.classList.toggle('checked');
            document.querySelectorAll('#documentsList .doc-row').forEach(function(row) {
                row.classList.toggle('selected', checked);
            });
        }
        function paDocsToggleRow(box, ev) {
            if (ev) ev.stopPropagation();
            var row = box.closest('.doc-row');
            if (!row) return;
            row.classList.toggle('selected');
            // Sync the master Select All checkbox
            var rows = document.querySelectorAll('#documentsList .doc-row');
            var selected = document.querySelectorAll('#documentsList .doc-row.selected');
            var circle = document.querySelector('.docs-select-all-circle');
            if (circle) circle.classList.toggle('checked', rows.length > 0 && selected.length === rows.length);
        }
        function paDocsArchiveSelected() {
            var rows = Array.from(document.querySelectorAll('#documentsList .doc-row.selected'));
            if (!rows.length) return;
            // Per spec: archived entries stay AVAILABLE to the user (visible
            // with reduced opacity, moved to the bottom of their group) but
            // are excluded from completion stats + reminders. Show the system
            // popup so the user knows what archive means before confirming.
            var doArchive = function() {
                rows.forEach(function(r) {
                    if (typeof window.paArchiveEntryRow === 'function') {
                        // Find the row's archive dd-row label and click it through
                        // the canonical handler so menu state stays consistent.
                        var label = r.querySelector('.dd-row .dd-row-label');
                        // Faster path: directly toggle on the row.
                    }
                    if (!r.classList.contains('archived')) {
                        r.classList.add('archived');
                        var body = r.nextElementSibling;
                        if (body && body.classList.contains('entry-expand-body')) body.classList.add('archived');
                        // Swap menu label "Archive" \u2194 "Unarchive"
                        var menuLabel = Array.from(r.querySelectorAll('.dd-row .dd-row-label')).find(function(l){ return /^(Archive|Unarchive)$/.test((l.textContent||'').trim()); });
                        if (menuLabel) menuLabel.textContent = 'Unarchive';
                        // Hide Edit option while archived (per spec)
                        var editRow = r.querySelector('.dd-row.dd-row-edit');
                        if (editRow) editRow.style.display = 'none';
                    }
                    r.classList.remove('selected');
                });
                // Reset Select All circle
                var circle = document.querySelector('.docs-select-all-circle');
                if (circle) circle.classList.remove('checked');
            };
            if (typeof window.showArchiveDocumentsPopup === 'function') {
                window.showArchiveDocumentsPopup(doArchive);
            } else {
                doArchive();
            }
        }
        function paDocsRemoveSelected() {
            var rows = Array.from(document.querySelectorAll('#documentsList .doc-row.selected'));
            if (!rows.length) return;
            // Per XD spec: batch delete from Documents tab triggers the canonical
            // "Delete Documents" confirmation popup. SSOT cascade: each removed
            // row also drops from entriesStore so the deletion propagates to
            // every view (originating card, linked records, Vault).
            var doRemove = function() {
                rows.forEach(function(r) {
                    try {
                        var entry = JSON.parse(r.getAttribute('data-entry') || '{}');
                        if (Array.isArray(window.entriesStore)) {
                            var entryId = entry.id || r.getAttribute('data-entry-id');
                            if (entryId) {
                                window.entriesStore = window.entriesStore.filter(function(e) { return e.id !== entryId; });
                            } else if (entry.title && entry.category) {
                                window.entriesStore = window.entriesStore.filter(function(e) {
                                    return !(e.title === entry.title && (e.subcategory || '') === (entry.category || ''));
                                });
                            }
                        }
                    } catch(e) {}
                    r.remove();
                });
                if (typeof window.paSaveSession === 'function') window.paSaveSession();
                var circle = document.querySelector('.docs-select-all-circle');
                if (circle) circle.classList.remove('checked');
                // Re-render Docs tab + purge any orphaned rows on Overview
                // cards (Essential / Medical / Education / Employment / Beliefs)
                // so the batch delete is reflected everywhere.
                if (typeof window.paRenderDocumentsList === 'function') {
                    window.paRenderDocumentsList();
                }
                if (typeof window.paPurgeOrphanedEntryRows === 'function') {
                    window.paPurgeOrphanedEntryRows();
                }
            };
            if (typeof window.showDeleteDocumentsPopup === 'function') {
                window.showDeleteDocumentsPopup(doRemove);
            } else {
                doRemove();
            }
        }
        function paDocsFilter(q) {
            q = (q || '').toLowerCase().trim();
            // Hide the "By Type" dropdown as soon as user starts typing
            var dd = document.getElementById('docsSearchDropdown');
            if (dd) dd.classList.toggle('open', !q ? dd.classList.contains('open') : false);
            document.querySelectorAll('#documentsList .doc-row').forEach(function(row) {
                if (!q) { row.style.display = ''; return; }
                var t = (row.textContent || '').toLowerCase();
                row.style.display = t.indexOf(q) >= 0 ? '' : 'none';
            });
            document.querySelectorAll('#documentsList .data-group-title').forEach(function(g) {
                var n = g.nextElementSibling, anyVisible = false;
                while (n && !n.classList.contains('data-group-title')) {
                    if (n.classList.contains('doc-row') && n.style.display !== 'none') { anyVisible = true; break; }
                    n = n.nextElementSibling;
                }
                g.style.display = (q && !anyVisible) ? 'none' : '';
            });
        }
        function paDocsSearchFocus(input) {
            // Show "By Type" dropdown only while input is empty
            var dd = document.getElementById('docsSearchDropdown');
            if (!dd) return;
            if (!input.value) dd.classList.add('open');
        }
        function paDocsSearchBlur(input) {
            // Defer so click on a dropdown item still fires
            setTimeout(function() {
                var dd = document.getElementById('docsSearchDropdown');
                if (dd) dd.classList.remove('open');
            }, 150);
        }
        function paDocsSearchPick(value) {
            var input = document.querySelector('.docs-search-input');
            if (input) { input.value = value; paDocsFilter(value); }
            var dd = document.getElementById('docsSearchDropdown');
            if (dd) dd.classList.remove('open');
        }
        window.paDocsSelectAll = paDocsSelectAll;
        window.paDocsToggleRow = paDocsToggleRow;
        window.paDocsArchiveSelected = paDocsArchiveSelected;
        window.paDocsRemoveSelected = paDocsRemoveSelected;
        window.paDocsFilter = paDocsFilter;
        window.paDocsSearchFocus = paDocsSearchFocus;
        window.paDocsSearchBlur = paDocsSearchBlur;
        window.paDocsSearchPick = paDocsSearchPick;

        // ── Universal partial loader (exposed to window so partials/*.html can be lazy-loaded) ──
        // Used by data-partial="<name>" attribute on any mount element.
        // Re-runs <script> tags inside the partial (innerHTML doesn't auto-execute them).
        window.loadPartial = function loadPartial(name, target) {
            var el = typeof target === 'string' ? document.querySelector(target) : target;
            if (!el) return Promise.reject(new Error('loadPartial: target not found ' + target));
            return fetch('partials/' + name + '.html', { cache: 'no-store' })
                .then(function(res) {
                    if (!res.ok) throw new Error('loadPartial: ' + res.status + ' for ' + name);
                    return res.text();
                })
                .then(function(html) {
                    el.innerHTML = html;
                    // Re-execute any <script> blocks inside the partial
                    el.querySelectorAll('script').forEach(function(oldScript) {
                        var s = document.createElement('script');
                        if (oldScript.src) s.src = oldScript.src;
                        else s.textContent = oldScript.textContent;
                        oldScript.replaceWith(s);
                    });
                });
        };

        // Auto-load the Documents tab partial if a mount with [data-partial="tab-documents"] exists.
        function paInitDocumentsTabPartial() {
            var mount = document.querySelector('#documentsTabMount[data-partial="tab-documents"]');
            if (!mount || mount.dataset.loaded) return;
            mount.dataset.loaded = '1';
            if (typeof window.loadPartial === 'function') {
                window.loadPartial('tab-documents', '#documentsTabMount').then(function() {
                    if (typeof paRenderDocumentsList === 'function') paRenderDocumentsList();
                }).catch(function(err) {
                    console.warn('Documents tab partial load failed:', err.message);
                });
            }
        }
        if (document.readyState === 'loading') {
            document.addEventListener('DOMContentLoaded', paInitDocumentsTabPartial);
        } else {
            paInitDocumentsTabPartial();
        }

        // Expose for dev/debug.
        window.paAddUploadedFile = paAddUploadedFile;
        window.paRenderDocumentsList = paRenderDocumentsList;
        window.paResetUploads = paResetUploads;
        window.paOnFileIconClick = paOnFileIconClick;
        window.paConfirmDeleteFile = paConfirmDeleteFile;
        window.paDeleteFileById = paDeleteFileById;
        window.paDeletePopupShow = paDeletePopupShow;
        window.paDeletePopupHide = paDeletePopupHide;

        // Initial render on load.
        if (document.readyState === 'loading') {
            document.addEventListener('DOMContentLoaded', paRenderDocumentsList);
        } else {
            paRenderDocumentsList();
        }

        // XD max-size: 25 MB. Accepted: PDF / JPG / PNG.
        var KYC_UPLOAD_MAX_BYTES = 25 * 1024 * 1024;
        var KYC_UPLOAD_ACCEPT_RE = /\.(pdf|jpe?g|png)$/i;
        // Stepped jumps instead of smooth ticker: 0 → 50 → 100 → file in list.
        // These are the delays between jumps (ms).
        var KYC_JUMP_TO_50_MS   = 400;
        var KYC_JUMP_TO_100_MS  = 500;   // after reaching 50%
        var KYC_HOLD_AT_100_MS  = 400;   // pause at 100% so user sees the bar full
        var kycUploadTimers = [];
        var kycCurrentFile = null;
        // Session-scoped list of files uploaded in this KYC run (shown below the
        // zone). Cleared on closeKycFlow(). Also persisted to the global
        // Documents tab via paAddUploadedFile().
        var kycStep1Files = [];

        function kycClearUploadTimers() {
            kycUploadTimers.forEach(function(t){ clearTimeout(t); clearInterval(t); });
            kycUploadTimers = [];
        }

        function kycSetUploadState(state) {
            var zone = document.getElementById('kycUploadZone');
            var btn = document.getElementById('kycContinueBtn');
            if (!zone) return;
            zone.setAttribute('data-state', state);
            kycUpdateContinueButton();
        }
        // Continue activation rules per step:
        //   Step 1 → active only after a file is uploaded (or the zone is in
        //            the transient "complete" state during the finalize flip).
        //   Step 2+ → active by default (navigation-only for prototype; future
        //            steps will re-gate on their own completion state).
        function kycUpdateContinueButton() {
            var btn = document.getElementById('kycContinueBtn');
            if (!btn) return;
            var step = (typeof kycCurrentStep !== 'undefined') ? kycCurrentStep : 1;
            var active;
            if (step === 1) {
                var zone = document.getElementById('kycUploadZone');
                var state = zone ? zone.getAttribute('data-state') : 'default';
                active = (kycStep1Files.length > 0) || (state === 'complete');
            } else {
                active = true;
            }
            if (active) {
                btn.classList.remove('kyc-continue-btn--inactive');
                btn.setAttribute('aria-disabled', 'false');
            } else {
                btn.classList.add('kyc-continue-btn--inactive');
                btn.setAttribute('aria-disabled', 'true');
            }
        }

        // Render the Step-1 inline file list (below upload zone).
        function kycRenderStep1Files() {
            var container = document.getElementById('kycStep1Files');
            if (!container) return;
            container.innerHTML = kycStep1Files.map(paFileRowHtml).join('');
        }
        window.kycRenderStep1Files = kycRenderStep1Files;

        // Format bytes → "12.5 MB" / "800 KB". No fake ".0".
        function kycFormatSize(bytes) {
            if (bytes >= 1024 * 1024) {
                return (bytes / (1024 * 1024)).toFixed(1).replace(/\.0$/, '') + ' MB';
            }
            if (bytes >= 1024) {
                return (bytes / 1024).toFixed(1).replace(/\.0$/, '') + ' KB';
            }
            return bytes + ' B';
        }

        // Render the Uploading Progress state: % + filename + "X MB of Y MB".
        function kycRenderProgress(pct, file) {
            var fill = document.getElementById('kycUploadProgressFill');
            var pctNum = document.getElementById('kycUploadPctNum');
            var size = document.getElementById('kycUploadSize');
            var label = document.getElementById('kycUploadingLabel');
            if (fill) fill.style.setProperty('--kyc-upload-pct', pct);
            if (pctNum) pctNum.textContent = Math.round(pct);
            if (label && file) {
                label.textContent = file.name;
                label.setAttribute('title', file.name);
            }
            if (size && file) {
                var done = kycFormatSize(Math.round(file.size * pct / 100));
                var total = kycFormatSize(file.size);
                size.textContent = done + ' of ' + total;
            }
        }

        // Render the Uploading Complete state: filename + full-size "Y MB of Y MB".
        function kycRenderComplete(file) {
            var label = document.getElementById('kycCompleteLabel');
            var size = document.getElementById('kycCompleteSize');
            if (label && file) {
                label.textContent = file.name;
                label.setAttribute('title', file.name);
            }
            if (size && file) {
                var total = kycFormatSize(file.size);
                size.textContent = total + ' of ' + total;
            }
        }

        // Stepped upload: 0% → 50% → 100% → file moves into list below, zone
        // resets to Default so user can upload another. Continue stays active.
        function kycStartUpload(file) {
            kycClearUploadTimers();
            kycCurrentFile = file;
            kycSetUploadState('uploading');
            kycRenderProgress(0, file);

            var t50 = setTimeout(function() {
                kycRenderProgress(50, file);
            }, KYC_JUMP_TO_50_MS);

            var t100 = setTimeout(function() {
                kycRenderProgress(100, file);
            }, KYC_JUMP_TO_50_MS + KYC_JUMP_TO_100_MS);

            // After the user has seen the bar reach 100%, commit the file:
            //   1) push to kycStep1Files (session list shown under the zone)
            //   2) persist to global Documents tab via paAddUploadedFile()
            //   3) reset the zone to Default so it's ready for the next file
            //   4) keep Continue active (kycStep1Files.length > 0)
            var tFinalize = setTimeout(function() {
                var entry = {
                    id: 'k' + Date.now(),
                    name: file.name,
                    size: file.size || 0,
                    type: file.type || '',
                    uploadedAt: Date.now()
                };
                kycStep1Files.push(entry);
                if (typeof paAddUploadedFile === 'function') paAddUploadedFile(file);
                kycRenderStep1Files();
                kycClearUploadTimers();
                kycCurrentFile = null;
                kycSetUploadState('default');
                kycUpdateContinueButton();
            }, KYC_JUMP_TO_50_MS + KYC_JUMP_TO_100_MS + KYC_HOLD_AT_100_MS);

            kycUploadTimers.push(t50, t100, tFinalize);
        }

        // Validate a FileList → start upload on the first valid file.
        function kycHandleFileSelection(files) {
            if (!files || files.length === 0) return;
            var file = files[0];
            if (!KYC_UPLOAD_ACCEPT_RE.test(file.name)) {
                console.warn('[KYC] Unsupported format:', file.name);
                return;
            }
            if (file.size > KYC_UPLOAD_MAX_BYTES) {
                console.warn('[KYC] File too large:', file.size, 'bytes');
                return;
            }
            kycStartUpload(file);
        }

        // Click the hidden native file input to open the OS file picker.
        function kycOpenFileDialog() {
            var input = document.getElementById('kycFileInput');
            if (input) {
                input.value = '';           // allow re-selecting the same file
                input.click();
            }
        }

        // Zone click handler: Default → open picker, Complete → reset to Default.
        function kycOnZoneClick(e) {
            // Ignore clicks that bubble up from the hidden <input> itself
            if (e && e.target && e.target.id === 'kycFileInput') return;
            var zone = document.getElementById('kycUploadZone');
            if (!zone) return;
            var state = zone.getAttribute('data-state') || 'default';
            if (state === 'default') {
                kycOpenFileDialog();
            } else if (state === 'complete') {
                // Tap a completed zone → remove file, return to Default
                kycClearUploadTimers();
                kycCurrentFile = null;
                kycSetUploadState('default');
            }
            // Uploading state: swallow clicks
        }

        // Drag-and-drop: style the zone on dragover, accept on drop.
        function kycOnDragOver(e) {
            e.preventDefault();
            e.stopPropagation();
            if (e.dataTransfer) e.dataTransfer.dropEffect = 'copy';
            var zone = document.getElementById('kycUploadZone');
            if (zone && zone.getAttribute('data-state') === 'default') {
                zone.classList.add('kyc-upload-zone--dragover');
            }
        }
        function kycOnDragLeave(e) {
            e.preventDefault();
            e.stopPropagation();
            var zone = document.getElementById('kycUploadZone');
            if (zone) zone.classList.remove('kyc-upload-zone--dragover');
        }
        function kycOnDrop(e) {
            e.preventDefault();
            e.stopPropagation();
            var zone = document.getElementById('kycUploadZone');
            if (zone) zone.classList.remove('kyc-upload-zone--dragover');
            if (!zone || zone.getAttribute('data-state') !== 'default') return;
            if (e.dataTransfer && e.dataTransfer.files) {
                kycHandleFileSelection(e.dataTransfer.files);
            }
        }

        // Back-compat: keep the old demo hook so any older listeners still work,
        // but route it through the real picker flow.
        function kycSimulateFileUpload() { kycOnZoneClick(); }

        window.kycSimulateFileUpload = kycSimulateFileUpload;
        window.kycSetUploadState = kycSetUploadState;  // dev/demo hook
        window.kycHandleFileSelection = kycHandleFileSelection;

        // Wire everything once DOM is ready.
        (function wireKycUploadZone() {
            function attach() {
                var zone = document.getElementById('kycUploadZone');
                var input = document.getElementById('kycFileInput');
                if (!zone) return;

                zone.addEventListener('click', kycOnZoneClick);
                zone.addEventListener('dragenter', kycOnDragOver);
                zone.addEventListener('dragover',  kycOnDragOver);
                zone.addEventListener('dragleave', kycOnDragLeave);
                zone.addEventListener('drop',      kycOnDrop);

                if (input) {
                    input.addEventListener('change', function(e) {
                        kycHandleFileSelection(e.target.files);
                    });
                }

                // Prevent browser from opening the file when dropped OUTSIDE the zone
                window.addEventListener('dragover', function(e){ e.preventDefault(); });
                window.addEventListener('drop',     function(e){ e.preventDefault(); });
            }
            if (document.readyState === 'loading') {
                document.addEventListener('DOMContentLoaded', attach);
            } else {
                attach();
            }
        })();

        // Legacy cycle helper — kept for dev preview only. NOT wired to pill.
        function cycleVerificationStatus() {
            const states = ['unverified', 'pending', 'verified'];
            const labels = { unverified: 'Unverified', pending: 'Pending', verified: 'Verified' };
            // XD-locked 2026-04-16:
            // - Unverified Hover: swap to "Verify Now"
            // - Pending Hover:    stay "Pending" (no swap, only tooltip changes)
            // - Verified:         no hover state (no swap)
            const hoverLabels = { unverified: 'Verify Now', pending: 'Pending', verified: 'Verified' };
            const barLabels = { unverified: 'Unverified', pending: 'Pending', verified: 'Verified' };
            const card = document.querySelector('.profile-header-card');
            const area = document.querySelector('.profile-status-area');
            const text = area.querySelector('.profile-status-text');
            const hoverText = area.querySelector('.profile-status-hover-text');
            const barWrap = document.getElementById('barVerifyWrap');
            const current = area.getAttribute('data-status');
            const next = states[(states.indexOf(current) + 1) % states.length];
            
            area.setAttribute('data-status', next);
            card.setAttribute('data-status', next);
            text.textContent = labels[next];
            hoverText.textContent = hoverLabels[next];
            if (barWrap) barWrap.setAttribute('data-label', barLabels[next]);
        }

        /* ========== MORE SHEET TOGGLE ========== */
        function toggleMoreSheet() {
            const overlay = document.getElementById('moreSheetOverlay');
            overlay.classList.toggle('open');
        }

        function navigateTo(page) {
            // Cross-page navigation
            var pageMap = {
                'dashboard':   'index.html',
                'profile':     'profile.html',
                'family':      'family.html',
                'network':     'network.html',
                'assets':      'assets.html',
                'health':      'health.html',
                'goals':       'goals.html',
                'legacy':      'legacy.html',
                'will':        'will.html',
                'tasks':       'tasks.html',
                'vault':       'vault.html',
                'marketplace': 'marketplace.html',
                'shared':      'shared.html',
                'settings':    'settings.html',
                'print':       'print-document.html'
            };
            if (pageMap[page]) {
                // ── Unsaved Changes guard ─────────────────────────────────
                // Per spec: navigating away with an open Edit-mode form that has
                // unsaved changes should prompt for Save / Don't Save. Without
                // this, user clicks Back arrow → navigation happens immediately
                // and edits are lost silently.
                var __paOpenEdit = document.querySelector('.essential-info-card.editing');
                if (__paOpenEdit && typeof window.eiHasChanges === 'function' && window.eiHasChanges()) {
                    if (typeof window.showSystemPopup === 'function') {
                        window.showSystemPopup({
                            title: 'Unsaved Changes',
                            body: 'You have unsaved changes in Essential Info. Save before leaving?',
                            actionLabel: 'Save',
                            discardLabel: "Don't Save",
                            onAction: function() {
                                if (typeof window.saveEssentialInfo === 'function') {
                                    try { window.saveEssentialInfo(); } catch(e) {}
                                }
                                window.location.href = pageMap[page];
                            },
                            onDiscard: function() {
                                window.location.href = pageMap[page];
                            }
                        });
                        return;
                    }
                }
                window.location.href = pageMap[page];
                return;
            }
            // Stop article voice if playing
            if (typeof stopArticleVoice === 'function') stopArticleVoice();
            var vfab = document.getElementById('voiceFab');
            if (vfab) vfab.classList.remove('visible');
            // Close more sheet if open
            const moreSheet = document.getElementById('moreSheetOverlay');
            if (moreSheet) moreSheet.classList.remove('open');
            const scrollContainer = document.getElementById('scroll-container');
            // Hide all pages
            document.querySelectorAll('.page').forEach(p => { p.classList.remove('active'); });
            // Show target page
            const target = document.getElementById('page-' + page);
            if (target) {
                target.classList.add('active');
                // Re-trigger animation
                const anim = target.querySelector('.page-transition');
                if (anim) { anim.style.animation = 'none'; anim.offsetHeight; anim.style.animation = ''; }
            }
            // Update greeting. On record.html (record-view) the page header shows
            // the viewed person's NAME — never "My Profile" (which is reserved
            // for Sarah / Plan Owner only). Person Records use "Record" labelling.
            const greeting = document.getElementById('greetingText');
            const viewedPerson = (window.__paIsRecordView && typeof window.peopleById === 'function')
                ? window.peopleById('sj')
                : null;
            const viewedName = viewedPerson ? (viewedPerson.name || '') : '';
            // Plan Owner greeting reads firstName from peopleStore so editing
            // the name in Essential Info propagates to the dashboard greeting
            // (per Violetka 2026-05-10).
            const planOwner = (typeof window.paGetPlanOwner === 'function') ? window.paGetPlanOwner() : null;
            const ownerFirst = (planOwner && planOwner.firstName) ? planOwner.firstName : 'Sarah';
            if (page === 'dashboard') {
                greeting.textContent = viewedName
                    ? (viewedName + ' — Record')
                    : ('Welcome back, ' + ownerFirst + '!');
            } else if (page === 'profile') {
                greeting.textContent = viewedName
                    ? viewedName
                    : 'My Profile';
                // Reposition tab pill after page is visible
                requestAnimationFrame(() => {
                    const tabsPill = document.getElementById('tabsPill');
                    const activeTab = document.querySelector('.profile-tab.active');
                    if (tabsPill && activeTab) {
                        tabsPill.style.transition = 'none';
                        tabsPill.style.left = activeTab.offsetLeft + 'px';
                        tabsPill.style.width = activeTab.offsetWidth + 'px';
                        requestAnimationFrame(() => {
                            tabsPill.style.transition = 'left 0.3s ease-out, width 0.3s ease-out';
                        });
                    }
                });
            } else if (page === 'assets') {
                greeting.textContent = 'Assets & Liabilities';
            } else if (page === 'family') {
                greeting.textContent = 'My Family';
                requestAnimationFrame(() => fmInitTabPill());
            } else if (page === 'article') {
                greeting.textContent = 'Articles & Resources';
                var vfab = document.getElementById('voiceFab');
                if (vfab) vfab.classList.add('visible');
            }
            // Right panel: toggle between progress bars (dashboard) and AI card (inner pages)
            const progressSection = document.querySelector('#rightPanel > div:first-child');
            const aiCol4 = document.getElementById('aiCardCol4');
            if (page === 'dashboard') {
                if (progressSection) progressSection.style.display = 'flex';
                if (aiCol4) aiCol4.style.display = 'none';
            } else {
                if (progressSection) progressSection.style.display = 'none';
                if (aiCol4) aiCol4.style.display = 'flex';
            }
            // Scroll to top
            scrollContainer.scrollTo({ top: 0, behavior: 'smooth' });
            // Update AI placeholder contextually
            var col4Input = document.getElementById('col4AiInput');
            if (col4Input) {
                var placeholders = {
                    'dashboard': 'Ask me anything about...',
                    'profile': 'Ask about your profile or documents...',
                    'assets': 'Ask about your assets & liabilities...'
                };
                col4Input.placeholder = placeholders[page] || 'Ask me anything about...';
            }
            // Update sidebar active state
            document.querySelectorAll('.nav-item').forEach(n => n.classList.remove('active'));
            // Close sidebar on mobile
            if (window.innerWidth < 1280) closeSidebar();
        }

        // ========== FAMILY & RELATIONSHIPS CARD ==========
        let frEditMode = false;
        let frOpenMemberId = null; // currently expanded member (view or edit)
        // Single-Expand Rule (Violetka 2026-05-14): only one F&R panel may be
        // open at a time. When the user clicks another summary card while an
        // Edit panel has unsaved changes, prompt to save before switching.
        // Tracks which member IDs have dirty edit panels.
        const frDirtyMembers = new Set();
        function paFrMarkDirty(memberId) {
            if (!memberId) return;
            frDirtyMembers.add(memberId);
        }
        function paFrClearDirty(memberId) {
            if (!memberId) return;
            frDirtyMembers.delete(memberId);
        }
        function paFrIsDirty(memberId) {
            return !!memberId && frDirtyMembers.has(memberId);
        }
        // Resolve a member's display name for the prompt copy. Falls back to
        // the memberId if no card name is in the DOM (e.g. mid-render).
        function paFrMemberName(memberId) {
            const card = document.getElementById('fr-card-' + memberId);
            const nameEl = card && card.querySelector('.fr-card-name');
            return nameEl ? nameEl.textContent.trim() : memberId;
        }
        // Prompt the user when there are unsaved changes. Returns:
        //   'save'    → user wants to save before continuing
        //   'discard' → user wants to discard changes and continue
        //   'cancel'  → user wants to stay on the current panel (abort switch)
        // Uses native confirm() for now; will be replaced with a styled
        // modal in a follow-up pass. Spec: "first asks me with a message
        // whether I want to save changes" — Violetka 2026-05-14.
        function paFrPromptUnsaved(memberId) {
            const name = paFrMemberName(memberId);
            const saveIt = window.confirm(
                'You have unsaved changes to ' + name + '.\n\n' +
                'OK → Save changes\nCancel → Discard changes'
            );
            return saveIt ? 'save' : 'discard';
        }
        window.paFrMarkDirty = paFrMarkDirty;
        window.paFrClearDirty = paFrClearDirty;
        window.paFrIsDirty = paFrIsDirty;

        // ── Relationship Type → Specific Role mapping ──
        const FR_ROLE_MAP = {
            'Spouse / Partner': ['Husband','Wife','Partner (Non-registered)','Civil Partner (Registered)','Fiancé','Fiancée'],
            'Former Partner / Spouse': ['Ex-husband','Ex-wife','Former Partner','Former Civil Partner'],
            'Child': ['Biological Son','Biological Daughter','Adopted Son','Adopted Daughter','Stepson','Stepdaughter','Foster Son','Foster Daughter'],
            'Parent': ['Biological Mother','Biological Father','Adoptive Mother','Adoptive Father','Stepmother','Stepfather','Foster Mother','Foster Father'],
            'Sibling': ['Biological Brother','Biological Sister','Half-brother','Half-sister','Stepbrother','Stepsister','Adopted Brother','Adopted Sister'],
            'Grandparent': ['Paternal Grandfather','Paternal Grandmother','Maternal Grandfather','Maternal Grandmother'],
            'Grandchild': ['Grandson','Granddaughter'],
            'Extended Family': ['Uncle','Aunt','Nephew','Niece','Cousin (Male)','Cousin (Female)','Other'],
            'Pet': [],
            'Other': ['Custom / Other']
        };

        function frOnRelTypeChange(selectEl, memberId) {
            const panel = document.getElementById('fr-edit-panel-' + memberId);
            if (!panel) return;
            const type = selectEl.value;
            const roles = FR_ROLE_MAP[type] || [];
            const fields = panel.querySelectorAll('.fr-ep-field');
            const roleField = fields[1];
            const petFields = panel.querySelectorAll('.fr-pet-field');
            if (type === 'Pet') {
                if (roleField) roleField.style.display = 'none';
                petFields.forEach(f => f.style.display = '');
            } else {
                if (roleField) roleField.style.display = '';
                petFields.forEach(f => f.style.display = 'none');
                if (roleField) {
                    const sel = roleField.querySelector('select');
                    if (sel) {
                        const cur = sel.value;
                        sel.innerHTML = roles.map(r =>
                            `<option${r === cur ? ' selected' : ''}>${r}</option>`
                        ).join('');
                    }
                }
            }
        }

        const frPanelInited = new Set();
        function frInitEditPanel(memberId) {
            const panel = document.getElementById('fr-edit-panel-' + memberId);
            if (!panel) return;
            // Single-Expand dirty tracking: every time a field in this Edit
            // panel changes/inputs, mark this member as dirty so the
            // Single-Expand prompt knows to ask before switching. Wired once
            // per panel (panel-level event delegation handles dynamically
            // added fields too, e.g. when species/breed appear for Pet).
            if (!panel._dirtyWired) {
                panel._dirtyWired = true;
                const onMaybeDirty = function () { paFrMarkDirty(memberId); };
                panel.addEventListener('input',  onMaybeDirty, true);
                panel.addEventListener('change', onMaybeDirty, true);
            }
            if (frPanelInited.has(memberId)) return;
            frPanelInited.add(memberId);
            const fields = panel.querySelectorAll('.fr-ep-field');
            if (!fields[0]) return;
            const typeSelect = fields[0].querySelector('select');
            if (!typeSelect) return;
            // Guard: only wire if this is a Relationship Type select
            // (has "Spouse / Partner" or "Child" etc — not Species/Breed)
            const opts = Array.from(typeSelect.options).map(o => o.value);
            const isRelType = opts.some(o =>
                ['Spouse / Partner','Former Partner / Spouse','Child','Parent',
                 'Sibling','Grandparent','Grandchild','Extended Family','Pet','Other'].includes(o)
            );
            if (!isRelType) return; // Enzo — skip
            typeSelect.addEventListener('change', function(e) {
                e.stopPropagation();
                frOnRelTypeChange(this, memberId);
            });
            frOnRelTypeChange(typeSelect, memberId);
        }

        function toggleFrEdit() {
            frEditMode = !frEditMode;
            const btn = document.getElementById('fr-edit-btn');
            const statusBlock = document.getElementById('fr-status-block');
            const editOnlyEls = document.querySelectorAll('.fr-edit-only');

            // Ensure button text ALWAYS reads "Edit" (canonical pattern —
            // visual state is controlled by .editing class, NEVER by text).
            // Defensive reset to clean up any stale "Done" from older builds.
            const btnSpan = btn && btn.querySelector('span');
            if (btnSpan) btnSpan.textContent = 'Edit';

            if (frEditMode) {
                // CANONICAL edit-btn state (Violetka 2026-05-15: "имам едит
                // дефолт и едит ацтиве" — button text stays "Edit" in both
                // states; only the .editing class changes the visual to
                // Hover-Tap-Hold look (white circle + text shifted 10px).
                // NEVER change text to "Done".
                btn.classList.add('editing');
                if (statusBlock) statusBlock.style.display = 'none';
                // Restore each .fr-edit-only element to its NATURAL CSS display
                // (Violetka 2026-05-15 bug fix: forcing display:flex on every
                // .fr-edit-only broke .fr-group-label centering — that class
                // is canonically display:block with text-align:center, but
                // flex turned it into a row with text at flex-start).
                // Empty string = "use the CSS-defined display value" so block
                // labels stay block + centered, .fr-add-btn flex stays flex,
                // .fr-save-row flex stays flex.
                editOnlyEls.forEach(el => el.style.display = '');
                // Force-expand BOTH sections (Immediate + Extended) in Edit
                // mode (Violetka 2026-05-15: "в едит моде категориите са
                // винаги разпънати и -"). frEditMode is already true at
                // this point, which would short-circuit frToggleSection's
                // guard — temporarily flip the flag, expand each collapsed
                // section, then restore. Cleaner: call the inner DOM sync
                // directly without going through frToggleSection.
                ['fr-imm', 'fr-ext'].forEach(function(sectId) {
                    const body = document.getElementById(sectId);
                    if (!body || !body.classList.contains('collapsed')) return;
                    body.classList.remove('collapsed');
                    const toggleId = sectId === 'fr-imm' ? 'fr-imm-toggle' : 'fr-ext-toggle';
                    const toggleSpan = document.querySelector('#' + toggleId + ' span');
                    if (toggleSpan) toggleSpan.textContent = '−';
                    const headerEl = sectId === 'fr-imm'
                        ? document.querySelector('#fr-sections-outer .fr-section-header:first-child')
                        : document.getElementById('fr-ext-header');
                    if (headerEl) headerEl.classList.add('open');
                });
                // If a card is currently open in Read mode, immediately swap
                // it to Edit mode (no extra click between section-toggle and
                // edit). Per Violetka 2026-05-15.
                if (frOpenMemberId) {
                    const openWrap = document.getElementById('fr-wrap-' + frOpenMemberId);
                    const openExpand = document.getElementById('fr-expand-' + frOpenMemberId);
                    const openEdit = document.getElementById('fr-edit-panel-' + frOpenMemberId);
                    if (openExpand) openExpand.style.display = 'none';
                    if (openEdit) openEdit.style.display = 'block';
                    if (openWrap) openWrap.classList.add('edit-open');
                    if (typeof window.paRenderEditExpandPanel === 'function') {
                        try { window.paRenderEditExpandPanel(frOpenMemberId); } catch (err) {}
                    }
                }
            } else {
                btn.classList.remove('editing');
                if (statusBlock) statusBlock.style.display = '';
                editOnlyEls.forEach(el => el.style.display = 'none');
                // Close all edit panels
                document.querySelectorAll('[id^="fr-edit-panel-"]').forEach(p => p.style.display = 'none');
                document.querySelectorAll('[id^="fr-expand-"]').forEach(p => p.style.display = 'none');
                document.querySelectorAll('.fr-member-card').forEach(c => c.classList.remove('expanded'));
                document.querySelectorAll('.fr-card-wrap').forEach(c => { c.classList.remove('expanded'); c.classList.remove('edit-open'); });

                frOpenMemberId = null;
            }
        }

        function frToggleSection(id) {
            // In Edit mode, sections are LOCKED open (Violetka 2026-05-15:
            // "в едит моде категориите са винаги разпънати"). User can't
            // collapse them via header click. They re-collapse only when
            // Save is clicked → exits Edit mode → toggleFrEdit() closes them.
            if (frEditMode) return;
            const body = document.getElementById(id);
            if (!body) return;
            body.classList.toggle('collapsed');
            const isCollapsed = body.classList.contains('collapsed');

            // Find the matching header inside fr-sections-outer
            const outer = document.getElementById('fr-sections-outer');
            // Determine which toggle span and header to update
            const toggleId = id === 'fr-imm' ? 'fr-imm-toggle' : 'fr-ext-toggle';
            const headerId = id === 'fr-imm' ? null : 'fr-ext-header';
            const toggleSpan = document.querySelector('#' + toggleId + ' span');
            if (toggleSpan) toggleSpan.textContent = isCollapsed ? '+' : '−';

            // Toggle .open on the header row
            const headers = outer ? outer.querySelectorAll('.fr-section-header') : [];
            const headerEl = id === 'fr-imm' ? headers[0] : document.getElementById('fr-ext-header');
            if (headerEl) headerEl.classList.toggle('open', !isCollapsed);

            // outer card is always flat (border-radius: 0), no JS radius update needed
        }

        // Save all F&R edits + exit Edit mode (Violetka 2026-05-15 XD reference:
        // single Save button in the bottom of the F&R card; click it → all dirty
        // member edits get persisted, then the section transitions back to View
        // mode — the Edit button returns to default state, section status block
        // reappears, +Add buttons hide). Save flow:
        //   1. Iterate every dirty memberId → call frSaveMember (writes to
        //      anchor.relationships + inverse mirror, runs the relationship
        //      engine, re-renders the F&R card row)
        //   2. paAutoSave → localStorage (debounced)
        //   3. paRelationshipEngine → orphan cleanup, dedupe, Tier B suggestions
        //   4. toggleFrEdit() → exits Edit mode (button .editing removed, status
        //      block visible, +Add buttons hidden, all panels closed)
        function frSaveAll() {
            // 1. Save every dirty member edit (collect first; the save fn
            //    mutates the set as it clears dirty flags).
            const dirty = Array.from(frDirtyMembers);
            dirty.forEach(function(memberId) {
                try { if (typeof frSaveMember === 'function') frSaveMember(memberId); } catch (err) { console.warn('[frSaveAll]', memberId, err); }
            });
            // 2. Persist (debounced; will coalesce with frSaveMember's own auto-save)
            if (typeof window.paAutoSave === 'function') {
                try { window.paAutoSave(); } catch (e) {}
            }
            // 3. Engine pass (cleans up orphans, dedupes, ensures bidirectional)
            if (typeof window.paRelationshipEngine === 'function') {
                try { window.paRelationshipEngine(); } catch (e) {}
            }
            // 4. Exit Edit mode → toggleFrEdit removes .editing class, hides
            //    +Add buttons, restores status block. Sections stay open
            //    (user can collapse manually now that frEditMode is false).
            if (frEditMode) {
                try { toggleFrEdit(); } catch (e) {}
            }
            try { window.dispatchEvent(new CustomEvent('toast', { detail: { msg: 'Family & Relationships saved' } })); } catch (e) {}
        }
        window.frSaveAll = frSaveAll;

        function frToggleMember(memberId, e) {
            if (e) e.stopPropagation();
            // Guard (Violetka 2026-05-15: "в едит форм на връзка на някой
            // вече закъчен рекърд, не мога да променям нищо — ако кликна в
            // него всичко се затваря"). The .fr-card-wrap onclick bubbles
            // up from EVERY click inside, including textareas / inputs in
            // the open edit panel. We need to early-return if the click
            // originated INSIDE the edit panel (which is a sibling of the
            // card-top but inside the same wrap) — otherwise typing in a
            // notes textarea or picking a date instantly collapses the
            // card with the unsaved-changes prompt. Only toggle on actual
            // card-top clicks (the visible summary card with avatar+name).
            if (e && e.target) {
                const t = e.target;
                // Inside edit panel → don't toggle, let the inner control handle the click
                if (t.closest && t.closest('.fr-edit-panel')) return;
                // Inside expand panel (read-mode body) → don't toggle either
                if (t.closest && t.closest('.fr-expand-panel')) return;
                // Inside any form-level interactive control (input/textarea/select/button)
                // anywhere in the wrap → don't toggle
                const tag = (t.tagName || '').toUpperCase();
                if (tag === 'INPUT' || tag === 'TEXTAREA' || tag === 'SELECT' || tag === 'BUTTON' || tag === 'OPTION' || tag === 'LABEL') return;
                if (t.closest && t.closest('input, textarea, select, button, .ee-input-wrap, .tl-dd-trigger, .tl-dd-dropdown, .ee-contact-picker, .ee-contact-suggestions, .ee-field-dropdown')) return;
            }
            const card = document.getElementById('fr-card-' + memberId);
            const wrap = document.getElementById('fr-wrap-' + memberId);
            const expandPanel = document.getElementById('fr-expand-' + memberId);
            const editPanel = document.getElementById('fr-edit-panel-' + memberId);
            if (!card) return;

            const isExpanded = card.classList.contains('expanded');

            function getAccordion(el) {
                let p = el;
                while (p) { if (p.classList && p.classList.contains('accordion-section')) return p; p = p.parentElement; }
                return null;
            }

            // Single-Expand Rule (Violetka 2026-05-14): close the previously
            // open member before opening a new one. If the previous member
            // has unsaved edit-panel changes, prompt the user first:
            //   • Save    → run frSaveMember(prev), then proceed
            //   • Discard → drop changes, proceed
            //   • Cancel  → abort the switch entirely (stay on previous)
            // This guarantees no two F&R panels are ever open simultaneously
            // and no edits are silently lost.
            if (frOpenMemberId && frOpenMemberId !== memberId) {
                const prevId = frOpenMemberId;
                if (paFrIsDirty(prevId)) {
                    const choice = paFrPromptUnsaved(prevId);
                    if (choice === 'save') {
                        try { if (typeof frSaveMember === 'function') frSaveMember(prevId); } catch (err) {}
                    }
                    // discard / save both proceed; clear the flag either way
                    paFrClearDirty(prevId);
                }
                const prevCard = document.getElementById('fr-card-' + prevId);
                const prevWrap = document.getElementById('fr-wrap-' + prevId);
                const prevExpand = document.getElementById('fr-expand-' + prevId);
                const prevEdit = document.getElementById('fr-edit-panel-' + prevId);

                if (prevCard) prevCard.classList.remove('expanded');
                if (prevWrap) { prevWrap.classList.remove('expanded'); prevWrap.classList.remove('edit-open'); }
                if (prevExpand) prevExpand.style.display = 'none';
                if (prevEdit) prevEdit.style.display = 'none';
                if (prevWrap) { const acc = getAccordion(prevWrap); if (acc) acc.classList.remove('fr-expanded'); }
                frOpenMemberId = null;
            }

            const accordion = wrap ? getAccordion(wrap) : null;

            if (isExpanded) {
                // Collapse — restore card-top first
                card.classList.remove('expanded');
                if (wrap) { wrap.classList.remove('expanded'); wrap.classList.remove('edit-open'); }
                if (expandPanel) expandPanel.style.display = 'none';
                if (editPanel) editPanel.style.display = 'none';
                if (accordion) {
                    accordion.classList.remove('fr-expanded');
                    accordion.style.overflow = '';
                    const body = accordion.querySelector('.accordion-body');
                    if (body) body.style.overflow = '';
                    const inner = accordion.querySelector('.accordion-inner');
                    if (inner) inner.style.overflow = '';
                }
                frOpenMemberId = null;
            } else {
                // Expand
                card.classList.add('expanded');
                if (wrap) wrap.classList.add('expanded');
                if (accordion) {
                    accordion.classList.add('fr-expanded');
                    accordion.style.overflow = 'visible';
                    const body = accordion.querySelector('.accordion-body');
                    if (body) body.style.overflow = 'visible';
                    const inner = accordion.querySelector('.accordion-inner');
                    if (inner) inner.style.overflow = 'visible';
                }
                if (frEditMode) {
                    if (expandPanel) expandPanel.style.display = 'none';
                    if (editPanel) editPanel.style.display = 'block';
                    if (wrap) wrap.classList.add('edit-open');
                    // Phase 2A.2 — render the dynamic Edit panel from
                    // peopleStore (Type / Specific Role / Timeline /
                    // Notes / Save). Falls back to legacy frInitEditPanel
                    // if the new renderer isn't loaded for some reason.
                    if (typeof window.paRenderEditExpandPanel === 'function') {
                        try { window.paRenderEditExpandPanel(memberId); } catch (err) {}
                    } else {
                        frInitEditPanel(memberId);
                    }
                } else {
                    // Phase 2A.1 — dynamically build Read Mode panel content
                    // (Type + Specific Role + Timeline + Hide Details) from
                    // peopleStore. Single source of truth — no hardcoded markup.
                    if (expandPanel && typeof window.paRenderReadExpandPanel === 'function') {
                        try { window.paRenderReadExpandPanel(memberId); } catch (err) {}
                    }
                    if (expandPanel) expandPanel.style.display = 'block';
                    if (editPanel) editPanel.style.display = 'none';
                    if (wrap) wrap.classList.remove('edit-open');
                }
                frOpenMemberId = memberId;
            }
        }

        function frCloseEditPanel(memberId, e) {
            if (e) e.stopPropagation();
            // Single-Expand Rule: same save-prompt as the toggle path.
            if (paFrIsDirty(memberId)) {
                const choice = paFrPromptUnsaved(memberId);
                if (choice === 'save') {
                    try { if (typeof frSaveMember === 'function') frSaveMember(memberId); } catch (err) {}
                }
                paFrClearDirty(memberId);
            }
            const card = document.getElementById('fr-card-' + memberId);
            const wrap = document.getElementById('fr-wrap-' + memberId);
            const expandPanel = document.getElementById('fr-expand-' + memberId);
            const editPanel = document.getElementById('fr-edit-panel-' + memberId);
            // Restore card-top before removing edit-open so transition plays

            if (card) card.classList.remove('expanded');
            if (wrap) { wrap.classList.remove('expanded'); wrap.classList.remove('edit-open'); }
            if (expandPanel) expandPanel.style.display = 'none';
            if (editPanel) editPanel.style.display = 'none';
            frOpenMemberId = null;
        }

        function frOpenMenu(memberId, e) {
            e.stopPropagation();
            // Close all other dropdowns
            document.querySelectorAll('.fr-dropdown').forEach(d => {
                if (d.id !== 'fr-dd-' + memberId) d.classList.remove('open');
            });
            const dd = document.getElementById('fr-dd-' + memberId);
            if (!dd) return;
            const wasOpen = dd.classList.contains('open');
            dd.classList.toggle('open');
            // After opening, ensure the dropdown is in view. Violetka 2026-05-18:
            // "натисма върху ... тоаки [нищо не става]" — actually the menu was
            // opening but BELOW the visible area, so the user thought it didn't
            // work. Scroll the dropdown into view when it opens.
            if (!wasOpen) {
                requestAnimationFrame(function(){
                    try {
                        var rect = dd.getBoundingClientRect();
                        var vh = window.innerHeight || document.documentElement.clientHeight;
                        // If bottom is below viewport OR top is above, scroll into view
                        if (rect.bottom > vh - 20 || rect.top < 20) {
                            dd.scrollIntoView({ block: 'nearest', behavior: 'smooth' });
                        }
                        // ALSO check inside the .scroll-container (the platform
                        // uses a custom scroll container, not window scroll)
                        var sc = document.getElementById('scroll-container');
                        if (sc) {
                            var scRect = sc.getBoundingClientRect();
                            var ddRect = dd.getBoundingClientRect();
                            if (ddRect.bottom > scRect.bottom - 20) {
                                sc.scrollBy({ top: ddRect.bottom - scRect.bottom + 40, behavior: 'smooth' });
                            } else if (ddRect.top < scRect.top + 20) {
                                sc.scrollBy({ top: ddRect.top - scRect.top - 40, behavior: 'smooth' });
                            }
                        }
                    } catch (err) {}
                });
            }
        }

        function frOpenProfile(memberId) {
            // Navigate to the member's record page. (Violetka 2026-05-16:
            // "тези менута да работят" — was a stub `alert` placeholder.)
            // Plan Owner ('sj') has the canonical profile.html; everyone
            // else uses record.html#<id> hash routing. Pets fall through
            // to record.html too — record.html bootstrap handles the pet
            // body class.
            if (!memberId) return;
            // Close any open dropdown first
            var dd = document.getElementById('fr-dd-' + memberId);
            if (dd) dd.classList.remove('open');
            if (memberId === 'sj') {
                window.location.href = 'profile.html';
            } else {
                window.location.href = 'record.html#' + encodeURIComponent(memberId);
            }
        }

        // frShare — placeholder for the per-record share UI. Violetka
        // 2026-05-16: "iskam ot ... menu da mofaga da ... sherwam". A real
        // share modal will land in a separate iteration (per spec — role
        // chips, sharedTo array, post-mortem rules, etc.). For now: navigate
        // to the person's record where the existing share UI lives, OR
        // toast a placeholder if no canonical share modal exists yet.
        function frShare(memberId) {
            if (!memberId) return;
            var dd = document.getElementById('fr-dd-' + memberId);
            if (dd) dd.classList.remove('open');
            // If the record page exposes a share modal opener, route to the
            // record with a query/hash to trigger it. Otherwise toast.
            // For now navigate to record.html#<id>?share=1 — record.html
            // can later auto-open its share UI when it sees ?share=1.
            try {
                window.dispatchEvent(new CustomEvent('toast', {
                    detail: { msg: 'Share UI coming soon — opening record for now' }
                }));
            } catch (e) {}
            if (memberId === 'sj') {
                window.location.href = 'profile.html?share=1';
            } else {
                window.location.href = 'record.html#' + encodeURIComponent(memberId) + '?share=1';
            }
        }

        // frDelete — DESTRUCTIVE. Fully removes the person from peopleStore
        // (along with every cross-record reference). Violetka 2026-05-16:
        // "iskam ot ... menu da mofaga da triq recurd". Distinct from
        // frRemove which only severs the anchor↔person relationship link;
        // frDelete obliterates the person record entirely. Requires explicit
        // confirm() because this can't be undone.
        function frDelete(memberId) {
            if (!memberId) return;
            if (memberId === 'sj') return; // never allow deleting the Plan Owner
            // Close menu
            var dd = document.getElementById('fr-dd-' + memberId);
            if (dd) dd.classList.remove('open');
            // Resolve the person for a useful confirm prompt
            var person = (window.peopleStore || []).find(function(p){ return p.id === memberId; });
            var name = (person && (person.name || person.firstName)) || 'this record';
            /* Canonical confirmation popup (Violetka 2026-05-25 "apply
               design and ideas from Assets/Liabilities everywhere").
               Replaces the native window.confirm() with the platform's
               showSystemPopup — same pattern used by .aa-tile-options
               delete and all other destructive actions. */
            var doDelete = function() {
                _frDeletePerformActual(memberId, person, name);
            };
            if (typeof window.showSystemPopup === 'function') {
                window.showSystemPopup({
                    title: 'Delete Record',
                    discardLabel: 'Cancel',
                    body: 'Permanently delete the record for ' + name + '? This removes them from your plan everywhere — every record’s relationships, the family tree, statistics, and any shared access. This action cannot be undone!',
                    actionLabel: 'Delete',
                    onAction: doDelete
                });
                return;
            }
            /* Fallback if popup not available */
            if (!window.confirm('Permanently delete the record for ' + name + '? This cannot be undone.')) return;
            doDelete();
        }
        function _frDeletePerformActual(memberId, person, name) {
            if (!memberId) return;
            // Wipe person + every cross-record reference
            if (Array.isArray(window.peopleStore)) {
                window.peopleStore = window.peopleStore.filter(function(p) { return p && p.id !== memberId; });
                // Strip relationships + suggestions pointing to deleted person
                window.peopleStore.forEach(function(p) {
                    if (!p) return;
                    if (Array.isArray(p.relationships)) {
                        p.relationships = p.relationships.filter(function(r){ return r && r.toId !== memberId; });
                    }
                    if (Array.isArray(p.suggestedRelationships)) {
                        p.suggestedRelationships = p.suggestedRelationships.filter(function(s){ return s && s.fromId !== memberId; });
                    }
                });
            }
            // Persist + refresh all live views (same chain as frRemove)
            if (typeof window.paSaveAll === 'function') {
                try { window.paSaveAll(); } catch (e) {}
            } else if (typeof window.paSaveSession === 'function') {
                try { window.paSaveSession(); } catch (e) {}
            }
            if (typeof window.paRelationshipEngine === 'function') {
                try { window.paRelationshipEngine(); } catch (e) {}
            }
            if (typeof window.renderFamilyDirectory === 'function') {
                try { window.renderFamilyDirectory(); } catch (e) {}
            }
            if (typeof window.renderNetworkDirectory === 'function') {
                try { window.renderNetworkDirectory(); } catch (e) {}
            }
            if (typeof window.paInjectFamilyMembersIntoFRCard === 'function') {
                try { window.paInjectFamilyMembersIntoFRCard(); } catch (e) {}
            }
            if (typeof window.paInjectNewFamilyMembersIntoTree === 'function') {
                try { window.paInjectNewFamilyMembersIntoTree(); } catch (e) {}
            }
            if (typeof window.paUpdateFamilyAnalytics === 'function') {
                try { window.paUpdateFamilyAnalytics(); } catch (e) {}
            }
            if (typeof window.paUpdateFamilyHeaderStats === 'function') {
                try { window.paUpdateFamilyHeaderStats(); } catch (e) {}
            }
            // Remove any visible card for this id
            document.querySelectorAll('[data-person-id="' + memberId + '"]').forEach(function(el) {
                if (el.closest('.ee-contact-option, .ee-contact-suggestions, .ee-contact-picker')) return;
                el.remove();
            });
            // Toast confirmation
            try {
                window.dispatchEvent(new CustomEvent('toast', {
                    detail: { msg: name + ' deleted permanently' }
                }));
            } catch (e) {}
        }

        function frRemove(memberId) {
            // Close menu first
            const dd = document.getElementById('fr-dd-' + memberId);
            if (dd) dd.classList.remove('open');
            // Inline removal action — runs after popup confirmation.
            const doRemove = function() {
                const card = document.getElementById('fr-card-' + memberId);
                const expandPanel = document.getElementById('fr-expand-' + memberId);
                const editPanel = document.getElementById('fr-edit-panel-' + memberId);
                if (card) card.style.display = 'none';
                if (expandPanel) expandPanel.style.display = 'none';
                if (editPanel) editPanel.style.display = 'none';
                // Also remove user-added .ee-person-card variants and clean
                // peopleStore relationships so persistence stays coherent.
                const pid = card?.getAttribute('data-person-id');
                if (pid && Array.isArray(window.peopleStore)) {
                    // ANCHOR = whoever's record we're editing — Sarah on
                    // profile.html, viewed person on record.html. (Violetka
                    // 2026-05-16 POV fix: previously hardcoded 'sj' here, so
                    // removing a family member from Emma's record was wiping
                    // the wrong side of the relationship — Sarah's side.)
                    const removeAnchorId = window.__paViewedPersonRealId || 'sj';
                    const removeAnchor = window.peopleStore.find(p => p.id === removeAnchorId);
                    if (removeAnchor && Array.isArray(removeAnchor.relationships)) {
                        removeAnchor.relationships = removeAnchor.relationships.filter(r => r.toId !== pid);
                    }
                    const other = window.peopleStore.find(p => p.id === pid);
                    if (other && Array.isArray(other.relationships)) {
                        other.relationships = other.relationships.filter(r => r.toId !== removeAnchorId);
                    }
                    // Also strip stale Tier B suggestions referencing this person
                    // from every record's suggestedRelationships array.
                    window.peopleStore.forEach(function(p) {
                        if (!p || !Array.isArray(p.suggestedRelationships)) return;
                        p.suggestedRelationships = p.suggestedRelationships.filter(function(s) {
                            return s && s.fromId !== pid;
                        });
                    });
                    if (typeof window.paSaveAll === 'function') {
                        try { window.paSaveAll(); } catch (e) {}
                    } else if (typeof window.paSaveSession === 'function') {
                        window.paSaveSession();
                    }
                }
                document.querySelectorAll(`.ee-person-card[data-person-id="${pid}"]`).forEach(el => el.remove());
                // Live refresh — directories, tree injection, analytics, engine.
                // Deleting a family member must update the My Family stats card
                // immediately (per Violetka 2026-05-13).
                if (typeof window.renderFamilyDirectory === 'function') {
                    try { window.renderFamilyDirectory(); } catch (e) {}
                }
                if (typeof window.renderNetworkDirectory === 'function') {
                    try { window.renderNetworkDirectory(); } catch (e) {}
                }
                if (typeof window.paInjectNewFamilyMembersIntoTree === 'function') {
                    try { window.paInjectNewFamilyMembersIntoTree(); } catch (e) {}
                }
                if (typeof window.paUpdateFamilyAnalytics === 'function') {
                    try { window.paUpdateFamilyAnalytics(); } catch (e) {}
                }
                if (typeof window.paUpdateFamilyHeaderStats === 'function') {
                    try { window.paUpdateFamilyHeaderStats(); } catch (e) {}
                }
                if (typeof window.paRecomputeFamilyTreeAnalytics === 'function') {
                    try { window.paRecomputeFamilyTreeAnalytics(); } catch (e) {}
                }
                if (typeof window.paRelationshipEngine === 'function') {
                    try { window.paRelationshipEngine(); } catch (e) {}
                }
                // Re-inject after engine pass — removes stale suggestions for
                // the deleted person and re-derives any new ones.
                if (typeof window.paInjectFamilyMembersIntoFRCard === 'function') {
                    try { window.paInjectFamilyMembersIntoFRCard(); } catch (e) {}
                }
            };
            if (typeof window.showRemoveRelationshipPopup === 'function') {
                window.showRemoveRelationshipPopup(doRemove);
            } else if (confirm('Remove this relationship?\nThis will unlink these two records. The person\'s record will not be deleted.')) {
                doRemove();
            }
        }

        // Milestone X-close — removes ONE milestone from the Edit panel
        // and its Read-mode mirror (Violetka 2026-05-15 bug fix: clicking
        // X was closing the whole F&R card because the click bubbled to
        // .fr-card-wrap.onclick → frToggleMember → collapse. Two fixes:
        //   1. Accept the event arg + stopPropagation immediately
        //   2. Target canonical .tl-milestone (was .fr-milestone-block
        //      which my canonical refactor removed). Legacy fallback kept.
        // Per Violetka — actual data deletion happens on Save (which reads
        // from the live DOM); removing a milestone block visually means
        // Save will write peopleStore without that milestone's dates.
        function frDeleteMilestone(btn, evt) {
            // Stop the click from bubbling to .fr-card-wrap.onclick which
            // would collapse the whole card.
            if (evt) { try { evt.stopPropagation(); } catch (e) {} }
            else if (typeof event !== 'undefined' && event) { try { event.stopPropagation(); } catch (e) {} }
            // Locate the milestone container (canonical first, legacy fallback)
            var block = btn.closest('.tl-milestone') || btn.closest('.fr-milestone-block');
            if (!block) return;
            var editPanel = block.closest('.fr-edit-panel');
            if (!editPanel) return;
            var memberId = editPanel.id.replace('fr-edit-panel-', '');
            // Mark this member as dirty so the Save / unsaved-changes prompt
            // fires correctly if the user switches cards before saving.
            if (typeof window.paFrMarkDirty === 'function') {
                try { window.paFrMarkDirty(memberId); } catch (e) {}
            }
            // Index of removed milestone — used to remove the mirror item
            // from the Read panel (idempotent — only if the read panel
            // currently has a matching milestone index).
            var blocks = Array.from(editPanel.querySelectorAll('.tl-milestone, .fr-milestone-block'));
            var idx = blocks.indexOf(block);
            block.remove();
            var expandPanel = document.getElementById('fr-expand-' + memberId);
            if (expandPanel) {
                var items = expandPanel.querySelectorAll('.tl-milestone, .fr-timeline-item');
                if (idx >= 0 && idx < items.length) {
                    items[idx].remove();
                }
            }
        }

        // Phase 2A.2 Save (Violetka 2026-05-14). Replaces the legacy
        // DOM-mutation save that only updated the displayed text and
        // didn't persist to peopleStore. New flow:
        //   1. Read the dynamic Edit panel values (Type, Role, every
        //      milestone's Y/M/D + Notes)
        //   2. Compose ISO dates (partial precision: Y / Y-M / Y-M-D)
        //   3. Write to the anchor's rel in peopleStore:
        //        rel.type            = canonical edgeType for role
        //        rel.specificRole    = chosen role label
        //        rel.dates[key]      = ISO date
        //        rel.dates[key+'Notes'] = note text (if present)
        //   4. Mirror to the inverse rel (bidirectional spec 2.4.1)
        //   5. Re-run relationship engine + re-render F&R + Read panel
        //   6. Switch panel display: Edit → Read
        // Clears dirty flag at the end so the Single-Expand prompt
        // doesn't fire on next switch.
        function frSaveMember(memberId) {
            const editPanel = document.getElementById('fr-edit-panel-' + memberId);
            const expandPanel = document.getElementById('fr-expand-' + memberId);
            if (!editPanel) { frCloseEditPanel(memberId); return; }

            // 1. Read dynamic panel values from CANONICAL .ee-input-value
            //    (was native <select>.value before the canonical refactor).
            //    Strip the " (legacy)" suffix used for fallback options so
            //    saved data stays canonical.
            const typeVal = editPanel.querySelector('.fr-ep-type');
            const roleVal = editPanel.querySelector('.fr-ep-role');
            const layer1 = typeVal ? (typeVal.textContent || '').trim() : '';
            const rawRole = roleVal ? (roleVal.textContent || '').trim() : '';
            const specificRole = rawRole.replace(/\s*\(legacy\)\s*$/i, '');

            // Resolve canonical edgeType for storage (Specific Role
            // refinement overrides Layer 1 default).
            const edgeType = (window.paFRRoleToType && window.paFRRoleToType[specificRole])
                          || (window.paFRLayer1ToType && window.paFRLayer1ToType[layer1])
                          || '';

            // 2. Compose dates + notes from each milestone block.
            // Selectors updated for canonical .tl-milestone (was .fr-milestone-block).
            // Custom milestones get their user-entered label stored as
            // newDates[key + 'Label'] so Read mode can show it.
            const newDates = {};
            editPanel.querySelectorAll('.tl-milestone, .fr-milestone-block').forEach(function(block) {
                const key = block.getAttribute('data-key');
                if (!key) return;
                const y  = (block.querySelector('.fr-ms-year')  || {}).value || '';
                const mo = (block.querySelector('.fr-ms-month') || {}).value || '';
                const d  = (block.querySelector('.fr-ms-day')   || {}).value || '';
                const n  = (block.querySelector('.fr-ms-notes') || {}).value || '';
                // Custom-label input (only present on Custom Date blocks)
                const labelInp = block.querySelector('.tl-custom-label-input');
                const customLabel = labelInp ? String(labelInp.value || '').trim() : '';
                let iso = '';
                if (y) iso = y;
                if (y && mo) iso = y + '-' + mo;
                if (y && mo && d) iso = y + '-' + mo + '-' + d;
                if (iso) newDates[key] = iso;
                if (n && String(n).trim()) newDates[key + 'Notes'] = String(n).trim();
                if (customLabel) newDates[key + 'Label'] = customLabel;
            });

            // 3. Resolve anchor + person + write to peopleStore
            const person = window.paFRResolvePerson ? window.paFRResolvePerson(memberId) : null;
            const anchorId = window.__paViewedPersonRealId || 'sj';
            const anchor = (window.peopleStore || []).find(function(p){ return p.id === anchorId; });
            if (person && anchor) {
                // Find existing rel or create a new one
                anchor.relationships = anchor.relationships || [];
                let rel = anchor.relationships.find(function(r){ return r && r.toId === person.id; });
                if (!rel) {
                    rel = { toId: person.id };
                    anchor.relationships.push(rel);
                }
                if (edgeType) rel.type = edgeType;
                if (specificRole) rel.specificRole = specificRole;
                rel.dates = Object.assign({}, rel.dates || {}, newDates);

                // 4. Mirror to the inverse rel (bidirectional spec 2.4.1).
                // Same dates + notes — those are SHARED across the link.
                // Inverse edgeType derived via paInverseEdgeType.
                person.relationships = person.relationships || [];
                let invRel = person.relationships.find(function(r){ return r && r.toId === anchor.id; });
                if (!invRel) {
                    invRel = { toId: anchor.id };
                    person.relationships.push(invRel);
                }
                // Inverse — use paComputeInverseRel for FULL inverse (type +
                // gendered specificRole). Was paInverseEdgeType (type-only)
                // which lost the gendered label on the other person's record
                // (Violetka 2026-05-16 audit fix C2).
                const anchorGender = (anchor.gender || '').toLowerCase();
                const inv = (typeof window.paComputeInverseRel === 'function')
                    ? window.paComputeInverseRel(edgeType, specificRole, anchorGender)
                    : null;
                const invType = inv ? inv.type
                    : ((typeof window.paInverseEdgeType === 'function') ? window.paInverseEdgeType(edgeType) : edgeType);
                if (invType) invRel.type = invType;
                if (inv && inv.specificRole) invRel.specificRole = inv.specificRole;
                invRel.dates = Object.assign({}, invRel.dates || {}, newDates);

                // 5. Persist + engine pass + re-render
                if (typeof window.paAutoSave === 'function') {
                    try { window.paAutoSave(); } catch (e) {}
                }
                if (typeof window.paRelationshipEngine === 'function') {
                    try { window.paRelationshipEngine(); } catch (e) {}
                }
                if (typeof window.paInjectFamilyMembersIntoFRCard === 'function') {
                    try { window.paInjectFamilyMembersIntoFRCard(); } catch (e) {}
                }
                if (typeof window.paRenderFamilyRelationships === 'function') {
                    try { window.paRenderFamilyRelationships(anchorId); } catch (e) {}
                }
            }

            // 6. Save succeeded — clear dirty flag immediately.
            if (typeof paFrClearDirty === 'function') paFrClearDirty(memberId);

            // 7. Re-open the card in READ mode so the user immediately
            // sees the saved data (per spec 2.3.4.A.7 "All derived views
            // update automatically"). Deferred via setTimeout 0 — the
            // re-render chain above runs sync, but some derived render
            // hooks queue microtasks that would otherwise overwrite our
            // class changes if we set them synchronously.
            setTimeout(function() {
                const freshWrap   = document.getElementById('fr-wrap-' + memberId);
                const freshCard   = document.getElementById('fr-card-' + memberId);
                const freshExpand = document.getElementById('fr-expand-' + memberId);
                const freshEdit   = document.getElementById('fr-edit-panel-' + memberId);
                if (!freshWrap || !freshExpand) return;

                freshWrap.classList.add('expanded');
                freshWrap.classList.remove('edit-open');
                if (freshCard) freshCard.classList.add('expanded');
                if (freshEdit) freshEdit.style.display = 'none';

                // Fill Read panel with the just-saved values
                if (typeof window.paRenderReadExpandPanel === 'function') {
                    try { window.paRenderReadExpandPanel(memberId); } catch (e) {}
                }
                freshExpand.style.display = 'block';

                // Make sure the parent section is open too (re-render
                // gives sections `collapsed` by default).
                const sectionBody = freshWrap.closest('.fr-section-body');
                if (sectionBody && sectionBody.classList.contains('collapsed')) {
                    sectionBody.classList.remove('collapsed');
                    const sectId = sectionBody.id;
                    const toggle = document.getElementById(sectId + '-toggle');
                    if (toggle) toggle.querySelector('span').textContent = '−';
                    const header = toggle && toggle.closest('.fr-section-header');
                    if (header) header.classList.remove('collapsed');
                }

                // Mark this member as the currently open one so
                // Single-Expand keeps working.
                try { frOpenMemberId = memberId; } catch (e) {}
            }, 0);
        }

        // Add Relationship inline flow per spec 2.3.4.B (Violetka 2026-05-14
        // XD walkthrough). Two-step interaction:
        //
        //   Step 1: "Adding a <type> to You" \u2014 X close + searchable picker
        //           grouped by My Family / My Network + "Create New Profile"
        //   Step 2A: Existing picked \u2192 Configure (Type pre-filled, Role,
        //           Timeline, Notes, Save) \u2014 reuses Edit panel structure
        //   Step 2B: Create New \u2192 Inline Quick Create form (photo, names,
        //           DOB, Type pre-filled, Role, emails, phones, Save)
        //
        // FR_TYPE_META encodes the per-group title + Layer 1 (canonical
        // Relationship Type) so Step 1 panel headers and Step 2 Type
        // dropdown can be pre-filled correctly.
        const FR_TYPE_META = {
            spouse:   { title: 'Spouse / Partner',    layer1: 'Spouse / Partner' },
            child:    { title: 'Child',               layer1: 'Child' },
            parent:   { title: 'Parent',              layer1: 'Parent' },
            sibling:  { title: 'Sibling',             layer1: 'Sibling' },
            pet:      { title: 'Pet',                 layer1: 'Pet' },
            extended: { title: 'Extended Family',     layer1: 'Extended Family' },
            // Edit-mode-only subsection (per spec 2.3.3 "Former Partner / Spouse")
            former:   { title: 'Former Partner / Spouse', layer1: 'Former Partner / Spouse' }
        };
        // ────────────────────────────────────────────────────────────────
        // Phase 2A.3 — +Add Relationship inline flow (spec 2.3.4.B)
        //
        // Step 1: Click +Add → button transforms into Step 1 panel:
        //   Title "Adding a <type> to You"
        //   X close (top-right)
        //   Subtitle "Link an Existing Profile or Create New"
        //   Searchable picker — grouped by My Family / My Network +
        //   "Create New Profile" at the bottom (red).
        //
        // Step 2A: User selects an existing profile → Step 1 collapses
        //   and Step 2 "Configure Relationship" expands below the picked
        //   person summary card. Configure = same structure as Edit panel
        //   (Type pre-filled, Role required, Timeline, Notes, Save).
        //
        // Step 2B: User clicks "Create New Profile" → Step 1 collapses
        //   and the inline Quick Create Person Record form expands. On
        //   Save the person is added to peopleStore, the relationship is
        //   linked, and Step 2A flow continues from there.
        function frAddMember(type, evt) {
            if (evt && evt.stopPropagation) evt.stopPropagation();
            const meta = FR_TYPE_META[type];
            if (!meta) return;
            const btn = document.querySelector(`[onclick*="frAddMember('${type}'"]`)
                     || document.querySelector(`[onclick*="frAddMember(\\'${type}\\'"]`)
                     || document.querySelector(`[data-fr-add-type="${type}"]`);
            if (!btn) return;
            // Toggle: if a panel is already open for this type, close it
            const existing = btn.parentElement && btn.parentElement.querySelector('.fr-add-panel');
            if (existing) { existing.remove(); btn.style.display = ''; return; }

            // Determine anchor — Plan Owner on profile.html, viewed person
            // on record.html. Used for the panel title ("Adding a Sibling to
            // You" — "You" is from the viewer's POV) and bidirectional save.
            const anchorId = window.__paViewedPersonRealId || 'sj';
            const anchorPerson = (window.peopleStore || []).find(p => p && p.id === anchorId);

            // Exclude people who are ALREADY related to the anchor via an F&R
            // edge (Violetka 2026-05-15: "Енцо е вече в картата — няма логика
            // да ми се показва — директно само Create New Record опцията").
            // If user wants to edit Enzo's relationship, they do that via the
            // existing card's Edit mode — adding a duplicate edge is blocked
            // anyway by paFRAddSaveNew's duplicate guard, so excluding here
            // prevents confusion + cleaner picker.
            const anchorRelatedIds = new Set(
                ((anchorPerson && anchorPerson.relationships) || [])
                    .map(function(r) { return r && r.toId; })
                    .filter(Boolean)
            );

            // Build the universe of existing people, split into My Family
            // / My Network by category. Sort each group alphabetically.
            const universe = (Array.isArray(window.peopleStore) ? window.peopleStore : [])
                .filter(p => p && p.id && p.id !== anchorId
                          && (p.name || p.firstName || p.familyName)
                          && !p._isNew
                          && !anchorRelatedIds.has(p.id));   // already-in-card excluded
            function personLabel(p) {
                return p.name || ((p.firstName || '') + ' ' + (p.familyName || '')).trim();
            }
            function personRoleHint(p) {
                // "(Husband)", "(Lawyer)", "(Banker)" — small grey meta line
                return p.roleLayer2 || p.role || p.roleLayer1 || '';
            }
            function isFamilyPerson(p) {
                return (p.categories || []).indexOf('family') !== -1
                    || ((p.categories || []).length === 0
                        && (p.roleLayer1 || '').toLowerCase().indexOf('family') !== -1);
            }
            function isPetPerson(p) {
                return (p.categories || []).indexOf('pet') !== -1;
            }
            // POOL FILTERING (Violetka 2026-05-15: "в дропдовн опциите - не може
            // да се рекърди от семейството - а само от май нетворк - а при петс
            // даже трябва да са само опции от петс рекърдс само"):
            //   • type === 'pet' → ONLY pet records (existing pets the user might
            //     want to formally link to themselves; e.g. roommate's dog being
            //     adopted). Excludes all non-pet records.
            //   • Any other type (spouse/sibling/parent/child/extended/former)
            //     → ONLY My Network records. Family records already in tree —
            //     adding an existing family member as another family role would
            //     duplicate the edge. Network records can be "promoted" to Family
            //     by picking them here (categories flips to 'family' on save).
            //   • Family group is HIDDEN from the picker in all cases.
            const isPetFlow = (type === 'pet');
            const fam = []; // Always empty — family records excluded from picker
            const net = isPetFlow
                ? universe.filter(isPetPerson).sort((a,b) => personLabel(a).localeCompare(personLabel(b)))
                : universe.filter(p => !isFamilyPerson(p) && !isPetPerson(p))
                          .sort((a,b) => personLabel(a).localeCompare(personLabel(b)));

            // +Add button stays VISIBLE below the form (Violetka 2026-05-15
            // XD: "+Add Sibling" label at top:2406, form pad bottom at 2375
            // → form sits between "Siblings" label and "+Add Sibling" button,
            // both visible at the same time). NEVER hide the button.

            // Build & insert Step 1 panel BEFORE the button (so the form
            // appears above it, between the subsection label and the button)
            const panel = document.createElement('div');
            panel.className = 'fr-add-panel';
            panel.setAttribute('data-fr-type', type);
            panel.setAttribute('data-fr-step', '1');

            function escHtmlLocal(s) {
                return String(s == null ? '' : s)
                    .replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;')
                    .replace(/"/g,'&quot;').replace(/'/g,'&#39;');
            }
            function optionRow(p) {
                const lbl = escHtmlLocal(personLabel(p));
                const hint = escHtmlLocal(personRoleHint(p));
                return `<div class="fr-add-picker-option" role="option" data-person-id="${escHtmlLocal(p.id)}" onclick="paFRAddPickPerson('${escHtmlLocal(type)}','${escHtmlLocal(p.id)}', event)">
                    <div class="fr-add-picker-name">${lbl}</div>
                    ${hint ? `<div class="fr-add-picker-hint">(${hint})</div>` : ''}
                </div>`;
            }
            const famHtml = fam.length
                ? `<div class="fr-add-picker-group-label">My Family</div>${fam.map(optionRow).join('')}`
                : '';
            // Group label adapts to flow: 'My Pets' for pet flow, 'My Network'
            // for everything else (since fam pool is excluded per Violetka).
            const netGroupLabel = isPetFlow ? 'My Pets' : 'My Network';
            const netHtml = net.length
                ? `<div class="fr-add-picker-group-label">${netGroupLabel}</div>${net.map(optionRow).join('')}`
                : '';
            const createNewHtml = `<div class="fr-add-picker-option fr-add-picker-create"
                role="option" onclick="paFRAddCreateNew('${escHtmlLocal(type)}', event)">
                <div class="fr-add-picker-name">Create New Profile</div>
            </div>`;

            // POV-aware title (Violetka 2026-05-16: "тук не е правилно заглавието
            // на формата — Adding a Spouse / Partner to Robert Smith — трябва да
            // е така"). On profile.html (Plan Owner = Sarah = 'sj'), title reads
            // "Adding a X to You" since user IS Sarah. On record.html viewing
            // someone else, title must use that person's NAME instead of "You"
            // (because user is still Sarah, but the new relationship belongs to
            // the viewed record, not to Sarah). Pet records ("enzo") fall back
            // to "to Your Record" since pets don't have grammatical "name".
            const planOwnerId = 'sj';
            const anchorName = (anchorPerson && (anchorPerson.name ||
                                  ((anchorPerson.firstName || '') + ' ' +
                                   (anchorPerson.familyName || '')).trim())) || '';
            const titleSuffix = (anchorId === planOwnerId)
                ? 'to You'
                : (anchorName ? ('to ' + anchorName) : 'to Your Record');
            panel.innerHTML = `
                <button type="button" class="fr-add-close" aria-label="Close" onclick="paFRAddClose(this)">
                    <svg width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="#000" stroke-width="1.5" stroke-linecap="round" stroke-linejoin="round"><line x1="6" y1="6" x2="18" y2="18"/><line x1="18" y1="6" x2="6" y2="18"/></svg>
                </button>
                <div class="fr-add-title">Adding a ${escHtmlLocal(meta.title)} ${escHtmlLocal(titleSuffix)}</div>
                <div class="fr-add-subtitle">Link an Existing Profile or Create New</div>
                <div class="fr-add-picker">
                    <div class="fr-add-picker-wrap" onclick="paFRAddOpenPicker(this, event)">
                        <span class="fr-add-picker-value">Select Profile</span>
                        <input class="fr-add-picker-input" type="text" placeholder="Type to search…" autocomplete="off"
                               oninput="paFRAddFilterPicker(this)" onclick="event.stopPropagation()">
                        <span class="fr-add-picker-chevron"></span>
                    </div>
                    <div class="fr-add-picker-label">Add Profile</div>
                    <div class="fr-add-picker-options" role="listbox">
                        ${famHtml}
                        ${netHtml}
                        ${createNewHtml}
                    </div>
                </div>
                <div class="fr-add-step2-host"></div>
            `;
            btn.parentNode.insertBefore(panel, btn);   // form goes BEFORE the button
            setTimeout(() => panel.scrollIntoView({ behavior: 'smooth', block: 'nearest' }), 50);
        }

        // Close Step 1 panel — destroys the form pad. The +Add button stays
        // visible the whole time (Violetka 2026-05-15 XD canon), so no
        // display restoration needed. Defensive `btn.style.display = ''`
        // kept as a one-time migration for users who saw the older build
        // that hid the button.
        function paFRAddClose(closeEl) {
            const panel = closeEl.closest('.fr-add-panel');
            if (!panel) return;
            const type = panel.getAttribute('data-fr-type');
            panel.remove();
            // Migration: clear any leftover inline display:none from older builds
            const btn = document.querySelector(`[onclick*="frAddMember('${type}'"]`)
                     || document.querySelector(`[data-fr-add-type="${type}"]`);
            if (btn && btn.style.display === 'none') btn.style.display = '';
        }

        // Open the picker dropdown — toggles `.open` on the picker container.
        // Closing other open pickers + clearing search input on open.
        function paFRAddOpenPicker(wrapEl, evt) {
            if (evt) evt.stopPropagation();
            const picker = wrapEl.closest('.fr-add-picker');
            if (!picker) return;
            // Toggle open
            const wasOpen = picker.classList.contains('open');
            document.querySelectorAll('.fr-add-picker.open').forEach(p => p.classList.remove('open'));
            if (wasOpen) return;
            picker.classList.add('open');
            // Focus the search input + reset filter
            const input = picker.querySelector('.fr-add-picker-input');
            if (input) {
                input.value = '';
                setTimeout(() => input.focus(), 50);
            }
            paFRAddFilterPicker(input);
        }

        // Real-time search filter (case-insensitive, name match across options).
        function paFRAddFilterPicker(inputEl) {
            if (!inputEl) return;
            const picker = inputEl.closest('.fr-add-picker');
            if (!picker) return;
            const q = (inputEl.value || '').trim().toLowerCase();
            picker.querySelectorAll('.fr-add-picker-option').forEach(opt => {
                if (opt.classList.contains('fr-add-picker-create')) {
                    // Always show Create New at the bottom
                    opt.style.display = '';
                    return;
                }
                const name = (opt.querySelector('.fr-add-picker-name')?.textContent || '').toLowerCase();
                opt.style.display = (!q || name.indexOf(q) !== -1) ? '' : 'none';
            });
            // Also hide group labels when both groups are empty
            picker.querySelectorAll('.fr-add-picker-group-label').forEach(lbl => {
                let n = lbl.nextElementSibling;
                let anyVisible = false;
                while (n && !n.classList.contains('fr-add-picker-group-label') && !n.classList.contains('fr-add-picker-create')) {
                    if (n.style.display !== 'none') { anyVisible = true; break; }
                    n = n.nextElementSibling;
                }
                lbl.style.display = anyVisible ? '' : 'none';
            });
        }

        // Existing-profile selection → advances to Step 2 (Configure relationship).
        // Renders canonical Type/Role/Timeline/Save into the panel's
        // .fr-add-step2-host using THE SAME building blocks as Edit Mode
        // (paFRBuildTimelineBlocks, .fr-ep-field, .ei-save-btn-wrap).
        // Per Violetka 2026-05-14: "use approved components, don't invent new ones".
        function paFRAddPickPerson(type, personId, evt) {
            if (evt) evt.stopPropagation();
            const picker = document.querySelector(`.fr-add-panel[data-fr-type="${type}"] .fr-add-picker`);
            if (picker) picker.classList.remove('open');
            const panel = document.querySelector(`.fr-add-panel[data-fr-type="${type}"]`);
            if (!panel) return;
            panel.setAttribute('data-fr-picked-id', personId);
            panel.setAttribute('data-fr-step', '2');
            // Update the picker value display + subtitle copy
            const valEl = panel.querySelector('.fr-add-picker-value');
            const person = (window.peopleStore || []).find(p => p.id === personId);
            if (valEl && person) valEl.textContent = person.name || personId;
            const subtitleEl = panel.querySelector('.fr-add-subtitle');
            if (subtitleEl) subtitleEl.textContent = 'Configure Relationship';
            // Render the Configure panel into the host.
            paFRAddRenderConfigurePanel(type, personId);
        }

        // "Create New Profile" path → opens inline Quick Create form.
        // Renders identity fields (First/Last Name + Status radios) ABOVE
        // the canonical Configure section (Type/Role/Timeline/Save) so the
        // user fills both in one screen, then Save creates the person
        // stub + bidirectional relationship in a single transaction.
        function paFRAddCreateNew(type, evt) {
            if (evt) evt.stopPropagation();
            const picker = document.querySelector(`.fr-add-panel[data-fr-type="${type}"] .fr-add-picker`);
            if (picker) picker.classList.remove('open');
            const panel = document.querySelector(`.fr-add-panel[data-fr-type="${type}"]`);
            if (!panel) return;
            panel.setAttribute('data-fr-step', '3');
            panel.setAttribute('data-fr-mode', 'create-new');
            // Update picker value display + subtitle copy
            const valEl = panel.querySelector('.fr-add-picker-value');
            if (valEl) valEl.textContent = 'Create New Profile';
            const subtitleEl = panel.querySelector('.fr-add-subtitle');
            if (subtitleEl) subtitleEl.textContent = 'Create New Family Profile';
            paFRAddRenderCreateNewPanel(type);
        }

        // CANONICAL F&R Add X form — Violetka 2026-05-15 directive:
        // "вземи всичко от аватарта надолу и сложи тази бланка като бланка на ADD X,
        //  като полето *Релатисхип Тъпе е популнео с това в зависимост кой бутон е
        //  натиснат (Add Sibling, Add Parent, etc.)"
        //
        // Implementation: reuse buildContactEditFormHtml (the SAME canonical form
        // used in Entry People & Contacts → Add New Contact / Edit existing) with
        // options to:
        //   • hide the My Network / My Family directory pill (locked Family)
        //   • pre-fill Relationship Type from FR_TYPE_META[type].layer1
        //   • route Save to paFRAddSaveCreateNewCanonical (also creates F&R edge)
        //
        // This gives F&R Add X the FULL form: Avatar, First/Family Name, DOB,
        // Life Status, Relationship Type (PRE-FILLED), Specific Role, Relationship
        // Timeline (date fields by role), E-mails, Phone Numbers, Social Media,
        // Notes, Save — identical to the canonical Add New Contact form.
        function paFRAddRenderCreateNewPanel(type) {
            const panel = document.querySelector(`.fr-add-panel[data-fr-type="${type}"]`);
            if (!panel) return;
            const host = panel.querySelector('.fr-add-step2-host');
            if (!host) return;
            const meta = FR_TYPE_META[type] || { layer1: 'Spouse / Partner' };
            // CRITICAL MAPPING (Violetka 2026-05-15 — fix: Specific Role hidden):
            // FR_TYPE_META.layer1 is SINGULAR ('Spouse / Partner', 'Sibling',
            // 'Parent', 'Child', 'Pet', 'Extended Family'). But canonical
            // LSC_EDIT_ROLES_FAMILY (Layer 1 dropdown for buildContactEditFormHtml)
            // uses PLURAL keys ('Spouses / Partners', 'Siblings', 'Parents',
            // 'Children', 'Pets', 'Other'). Without mapping, LSC_EDIT_LAYER2_FAMILY
            // lookup returns [] → Specific Role picker stays hidden because no
            // options → user can't save. Map here for pixel-perfect preset.
            const FR_TO_LSC_LAYER1 = {
                'Spouse / Partner':         'Spouses / Partners',
                'Former Partner / Spouse':  'Former Partner / Spouse',
                'Child':                    'Children',
                'Parent':                   'Parents',
                'Sibling':                  'Siblings',
                'Pet':                      'Pets',
                'Extended Family':          'Other'
            };
            const presetLayer1 = FR_TO_LSC_LAYER1[meta.layer1] || meta.layer1;
            function escHtmlLocal(s) {
                return String(s == null ? '' : s)
                    .replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;')
                    .replace(/"/g,'&quot;').replace(/'/g,'&#39;');
            }
            const typeEsc = escHtmlLocal(type);

            // Create stub person — pushed to peopleStore so saveContactEdit
            // can resolve by data-person-id. _isNew flag lets cancelCreate /
            // saveContactEdit detect CREATE mode + clean up properly.
            const stubId = 'fr_new_' + Date.now().toString(36) + Math.random().toString(36).slice(2, 6);
            const isPet = (type === 'pet');
            const stub = {
                id: stubId,
                firstName: '', familyName: '', name: '',
                roleLayer1: presetLayer1,
                roleLayer2: '',
                photo: '', dob: '',
                categories: isPet ? ['family', 'pet'] : ['family'],
                emails: [], phones: [], socials: [], notes: '',
                relationships: [], sharedTo: [],
                alive: true, lifeStatus: 'Living',
                _isNew: true
            };
            if (!Array.isArray(window.peopleStore)) window.peopleStore = [];
            window.peopleStore.push(stub);

            // Build canonical form via buildContactEditFormHtml with options.
            // hideDirectoryPill: skip "Add This Person to" + Network/Family pill
            // presetDir: 'family' — lock branch (F&R is always Family)
            // presetLayer1: pre-fill Relationship Type from button context
            // startExpanded: skip CREATE-mode collapse (no pill to click)
            // saveOnclick: route to F&R-specific save that also creates edge
            // extraFormAttrs: tag form so the save handler knows F&R context
            const formHtml = buildContactEditFormHtml(stub, {
                hideDirectoryPill: true,
                presetDir: 'family',
                presetLayer1: presetLayer1,
                startExpanded: true,
                // HIDE Relationship Type field (Violetka 2026-05-15: "щом си
                // избрал бутона Add X, то вече е избрано — трябва да се избере
                // само Specific Role"). Layer 1 value still stored in DOM via
                // presetLayer1, so saveContactEdit reads it correctly.
                hideRelationshipType: true,
                // PET FORM (Violetka 2026-05-15: "бланката за добавяне на домашен
                // любимец трябва да е с различни полета"). When type==='pet':
                // single Pet Name field, hide E-mails/Phones/Socials, show Breed/
                // Microchip/Primary Vet/Vet Phone/Guardian instead.
                isPetForm: isPet,
                saveOnclick: `paFRAddSaveCreateNewCanonical('${typeEsc}', this)`,
                extraFormAttrs: ` data-fr-create-type="${typeEsc}" data-create-mode="true"`
            });

            // Wrap form in .fr-add-canonical-wrap (provides 100px L/R padding
            // so fields + avatar sit 100px from card edge — canonical Add New
            // Contact pattern from openCreateContactFlow). Without this wrap
            // the form is left-aligned and fields touch the card edge.
            host.innerHTML = `<div class="fr-add-canonical-wrap">${formHtml}</div>`;

            // After render: prime the Family branch state. lscEditDir handles
            // DOB visibility (Family ON), Layer 2 picker mode (Family = picker
            // dropdown, Network = free-text), Organization/Title hide (Network-only),
            // and populates Layer 1 options. Then lscEditPopulateRoleLayer2
            // populates Layer 2 options based on the pre-filled Layer 1, and
            // lscEditRenderRelationshipDates renders any role-specific date fields.
            const form = host.querySelector('.lsc-edit-form');
            if (form) {
                const familyBtn = form.querySelector('.lsc-edit-dir-btn[data-dir="family"]');
                if (familyBtn && typeof window.lscEditDir === 'function') {
                    window.lscEditDir(familyBtn, 'family');
                }
                if (typeof window.lscEditPopulateRoleLayer2 === 'function') {
                    window.lscEditPopulateRoleLayer2(form, presetLayer1);
                }
            }

            // Smooth scroll into view + focus First Name for immediate typing
            try {
                setTimeout(function() {
                    host.scrollIntoView({ behavior: 'smooth', block: 'nearest' });
                    const firstInp = host.querySelector('.lsc-edit-firstname');
                    if (firstInp) firstInp.focus();
                }, 50);
            } catch (e) {}
            return;
            /* === LEGACY CUSTOM MARKUP BELOW — UNREACHABLE (kept for ref) ===
            const L1_KEYS = ['Spouse / Partner','Former Partner / Spouse','Child','Parent','Sibling','Pet','Extended Family'];
            const l2Options = (window.paFRLayer2ByLayer1 && window.paFRLayer2ByLayer1[presetLayer1]) || [];
            const initialRole = l2Options[0] || '';
            let html = '';

            // Wrap entire Create New form in .lsc-edit-form so canonical
            // avatar / save / drag-drop handlers (lscEditAvatarChange,
            // lscEditAvatarDragOver, etc.) can locate it via closest('.lsc-edit-form').
            // data-create-mode signals these handlers we're in CREATE flow
            // (no existing peopleStore record to mutate — photo applied on save).
            html += '<div class="lsc-edit-form" data-create-mode="true" data-fr-create="true">';

            // — Profile Image Upload — CANONICAL .lsc-edit-avatar-row pattern
            //   (Violetka 2026-05-15: "аватар на формата при създаване на нов
            //   рекърд трябва да има бяло кръгче и всички функционалсти").
            //   80×80 white-33% outer wrap + inner 40×40 white circle (grows
            //   to 60×60 on hover/drag-over) + plus 20×20 (opacity 0.16 → 1
            //   on hover) + drag/drop file support. Source: canonical avatar
            //   in buildContactEditFormHtml + .lsc-avatar-add-state CSS.
            html += '<div class="lsc-edit-avatar-row" onclick="this.querySelector(\'.lsc-avatar-file-input\').click()" ondragover="lscEditAvatarDragOver(event,this)" ondragleave="lscEditAvatarDragLeave(event,this)" ondrop="lscEditAvatarDrop(event,this)">';
            html +=   '<div class="lsc-avatar-wrap lsc-edit-avatar-wrap lsc-avatar-add-state">';
            html +=     '<span class="lsc-avatar-add-inner"></span>';
            html +=     '<svg class="lsc-avatar-add-plus" viewBox="0 0 20 20" width="20" height="20" fill="none" stroke="#000" stroke-width="1.5" stroke-linecap="round" aria-hidden="true"><path d="M10 5 L10 15 M5 10 L15 10"/></svg>';
            html +=     '<span class="lsc-avatar-edit-overlay" aria-hidden="true">+</span>';
            html +=   '</div>';
            html +=   '<div class="lsc-edit-avatar-cap">Add Profile Image</div>';
            html +=   '<input type="file" class="lsc-avatar-file-input" accept="image/png,image/jpeg,image/webp" style="display:none" onchange="lscEditAvatarChange(this)">';
            html += '</div>';

            // — First Name (required) — CANONICAL .ee-input-row / .ee-input-wrap
            html += '<div class="ee-input-row fr-ep-field">';
            html +=   '<div class="ee-input-wrap fr-ep-select-row">';
            html +=     '<input class="ee-input-value fr-create-first" type="text" placeholder="First Name" autocomplete="off">';
            html +=   '</div>';
            html +=   '<div class="ee-input-label fr-ep-label"><span class="fr-req">*</span>First Name</div>';
            html += '</div>';

            // — Family Name (required) — same canonical wrap
            html += '<div class="ee-input-row fr-ep-field">';
            html +=   '<div class="ee-input-wrap fr-ep-select-row">';
            html +=     '<input class="ee-input-value fr-create-last" type="text" placeholder="Family Name" autocomplete="off">';
            html +=   '</div>';
            html +=   '<div class="ee-input-label fr-ep-label"><span class="fr-req">*</span>Family Name</div>';
            html += '</div>';

            // — Date of Birth — three side-by-side dropdowns (Year/Month/Day),
            //   canonical .fr-tl-select pattern from the F&R timeline Y/M/D.
            html += '<div class="ee-input-row fr-ep-field fr-create-dob-row">';
            html +=   '<div class="fr-create-dob-grid">';
            html +=     '<div class="fr-create-dob-cell">';
            html +=       '<select class="fr-tl-select fr-create-dob-year">';
            html +=         '<option value="" disabled selected>Year *</option>';
            const dobYearMax = new Date().getFullYear();
            for (let y = dobYearMax; y >= 1900; y--) html += `<option value="${y}">${y}</option>`;
            html +=       '</select>';
            html +=     '</div>';
            html +=     '<div class="fr-create-dob-cell">';
            html +=       '<select class="fr-tl-select fr-create-dob-month">';
            html +=         '<option value="" disabled selected>Month *</option>';
            const dobMonthNames = ['January','February','March','April','May','June','July','August','September','October','November','December'];
            dobMonthNames.forEach((mn, i) => { html += `<option value="${String(i+1).padStart(2,'0')}">${mn}</option>`; });
            html +=       '</select>';
            html +=     '</div>';
            html +=     '<div class="fr-create-dob-cell">';
            html +=       '<select class="fr-tl-select fr-create-dob-day">';
            html +=         '<option value="" disabled selected>Day *</option>';
            for (let d = 1; d <= 31; d++) html += `<option value="${String(d).padStart(2,'0')}">${d}</option>`;
            html +=       '</select>';
            html +=     '</div>';
            html +=   '</div>';
            html +=   '<div class="ee-input-label fr-ep-label"><span class="fr-req">*</span>Date of Birth</div>';
            html += '</div>';

            // — Life Status — Living / Deceased / Unknown
            //   PIXEL-PERFECT canonical Essential Info Life Status pattern
            //   (Violetka 2026-05-15: "кругатет за опции тряба да почват от
            //   100 пиксел, а самият лейбъл Life Status от 120 пиксел да започва").
            //   Source: record.html line 1526-1541. Visual positions from card edge:
            //   pill outer at 100, radio circle at 120 (pill 20 internal padding),
            //   label at 120. margin-top:20 matches canonical Essential Info.
            //   The whole F&R Step 3 form is wrapped in .lsc-edit-form (above), so
            //   scoped CSS override `.lsc-edit-form .ei-radio-group { padding-left:0 }`
            //   applies here too — cancels the canonical padding-left:100 to prevent
            //   doubling with .linked-summary-wrap padding-left:100. Label inline
            //   padding-left:20 (NOT 120) for same reason. Default = "Living" selected
            //   since this is CREATE flow (new profile, no existing data to read).
            html += '<div class="ei-radio-group fr-create-life-status-group" style="margin-top:20px;">';
            html +=   '<div class="ei-radio-item selected" data-life-status="Living" onclick="paFRAddPickLifeStatus(this)">';
            html +=     '<div class="ei-radio-circle"><div class="ei-radio-dot"></div></div>';
            html +=     '<span class="ei-radio-label">Living</span>';
            html +=   '</div>';
            html +=   '<div class="ei-radio-item" data-life-status="Deceased" onclick="paFRAddPickLifeStatus(this)">';
            html +=     '<div class="ei-radio-circle"><div class="ei-radio-dot"></div></div>';
            html +=     '<span class="ei-radio-label">Deceased</span>';
            html +=   '</div>';
            html +=   '<div class="ei-radio-item" data-life-status="Unknown" onclick="paFRAddPickLifeStatus(this)">';
            html +=     '<div class="ei-radio-circle"><div class="ei-radio-dot"></div></div>';
            html +=     '<span class="ei-radio-label">Unknown</span>';
            html +=   '</div>';
            html += '</div>';
            html += '<input type="hidden" class="fr-create-life-status-value" value="Living">';
            // Label inline padding-left:20 (NOT 120). .linked-summary-wrap already
            // provides padding-left:100 → total 100+20 = 120 from card edge.
            html += '<div class="ei-field-label" style="padding-left:20px; margin-bottom:20px;">Life Status</div>';

            // — Configure section — Type + Role + Timeline (CANONICAL .ee-input-*)
            const l1OptsJsonCN = JSON.stringify(L1_KEYS).replace(/'/g, '&#39;');
            html += '<div class="ee-input-row fr-ep-field">';
            html += `  <div class="ee-input-wrap fr-ep-select-row fr-ep-type-wrap" data-options='${l1OptsJsonCN}' data-fr-type="${typeEsc}" onclick="event.stopPropagation();eeOpenFieldDropdown(this)">`;
            html += `    <span class="ee-input-value fr-ep-type">${escHtmlLocal(layer1Default)}</span>`;
            html +=     '<span class="ee-input-chevron fr-ep-chevron"></span>';
            html +=   '</div>';
            html +=   '<div class="ee-input-label fr-ep-label"><span class="fr-req">*</span>Relationship Type</div>';
            html += '</div>';
            const isPetCreate = (layer1Default === 'Pet');
            const l2OptsJsonCN = JSON.stringify(l2Options).replace(/'/g, '&#39;');
            html += `<div class="ee-input-row fr-ep-field"${isPetCreate ? ' style="display:none"' : ''}>`;
            html += `  <div class="ee-input-wrap fr-ep-select-row fr-ep-role-wrap" data-options='${l2OptsJsonCN}' data-fr-type="${typeEsc}" onclick="event.stopPropagation();eeOpenFieldDropdown(this)">`;
            // XD canon: empty Specific Role shows "Select Specific Role" placeholder text
            html += `    <span class="ee-input-value fr-ep-role">Select Specific Role</span>`;
            html +=     '<span class="ee-input-chevron fr-ep-chevron"></span>';
            html +=   '</div>';
            html +=   '<div class="ee-input-label fr-ep-label"><span class="fr-req">*</span>Specific Role</div>';
            html += '</div>';
            html += '<div class="fr-ep-timeline-host">';
            html += (typeof window.paFRBuildTimelineBlocks === 'function')
                ? window.paFRBuildTimelineBlocks(initialRole, {})
                : '';
            html += '</div>';

            // Contact Info sections (E-mails / Phones / Social Media), Notes
            // & Instructions, and Link Related People — DEFERRED until the
            // canonical entry form is fixed first (Violetka 2026-05-15:
            // "нека първо да поправим бланката за създаване на нов рекърд
            // през ентри"). After ANEF entry form is fixed, this Step 3
            // form will REUSE the same canonical sections.

            // Save button — canonical
            html += '<div class="fr-panel-actions">';
            html +=   `<div class="ei-save-btn-wrap" onclick="paFRAddSaveCreateNew('${typeEsc}')">`;
            html +=     '<span class="ei-save-btn-label">Save</span>';
            html +=     '<span class="ei-save-btn-dash"></span>';
            html +=     '<span class="ei-save-btn-circle">';
            html +=       '<svg class="ei-save-btn-arrow" width="9" height="16" viewBox="0 0 9 16" fill="none" stroke="#000" stroke-width="1.5" stroke-linecap="round" stroke-linejoin="round"><path d="M1 1l7 7-7 7"/></svg>';
            html +=     '</span>';
            html +=   '</div>';
            html += '</div>';

            html += '</div>'; // close .lsc-edit-form wrapper

            host.innerHTML = html;
            // Wire canonical .ee-input-wrap change listeners — Create-flow
            const typeWrapCN = host.querySelector('.fr-ep-type-wrap');
            const roleWrapCN = host.querySelector('.fr-ep-role-wrap');
            if (typeWrapCN) {
                typeWrapCN.addEventListener('ee-input-change', function(ev) {
                    paFRAddHandleCreateTypeChangeCanonical(type, ev.detail.value);
                });
            }
            if (roleWrapCN) {
                roleWrapCN.addEventListener('ee-input-change', function(ev) {
                    paFRAddHandleCreateRoleChangeCanonical(type, ev.detail.value);
                });
            }
            // Auto-focus First Name + smooth scroll into view
            try {
                setTimeout(function() {
                    host.scrollIntoView({ behavior: 'smooth', block: 'nearest' });
                    const firstInp = host.querySelector('.fr-create-first');
                    if (firstInp) firstInp.focus();
                }, 50);
            } catch (e) {}
            === END LEGACY UNREACHABLE CODE === */
        }

        // Create-flow Type pick (canonical) — refilter L2 + rebuild timeline.
        // Resets Specific Role to placeholder "Select Specific Role" (NOT
        // auto-selecting first option per XD canon).
        function paFRAddHandleCreateTypeChangeCanonical(type, newL1) {
            const panel = document.querySelector(`.fr-add-panel[data-fr-type="${type}"]`);
            if (!panel) return;
            const roleWrap = panel.querySelector('.fr-ep-role-wrap');
            const roleValue = roleWrap && roleWrap.querySelector('.ee-input-value');
            if (!roleWrap) return;
            const roleRow = roleWrap.closest('.ee-input-row');
            const l2Options = (window.paFRLayer2ByLayer1 && window.paFRLayer2ByLayer1[newL1]) || [];
            const optsJson = JSON.stringify(l2Options).replace(/'/g, '&#39;');
            roleWrap.setAttribute('data-options', optsJson);
            if (roleValue) roleValue.textContent = 'Select Specific Role';
            if (roleRow) roleRow.style.display = (newL1 === 'Pet') ? 'none' : '';
            paFRAddRefreshTimeline(panel, '');
        }

        // Profile Image pick — trigger hidden file input.
        function paFRAddPickProfileImage(circle) {
            if (!circle) return;
            const input = circle.querySelector('.fr-create-avatar-input');
            if (input) input.click();
        }

        // Profile Image change handler — read file as Data URL, set as
        // background image on the circle + replace + plus icon with photo.
        function paFRAddHandleProfileImage(input) {
            if (!input || !input.files || !input.files[0]) return;
            const file = input.files[0];
            const reader = new FileReader();
            reader.onload = function(e) {
                const circle = input.closest('.fr-create-avatar-circle');
                if (!circle) return;
                circle.style.backgroundImage = `url("${e.target.result}")`;
                circle.classList.add('has-image');
                circle.setAttribute('data-image', e.target.result);
            };
            reader.readAsDataURL(file);
        }

        // Create-flow Role pick (canonical) — rebuild timeline only.
        function paFRAddHandleCreateRoleChangeCanonical(type, newRole) {
            const panel = document.querySelector(`.fr-add-panel[data-fr-type="${type}"]`);
            if (!panel) return;
            paFRAddRefreshTimeline(panel, newRole);
        }

        // Legacy onchange (no-op after canonical refactor).
        function paFRAddHandleCreateTypeChange(selectEl, type) {
            const panel = document.querySelector(`.fr-add-panel[data-fr-type="${type}"]`);
            if (!panel) return;
            const newL1 = selectEl.value;
            const roleSelect = panel.querySelector('.fr-ep-role');
            if (!roleSelect) return;
            const roleField = roleSelect.closest('.fr-ep-field');
            const l2Options = (window.paFRLayer2ByLayer1 && window.paFRLayer2ByLayer1[newL1]) || [];
            function escHtmlLocal(s) {
                return String(s == null ? '' : s)
                    .replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;')
                    .replace(/"/g,'&quot;').replace(/'/g,'&#39;');
            }
            roleSelect.innerHTML = l2Options.map(function(opt) {
                return `<option value="${escHtmlLocal(opt)}">${escHtmlLocal(opt)}</option>`;
            }).join('');
            if (roleField) roleField.style.display = (newL1 === 'Pet') ? 'none' : '';
            const firstRole = l2Options[0] || '';
            paFRAddRefreshTimeline(panel, firstRole);
        }

        // Create-flow Role onchange (mirrors paFRAddHandleRoleChange)
        function paFRAddHandleCreateRoleChange(selectEl, type) {
            const panel = document.querySelector(`.fr-add-panel[data-fr-type="${type}"]`);
            if (!panel) return;
            paFRAddRefreshTimeline(panel, selectEl.value);
        }

        // Save flow for Create New Profile path.
        // 1. Validate First Name + Type + Role
        // 2. Create a new person stub in peopleStore (id = new uuid-like slug)
        // 3. Write bidirectional relationship via the same logic as paFRAddSaveNew
        // CANONICAL F&R Add X save handler — paired with the refactored
        // paFRAddRenderCreateNewPanel that uses buildContactEditFormHtml.
        // Flow:
        //   1. Validate & finalise the new person via saveContactEdit
        //      (canonical write to peopleStore — name, dob, lifeStatus, alive,
        //      emails, phones, socials, notes, roleLayer1, roleLayer2, organisation,
        //      title — same logic as Edit existing contact)
        //   2. Create bidirectional F&R relationship edge:
        //      anchor.relationships ← { toId, type, specificRole, dates }
        //      newPerson.relationships ← { toId: anchorId, type: invType, dates }
        //   3. Persist + engine pass + re-render F&R + close panel
        function paFRAddSaveCreateNewCanonical(type, btn) {
            const form = btn && btn.closest ? btn.closest('.lsc-edit-form') : null;
            if (!form) return;
            const personId = form.getAttribute('data-person-id');
            const person = (window.peopleStore || []).find(p => p && p.id === personId);
            if (!person) return;
            // Step 1 — run canonical saveContactEdit (mutates person in place).
            // saveContactEdit validates, writes all fields, drops _isNew, calls
            // paAutoSave + entry refresh. Return early if validation failed
            // (saveContactEdit shows its own error UI).
            if (typeof window.saveContactEdit !== 'function') return;
            try {
                window.saveContactEdit(btn);
            } catch (e) {
                console.warn('[F&R Add Canonical] saveContactEdit error:', e);
                return;
            }
            // After saveContactEdit, the person should still exist in peopleStore
            // (just finalised). If saveContactEdit removed it (validation fail),
            // the relationship logic below silently no-ops.
            const refreshed = (window.peopleStore || []).find(p => p && p.id === personId);
            if (!refreshed) return;
            // Step 1.5 — PET-specific fields (Violetka 2026-05-15: persist Breed,
            // Microchip, Primary Vet, Vet Phone, Guardian to person record so
            // they appear in the pet's Essential Info post-save). Same field
            // names as record.html canonical Essential Info storage.
            if (form.classList.contains('pet-form')) {
                const petBreed     = (form.querySelector('.lsc-edit-pet-breed')      || {}).value || '';
                const petMicrochip = (form.querySelector('.lsc-edit-pet-microchip')  || {}).value || '';
                const petVet       = (form.querySelector('.lsc-edit-pet-vet')        || {}).value || '';
                const petVetPhone  = (form.querySelector('.lsc-edit-pet-vet-phone')  || {}).value || '';
                const petGuardian  = (form.querySelector('.lsc-edit-pet-guardian')   || {}).value || '';
                // Species comes from Specific Role (Layer 2 picker, canonical
                // LSC_EDIT_LAYER2_FAMILY.Pets options). saveContactEdit already
                // wrote it to refreshed.roleLayer2 — mirror to refreshed.species
                // so Essential Info readers (eiReadSpecies etc.) find it.
                refreshed.species   = refreshed.roleLayer2 || '';
                refreshed.breed     = petBreed.trim();
                refreshed.microchip = petMicrochip.trim();
                refreshed.vet       = petVet.trim();
                refreshed.vetPhone  = petVetPhone.trim();
                refreshed.guardian  = petGuardian.trim();
                // Ensure pet category persists (saveContactEdit may overwrite
                // categories based on dir; we add 'pet' back if not present).
                refreshed.categories = refreshed.categories || [];
                if (refreshed.categories.indexOf('pet') === -1) {
                    refreshed.categories.push('pet');
                }
            }
            // Step 2 — reconcile the F&R bidirectional relationship edge.
            //
            // NOTE: saveContactEdit (just called above) ALREADY writes the
            // canonical anchor↔person edge using paNormalizeRelType +
            // paComputeInverseRel. This step is now IDEMPOTENT and only
            // ENRICHES that edge with anything saveContactEdit might have
            // missed (e.g. specific role mapping via paFRRoleToType or
            // dates from a different form path). Never pushes duplicates.
            const layer1 = refreshed.roleLayer1 || '';
            const layer2 = refreshed.roleLayer2 || '';
            const edgeType = (window.paFRRoleToType && window.paFRRoleToType[layer2])
                          || (window.paFRLayer1ToType && window.paFRLayer1ToType[layer1])
                          || type;  // fallback to the raw button-type
            // Read relationship-specific dates — canonical buildContactEditFormHtml
            // renders blocks as .lsc-edit-rel-required-block / .lsc-edit-rel-optional-block
            // (NOT the legacy .lsc-edit-rel-date-pad). Use canonical selectors.
            const MONTHS_ENG = ['January','February','March','April','May','June','July','August','September','October','November','December'];
            const toMonthNum = function(m) {
                if (!m) return '';
                if (/^\d+$/.test(m)) return String(parseInt(m, 10)).padStart(2, '0');
                const idx = MONTHS_ENG.indexOf(m);
                return idx >= 0 ? String(idx + 1).padStart(2, '0') : '';
            };
            const newDates = {};
            form.querySelectorAll('.lsc-edit-rel-required-block, .lsc-edit-rel-optional-block').forEach(function(block) {
                const key = block.getAttribute('data-date-key');
                if (!key) return;
                const y    = (block.querySelector('.lsc-edit-rel-date-year')  || {}).value || '';
                const mRaw = (block.querySelector('.lsc-edit-rel-date-month') || {}).value || '';
                const d    = (block.querySelector('.lsc-edit-rel-date-day')   || {}).value || '';
                const n    = (block.querySelector('.lsc-edit-rel-date-notes') || {}).value || '';
                const labelInp = block.querySelector('.tl-custom-label-input');
                const customLabel = labelInp ? String(labelInp.value || '').trim() : '';
                const m = toMonthNum(mRaw);
                let iso = '';
                if (y) iso = String(y);
                if (y && m) iso = `${y}-${m}`;
                if (y && m && d) iso = `${y}-${m}-${String(d).padStart(2, '0')}`;
                if (iso) newDates[key] = iso;
                if (n && String(n).trim()) newDates[key + 'Notes'] = String(n).trim();
                if (customLabel) newDates[key + 'Label'] = customLabel;
            });
            // ANCHOR — POV-aware. record.html sets __paViewedPersonRealId
            // to the viewed person; profile.html leaves it undefined → 'sj'.
            const anchorId = window.__paViewedPersonRealId || 'sj';
            const anchor = (window.peopleStore || []).find(p => p && p.id === anchorId);
            if (anchor) {
                anchor.relationships = anchor.relationships || [];
                // FIND-OR-UPDATE: saveContactEdit already wrote this edge —
                // enrich it without duplicating (the dedupe pass that runs
                // in the engine keys by toId, so duplicates would silently
                // lose the second writer's fields — including these dates).
                let anchorRel = anchor.relationships.find(r => r && r.toId === personId);
                if (!anchorRel) {
                    anchorRel = { toId: personId };
                    anchor.relationships.push(anchorRel);
                }
                if (edgeType) anchorRel.type = edgeType;
                if (layer2)   anchorRel.specificRole = layer2;
                anchorRel.dates = Object.assign({}, anchorRel.dates || {}, newDates);
                // Inverse — use paComputeInverseRel for FULL inverse (type +
                // gendered specificRole). Was paInverseEdgeType (type-only)
                // which lost the gendered label (Violetka 2026-05-16 audit C2).
                const anchorGender = (anchor.gender || '').toLowerCase();
                const inv = (typeof window.paComputeInverseRel === 'function')
                    ? window.paComputeInverseRel(edgeType, layer2, anchorGender)
                    : null;
                const invType = inv ? inv.type
                    : ((typeof window.paInverseEdgeType === 'function') ? window.paInverseEdgeType(edgeType) : edgeType);
                refreshed.relationships = refreshed.relationships || [];
                let personRel = refreshed.relationships.find(r => r && r.toId === anchorId);
                if (!personRel) {
                    personRel = { toId: anchorId };
                    refreshed.relationships.push(personRel);
                }
                if (invType) personRel.type = invType;
                if (inv && inv.specificRole) personRel.specificRole = inv.specificRole;
                personRel.dates = Object.assign({}, personRel.dates || {}, newDates);
            }
            // Step 3 — persist + engine + FULL refresh chain across the
            // entire platform (Violetka 2026-05-18: "ако добавя съпруг в
            // рекорда на Емма — ще се покаже ли навсякъде"). The added
            // person + their bidirectional edge + every derived link the
            // Tier A engine computes must show on:
            //   • the record's F&R card (paInjectFamilyMembersIntoFRCard)
            //   • the anchor person's F&R (paRenderFamilyRelationships)
            //   • Family Directory + Network Directory (My Family / My Network)
            //   • Family Tree + tree analytics
            //   • F&R header stats (Marital / Number of Children)
            //   • F&R analytics card (counters per group)
            //   • every avatar reference (sidebar, header, etc.) via paSyncPersonAvatars
            if (typeof window.paAutoSave === 'function') {
                try { window.paAutoSave(); } catch (e) {}
            }
            if (typeof window.paRelationshipEngine === 'function') {
                try { window.paRelationshipEngine(); } catch (e) {}
            }
            if (typeof window.paInjectFamilyMembersIntoFRCard === 'function') {
                try { window.paInjectFamilyMembersIntoFRCard(); } catch (e) {}
            }
            if (typeof window.paRenderFamilyRelationships === 'function') {
                try { window.paRenderFamilyRelationships(anchorId); } catch (e) {}
            }
            if (typeof window.paUpdateFamilyAnalytics === 'function') {
                try { window.paUpdateFamilyAnalytics(); } catch (e) {}
            }
            if (typeof window.paUpdateFamilyHeaderStats === 'function') {
                try { window.paUpdateFamilyHeaderStats(); } catch (e) {}
            }
            if (typeof window.renderFamilyDirectory === 'function') {
                try { window.renderFamilyDirectory(); } catch (e) {}
            }
            if (typeof window.renderNetworkDirectory === 'function') {
                try { window.renderNetworkDirectory(); } catch (e) {}
            }
            if (typeof window.paRecomputeFamilyTreeAnalytics === 'function') {
                try { window.paRecomputeFamilyTreeAnalytics(); } catch (e) {}
            }
            if (typeof window.paInjectNewFamilyMembersIntoTree === 'function') {
                try { window.paInjectNewFamilyMembersIntoTree(); } catch (e) {}
            }
            if (typeof window.paSyncPersonAvatars === 'function') {
                try { window.paSyncPersonAvatars(); } catch (e) {}
            }
            // Close the F&R Add panel + restore +Add button
            const panel = form.closest('.fr-add-panel');
            if (panel) {
                const closeBtn = panel.querySelector('.fr-add-close');
                if (closeBtn && typeof window.paFRAddClose === 'function') {
                    window.paFRAddClose(closeBtn);
                }
            }
            try {
                const fullName = (refreshed.name || (refreshed.firstName + ' ' + refreshed.familyName)).trim();
                const roleLabel = layer2 || layer1 || type;
                window.dispatchEvent(new CustomEvent('toast', {
                    detail: { msg: `${fullName} created and added as ${roleLabel}` }
                }));
            } catch (e) {}
        }

        // LEGACY save handler (kept for backward-compat if anything still calls it):
        // 4. Persist + re-render F&R + close panel
        function paFRAddSaveCreateNew(type) {
            const panel = document.querySelector(`.fr-add-panel[data-fr-type="${type}"]`);
            if (!panel) return;
            const firstInp = panel.querySelector('.fr-create-first');
            const lastInp  = panel.querySelector('.fr-create-last');
            const dobYearSel  = panel.querySelector('.fr-create-dob-year');
            const dobMonthSel = panel.querySelector('.fr-create-dob-month');
            const dobDaySel   = panel.querySelector('.fr-create-dob-day');
            // Photo — read from canonical .lsc-avatar-photo (after lscEditAvatarChange
            // replaces the .lsc-avatar-add-state with an <img>). Falls back to legacy
            // .fr-create-avatar-circle data-image attribute for old cached builds.
            const canonAvatarPhoto = panel.querySelector('.lsc-avatar-photo');
            const legacyAvatarCircle = panel.querySelector('.fr-create-avatar-circle');
            const photoDataUrl = (canonAvatarPhoto && canonAvatarPhoto.getAttribute('src'))
                              || (legacyAvatarCircle && legacyAvatarCircle.getAttribute('data-image'))
                              || '';
            // Life Status: prefer hidden input value (canonical Essential
            // Info pattern), fall back to data-life-status on selected item.
            const lifeStatusHidden = panel.querySelector('.fr-create-life-status-value');
            const lifeStatusItem = panel.querySelector('.fr-create-life-status-group .ei-radio-item.selected');
            const lifeStatus = (lifeStatusHidden && lifeStatusHidden.value)
                            || (lifeStatusItem && lifeStatusItem.getAttribute('data-life-status'))
                            || 'Living';
            const typeVal = panel.querySelector('.fr-ep-type');
            const roleVal = panel.querySelector('.fr-ep-role');
            const firstName = (firstInp && firstInp.value || '').trim();
            const lastName  = (lastInp  && lastInp.value  || '').trim();
            // Type/Role come from CANONICAL .ee-input-value text. Treat the
            // placeholder "Select Specific Role" as empty (= not picked yet).
            const layer1 = typeVal ? (typeVal.textContent || '').trim() : '';
            let specificRole = roleVal ? (roleVal.textContent || '').trim() : '';
            if (specificRole === 'Select Specific Role') specificRole = '';
            // DOB from the three Y/M/D dropdowns
            const dobY  = (dobYearSel  && dobYearSel.value)  || '';
            const dobMo = (dobMonthSel && dobMonthSel.value) || '';
            const dobD  = (dobDaySel   && dobDaySel.value)   || '';
            let dobIso = '';
            if (dobY) dobIso = dobY;
            if (dobY && dobMo) dobIso = dobY + '-' + dobMo;
            if (dobY && dobMo && dobD) dobIso = dobY + '-' + dobMo + '-' + dobD;
            // Validation: First Name + Family Name + Type required. Role
            // required except for Pet (uses Species/Breed instead, spec 2.3.4.B.11).
            const roleRequired = layer1 !== 'Pet';
            const errors = [];
            if (!firstName) { errors.push(firstInp.closest('.ee-input-wrap')); }
            if (!lastName) { errors.push(lastInp.closest('.ee-input-wrap')); }
            if (!layer1) { errors.push(panel.querySelector('.fr-ep-type-wrap')); }
            if (roleRequired && !specificRole) { errors.push(panel.querySelector('.fr-ep-role-wrap')); }
            if (errors.length) {
                errors.forEach(w => w && w.classList.add('is-error'));
                try { window.dispatchEvent(new CustomEvent('toast', { detail: { msg: 'Fill required fields' } })); } catch {}
                return;
            }
            // Create new person stub. All +Add Relationship paths route
            // through FR_TYPE_META, which only covers family types
            // (spouse/child/parent/sibling/pet/extended/former) — so we
            // can safely tag categories with 'family'. Pet gets a
            // secondary 'pet' tag so downstream renderers can pick the
            // Pet card variant.
            const fullName = lastName ? (firstName + ' ' + lastName) : firstName;
            const newId = 'p_' + Date.now().toString(36) + Math.random().toString(36).slice(2, 6);
            const categories = (type === 'pet') ? ['family', 'pet'] : ['family'];
            const newPerson = {
                id: newId,
                name: fullName,
                firstName: firstName,
                familyName: lastName || '',
                dob: dobIso,
                // Canonical lifeStatus ('Living' | 'Deceased' | 'Unknown') used
                // platform-wide by header/life-dot/In-Memory renderers. Keep
                // `livingStatus` (legacy lowercase) for backward-compat AND
                // sync `alive` boolean — every reader stays correct.
                lifeStatus: lifeStatus,
                livingStatus: (lifeStatus || 'Living').toLowerCase(),
                alive: (lifeStatus === 'Living'),
                categories: categories,
                roleLayer1: meta_layer1OrFallback(type),
                roleLayer2: specificRole || (type === 'pet' ? 'Pet' : ''),
                relationships: [],
                _isNew: false                                         // visible from creation
            };
            if (photoDataUrl) newPerson.photo = photoDataUrl;
            // Push into the store
            window.peopleStore = window.peopleStore || [];
            window.peopleStore.push(newPerson);
            // Now save the bidirectional relationship — reuse paFRAddSaveNew
            // logic by writing directly to anchor + new person.
            const edgeType = (window.paFRRoleToType && window.paFRRoleToType[specificRole])
                          || (window.paFRLayer1ToType && window.paFRLayer1ToType[layer1])
                          || '';
            const newDates = {};
            panel.querySelectorAll('.tl-milestone, .fr-milestone-block').forEach(function(block) {
                const key = block.getAttribute('data-key');
                if (!key) return;
                const y  = (block.querySelector('.fr-ms-year')  || {}).value || '';
                const mo = (block.querySelector('.fr-ms-month') || {}).value || '';
                const d  = (block.querySelector('.fr-ms-day')   || {}).value || '';
                const n  = (block.querySelector('.fr-ms-notes') || {}).value || '';
                const labelInp = block.querySelector('.tl-custom-label-input');
                const customLabel = labelInp ? String(labelInp.value || '').trim() : '';
                let iso = '';
                if (y) iso = y;
                if (y && mo) iso = y + '-' + mo;
                if (y && mo && d) iso = y + '-' + mo + '-' + d;
                if (iso) newDates[key] = iso;
                if (n && String(n).trim()) newDates[key + 'Notes'] = String(n).trim();
                if (customLabel) newDates[key + 'Label'] = customLabel;
            });
            const anchorId = window.__paViewedPersonRealId || 'sj';
            const anchor = (window.peopleStore || []).find(p => p && p.id === anchorId);
            if (anchor) {
                anchor.relationships = anchor.relationships || [];
                // FIND-OR-UPDATE — idempotent (Violetka 2026-05-16 audit:
                // avoid duplicate pushes that would be silently lost by the
                // engine's dedupe pass which keys by toId only).
                let anchorRel = anchor.relationships.find(r => r && r.toId === newId);
                if (!anchorRel) {
                    anchorRel = { toId: newId };
                    anchor.relationships.push(anchorRel);
                }
                if (edgeType)       anchorRel.type = edgeType;
                if (specificRole)   anchorRel.specificRole = specificRole;
                anchorRel.dates = Object.assign({}, anchorRel.dates || {}, newDates);
                // Inverse — use paComputeInverseRel for FULL inverse (type +
                // gendered specificRole). Violetka 2026-05-16 audit fix C2.
                const anchorGender = (anchor.gender || '').toLowerCase();
                const inv = (typeof window.paComputeInverseRel === 'function')
                    ? window.paComputeInverseRel(edgeType, specificRole, anchorGender)
                    : null;
                const invType = inv ? inv.type
                    : ((typeof window.paInverseEdgeType === 'function') ? window.paInverseEdgeType(edgeType) : edgeType);
                newPerson.relationships = newPerson.relationships || [];
                let personRel = newPerson.relationships.find(r => r && r.toId === anchorId);
                if (!personRel) {
                    personRel = { toId: anchorId };
                    newPerson.relationships.push(personRel);
                }
                if (invType) personRel.type = invType;
                if (inv && inv.specificRole) personRel.specificRole = inv.specificRole;
                personRel.dates = Object.assign({}, personRel.dates || {}, newDates);
            }
            // Persist + engine pass + re-render
            if (typeof window.paAutoSave === 'function') { try { window.paAutoSave(); } catch (e) {} }
            if (typeof window.paRelationshipEngine === 'function') { try { window.paRelationshipEngine(); } catch (e) {} }
            if (typeof window.paInjectFamilyMembersIntoFRCard === 'function') { try { window.paInjectFamilyMembersIntoFRCard(); } catch (e) {} }
            if (typeof window.paRenderFamilyRelationships === 'function') { try { window.paRenderFamilyRelationships(anchorId); } catch (e) {} }
            // Close panel + restore +Add button
            paFRAddClose(panel.querySelector('.fr-add-close'));
            try { window.dispatchEvent(new CustomEvent('toast', { detail: { msg: `${fullName} created and added as ${specificRole}` } })); } catch {}
        }

        // Helper: derive a sensible roleLayer1 label from the section type
        function meta_layer1OrFallback(type) {
            return (FR_TYPE_META[type] && FR_TYPE_META[type].layer1) || 'Family';
        }

        // Status pick handler — canonical .ei-radio-item selection (single-select)
        function paFRAddPickStatus(item) {
            if (!item) return;
            const group = item.closest('.fr-create-status-group');
            if (!group) return;
            group.querySelectorAll('.ei-radio-item').forEach(function(i) {
                i.classList.toggle('selected', i === item);
            });
        }

        // Life Status pick handler (Living / Deceased / Unknown).
        // Updates the canonical .ei-radio-item.selected class + syncs the
        // hidden <input> value so save reads the correct status.
        function paFRAddPickLifeStatus(item) {
            if (!item) return;
            const group = item.closest('.fr-create-life-status-group');
            if (!group) return;
            group.querySelectorAll('.ei-radio-item').forEach(function(i) {
                i.classList.toggle('selected', i === item);
            });
            const value = item.getAttribute('data-life-status') || 'Living';
            const hiddenInput = group.parentElement.querySelector('.fr-create-life-status-value');
            if (hiddenInput) hiddenInput.value = value;
        }

        // Global validation auto-clear — any input/change inside an
        // .fr-add-panel or .fr-edit-panel clears .is-error from its
        // canonical .ee-input-wrap (and legacy .fr-ep-select-row)
        // wrapper so the red underline disappears as soon as the user
        // starts fixing the field (spec 2.3.4.B.11). Listens for the
        // canonical 'ee-input-change' custom event dispatched when the
        // user picks a value from .ee-field-dropdown.
        function _frClearIsErrorFromTarget(target) {
            if (!target) return;
            const wrap = target.closest('.fr-add-panel .ee-input-wrap.is-error, .fr-edit-panel .ee-input-wrap.is-error, .fr-add-panel .fr-ep-select-row.is-error, .fr-edit-panel .fr-ep-select-row.is-error');
            if (wrap) wrap.classList.remove('is-error');
        }
        document.addEventListener('input',           function(e) { _frClearIsErrorFromTarget(e.target); }, true);
        document.addEventListener('change',          function(e) { _frClearIsErrorFromTarget(e.target); }, true);
        document.addEventListener('ee-input-change', function(e) { _frClearIsErrorFromTarget(e.target); }, true);

        // Step 2 — Configure Relationship inline panel render.
        // Reuses canonical Edit-panel building blocks: .fr-ep-field +
        // .fr-ep-select-row + .fr-ep-chevron for Type/Role, paFRBuildTimelineBlocks
        // for milestones, .fr-panel-actions + .ei-save-btn-wrap for Save.
        // Wires onchange handlers (paFRAddHandleTypeChange / RoleChange) and
        // delegates to paFRAddRefreshTimeline on each change.
        function paFRAddRenderConfigurePanel(type, personId) {
            const panel = document.querySelector(`.fr-add-panel[data-fr-type="${type}"]`);
            if (!panel) return;
            const host = panel.querySelector('.fr-add-step2-host');
            if (!host) return;
            const meta = FR_TYPE_META[type] || { layer1: 'Spouse / Partner' };
            const layer1Default = meta.layer1;
            const L1_KEYS = ['Spouse / Partner','Former Partner / Spouse','Child','Parent','Sibling','Pet','Extended Family'];
            const l2Options = (window.paFRLayer2ByLayer1 && window.paFRLayer2ByLayer1[layer1Default]) || [];
            const initialRole = l2Options[0] || '';
            function escHtmlLocal(s) {
                return String(s == null ? '' : s)
                    .replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;')
                    .replace(/"/g,'&quot;').replace(/'/g,'&#39;');
            }
            const typeEsc = escHtmlLocal(type);
            const personIdEsc = escHtmlLocal(personId);
            let html = '';

            // Layer 1 — Relationship Type (CANONICAL .ee-input-row / .ee-input-wrap)
            const l1OptsJson = JSON.stringify(L1_KEYS).replace(/'/g, '&#39;');
            html += '<div class="ee-input-row fr-ep-field">';
            html += `  <div class="ee-input-wrap fr-ep-select-row fr-ep-type-wrap" data-options='${l1OptsJson}' data-fr-type="${typeEsc}" onclick="event.stopPropagation();eeOpenFieldDropdown(this)">`;
            html += `    <span class="ee-input-value fr-ep-type">${escHtmlLocal(layer1Default)}</span>`;
            html +=     '<span class="ee-input-chevron fr-ep-chevron"></span>';
            html +=   '</div>';
            html +=   '<div class="ee-input-label fr-ep-label"><span class="fr-req">*</span>Relationship Type</div>';
            html += '</div>';

            // Layer 2 — Specific Role (filtered by Layer 1). Hidden for Pet.
            const isPet = (layer1Default === 'Pet');
            const l2OptsJson = JSON.stringify(l2Options).replace(/'/g, '&#39;');
            html += `<div class="ee-input-row fr-ep-field"${isPet ? ' style="display:none"' : ''}>`;
            html += `  <div class="ee-input-wrap fr-ep-select-row fr-ep-role-wrap" data-options='${l2OptsJson}' data-fr-type="${typeEsc}" onclick="event.stopPropagation();eeOpenFieldDropdown(this)">`;
            html += `    <span class="ee-input-value fr-ep-role">${escHtmlLocal(initialRole)}</span>`;
            html +=     '<span class="ee-input-chevron fr-ep-chevron"></span>';
            html +=   '</div>';
            html +=   '<div class="ee-input-label fr-ep-label"><span class="fr-req">*</span>Specific Role</div>';
            html += '</div>';

            // Timeline blocks — same builder as Edit Mode. Empty dates (new rel).
            html += '<div class="fr-ep-timeline-host">';
            html += (typeof window.paFRBuildTimelineBlocks === 'function')
                ? window.paFRBuildTimelineBlocks(initialRole, {})
                : '';
            html += '</div>';

            // Save button — canonical PlanAfter save pattern (label + dash + arrow).
            html += '<div class="fr-panel-actions">';
            html +=   `<div class="ei-save-btn-wrap" onclick="paFRAddSaveNew('${typeEsc}', '${personIdEsc}')">`;
            html +=     '<span class="ei-save-btn-label">Save</span>';
            html +=     '<span class="ei-save-btn-dash"></span>';
            html +=     '<span class="ei-save-btn-circle">';
            html +=       '<svg class="ei-save-btn-arrow" width="9" height="16" viewBox="0 0 9 16" fill="none" stroke="#000" stroke-width="1.5" stroke-linecap="round" stroke-linejoin="round"><path d="M1 1l7 7-7 7"/></svg>';
            html +=     '</span>';
            html +=   '</div>';
            html += '</div>';

            host.innerHTML = html;
            // Wire canonical .ee-input-wrap change listeners — type/role picks
            // dispatch 'ee-input-change' from eeOpenFieldDropdown.
            const typeWrap = host.querySelector('.fr-ep-type-wrap');
            const roleWrap = host.querySelector('.fr-ep-role-wrap');
            if (typeWrap) {
                typeWrap.addEventListener('ee-input-change', function(ev) {
                    paFRAddHandleTypeChangeCanonical(type, personId, ev.detail.value);
                });
            }
            if (roleWrap) {
                roleWrap.addEventListener('ee-input-change', function(ev) {
                    paFRAddHandleRoleChangeCanonical(type, personId, ev.detail.value);
                });
            }
            // Smooth scroll the Configure section into view so the user
            // immediately sees the new fields below the picker.
            try { setTimeout(() => host.scrollIntoView({ behavior: 'smooth', block: 'nearest' }), 50); } catch (e) {}
        }

        // Configure Type pick (canonical) — re-filter L2 + rebuild timeline.
        // Hides Role field for Pet (no Specific Role; uses Species/Breed).
        function paFRAddHandleTypeChangeCanonical(type, personId, newL1) {
            const panel = document.querySelector(`.fr-add-panel[data-fr-type="${type}"]`);
            if (!panel) return;
            const roleWrap = panel.querySelector('.fr-ep-role-wrap');
            const roleValue = roleWrap && roleWrap.querySelector('.ee-input-value');
            if (!roleWrap) return;
            const roleRow = roleWrap.closest('.ee-input-row');
            const l2Options = (window.paFRLayer2ByLayer1 && window.paFRLayer2ByLayer1[newL1]) || [];
            const firstRole = l2Options[0] || '';
            const optsJson = JSON.stringify(l2Options).replace(/'/g, '&#39;');
            roleWrap.setAttribute('data-options', optsJson);
            if (roleValue) roleValue.textContent = firstRole;
            if (roleRow) roleRow.style.display = (newL1 === 'Pet') ? 'none' : '';
            paFRAddRefreshTimeline(panel, firstRole);
        }

        // Configure Role pick (canonical) — rebuild timeline only.
        function paFRAddHandleRoleChangeCanonical(type, personId, newRole) {
            const panel = document.querySelector(`.fr-add-panel[data-fr-type="${type}"]`);
            if (!panel) return;
            paFRAddRefreshTimeline(panel, newRole);
        }

        // Legacy onchange (kept for safety if any native <select> still
        // calls it from somewhere — no-op in the canonical flow).
        function paFRAddHandleTypeChange(selectEl, type, personId) {
            const panel = document.querySelector(`.fr-add-panel[data-fr-type="${type}"]`);
            if (!panel) return;
            const newL1 = selectEl.value;
            const roleSelect = panel.querySelector('.fr-ep-role');
            if (!roleSelect) return;
            const roleField = roleSelect.closest('.fr-ep-field');
            const l2Options = (window.paFRLayer2ByLayer1 && window.paFRLayer2ByLayer1[newL1]) || [];
            function escHtmlLocal(s) {
                return String(s == null ? '' : s)
                    .replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;')
                    .replace(/"/g,'&quot;').replace(/'/g,'&#39;');
            }
            roleSelect.innerHTML = l2Options.map(function(opt) {
                return `<option value="${escHtmlLocal(opt)}">${escHtmlLocal(opt)}</option>`;
            }).join('');
            if (roleField) roleField.style.display = (newL1 === 'Pet') ? 'none' : '';
            const firstRole = l2Options[0] || '';
            paFRAddRefreshTimeline(panel, firstRole);
        }

        // Configure Role onchange — rebuild timeline only.
        function paFRAddHandleRoleChange(selectEl, type, personId) {
            const panel = document.querySelector(`.fr-add-panel[data-fr-type="${type}"]`);
            if (!panel) return;
            paFRAddRefreshTimeline(panel, selectEl.value);
        }

        // Re-render the timeline host inside the Configure panel.
        // Captures any in-progress Y/M/D/Notes values so the user
        // doesn't lose typed data when Role changes.
        function paFRAddRefreshTimeline(panel, specificRole) {
            const host = panel.querySelector('.fr-ep-timeline-host');
            if (!host) return;
            // Capture current values (so role change doesn't wipe entered dates)
            const captured = {};
            host.querySelectorAll('.tl-milestone, .fr-milestone-block').forEach(function(block) {
                const key = block.getAttribute('data-key');
                if (!key) return;
                const y  = (block.querySelector('.fr-ms-year')  || {}).value || '';
                const mo = (block.querySelector('.fr-ms-month') || {}).value || '';
                const d  = (block.querySelector('.fr-ms-day')   || {}).value || '';
                const n  = (block.querySelector('.fr-ms-notes') || {}).value || '';
                let iso = '';
                if (y) iso = y;
                if (y && mo) iso = y + '-' + mo;
                if (y && mo && d) iso = y + '-' + mo + '-' + d;
                if (iso) captured[key] = iso;
                if (n && String(n).trim()) captured[key + 'Notes'] = String(n).trim();
            });
            host.innerHTML = (typeof window.paFRBuildTimelineBlocks === 'function')
                ? window.paFRBuildTimelineBlocks(specificRole, captured)
                : '';
        }

        // Step 2 Save — creates a NEW bidirectional relationship between
        // the anchor (Sarah on profile.html, viewed person on record.html)
        // and the picked existing profile. Mirrors frSaveMember structure.
        function paFRAddSaveNew(type, personId) {
            const panel = document.querySelector(`.fr-add-panel[data-fr-type="${type}"]`);
            if (!panel) return;
            // Read from CANONICAL .ee-input-value (was native <select>.value).
            const typeVal = panel.querySelector('.fr-ep-type');
            const roleVal = panel.querySelector('.fr-ep-role');
            const layer1 = typeVal ? (typeVal.textContent || '').trim() : '';
            const specificRole = roleVal ? (roleVal.textContent || '').trim() : '';
            // Required: Type. Role required EXCEPT for Pet (which uses
            // Species/Breed instead — spec 2.3.4.B.11).
            const roleRequired = layer1 !== 'Pet';
            if (!layer1 || (roleRequired && !specificRole)) {
                const typeWrap = panel.querySelector('.fr-ep-type-wrap');
                const roleWrap = panel.querySelector('.fr-ep-role-wrap');
                if (!layer1 && typeWrap) typeWrap.classList.add('is-error');
                if (roleRequired && !specificRole && roleWrap) roleWrap.classList.add('is-error');
                try { window.dispatchEvent(new CustomEvent('toast', { detail: { msg: 'Pick Type and Role' } })); } catch {}
                return;
            }
            // Duplicate guard — refuse to create a second rel to the same person.
            // Existing rel should be edited via the card's Edit mode instead.
            const anchorIdGuard = window.__paViewedPersonRealId || 'sj';
            const anchorGuard = (window.peopleStore || []).find(p => p && p.id === anchorIdGuard);
            const existingRel = anchorGuard && (anchorGuard.relationships || []).find(r => r && r.toId === personId);
            if (existingRel) {
                try { window.dispatchEvent(new CustomEvent('toast', { detail: { msg: 'Relationship already exists — edit instead' } })); } catch {}
                return;
            }
            // Canonical edgeType resolution (Role-specific overrides Layer-1 default)
            const edgeType = (window.paFRRoleToType && window.paFRRoleToType[specificRole])
                          || (window.paFRLayer1ToType && window.paFRLayer1ToType[layer1])
                          || '';
            // Collect dates from milestones
            const newDates = {};
            panel.querySelectorAll('.tl-milestone, .fr-milestone-block').forEach(function(block) {
                const key = block.getAttribute('data-key');
                if (!key) return;
                const y  = (block.querySelector('.fr-ms-year')  || {}).value || '';
                const mo = (block.querySelector('.fr-ms-month') || {}).value || '';
                const d  = (block.querySelector('.fr-ms-day')   || {}).value || '';
                const n  = (block.querySelector('.fr-ms-notes') || {}).value || '';
                const labelInp = block.querySelector('.tl-custom-label-input');
                const customLabel = labelInp ? String(labelInp.value || '').trim() : '';
                let iso = '';
                if (y) iso = y;
                if (y && mo) iso = y + '-' + mo;
                if (y && mo && d) iso = y + '-' + mo + '-' + d;
                if (iso) newDates[key] = iso;
                if (n && String(n).trim()) newDates[key + 'Notes'] = String(n).trim();
                if (customLabel) newDates[key + 'Label'] = customLabel;
            });
            // Write to peopleStore — anchor + person + inverse
            const anchorId = window.__paViewedPersonRealId || 'sj';
            const anchor = (window.peopleStore || []).find(p => p && p.id === anchorId);
            const person = (window.peopleStore || []).find(p => p && p.id === personId);
            if (anchor && person) {
                anchor.relationships = anchor.relationships || [];
                let rel = anchor.relationships.find(r => r && r.toId === personId);
                if (!rel) { rel = { toId: personId }; anchor.relationships.push(rel); }
                if (edgeType) rel.type = edgeType;
                if (specificRole) rel.specificRole = specificRole;
                rel.dates = Object.assign({}, rel.dates || {}, newDates);
                // Inverse — use paComputeInverseRel for FULL inverse (type +
                // gendered specificRole). Violetka 2026-05-16 audit fix C2.
                person.relationships = person.relationships || [];
                let invRel = person.relationships.find(r => r && r.toId === anchorId);
                if (!invRel) { invRel = { toId: anchorId }; person.relationships.push(invRel); }
                const anchorGender = (anchor.gender || '').toLowerCase();
                const inv = (typeof window.paComputeInverseRel === 'function')
                    ? window.paComputeInverseRel(edgeType, specificRole, anchorGender)
                    : null;
                const invType = inv ? inv.type
                    : ((typeof window.paInverseEdgeType === 'function') ? window.paInverseEdgeType(edgeType) : edgeType);
                if (invType) invRel.type = invType;
                if (inv && inv.specificRole) invRel.specificRole = inv.specificRole;
                invRel.dates = Object.assign({}, invRel.dates || {}, newDates);
                // Persist + re-render F&R
                if (typeof window.paAutoSave === 'function') { try { window.paAutoSave(); } catch (e) {} }
                if (typeof window.paRelationshipEngine === 'function') { try { window.paRelationshipEngine(); } catch (e) {} }
                if (typeof window.paInjectFamilyMembersIntoFRCard === 'function') { try { window.paInjectFamilyMembersIntoFRCard(); } catch (e) {} }
                if (typeof window.paRenderFamilyRelationships === 'function') { try { window.paRenderFamilyRelationships(anchorId); } catch (e) {} }
            }
            // Close the +Add panel and restore +Add button visibility
            paFRAddClose(panel.querySelector('.fr-add-close'));
            try { window.dispatchEvent(new CustomEvent('toast', { detail: { msg: `${(person && person.name) || personId} added as ${specificRole}` } })); } catch {}
        }

        // Click-outside handler — close any open picker dropdown when the
        // user clicks elsewhere on the page.
        document.addEventListener('click', function(e) {
            if (!e.target.closest('.fr-add-picker')) {
                document.querySelectorAll('.fr-add-picker.open').forEach(p => p.classList.remove('open'));
            }
        });

        // Legacy backward-compat wrappers — old hardcoded onclick="frCloseAddPanel"
        // attributes still call the original wrapper name. Just delegate.
        function frCloseAddPanel(closeBtn) { return paFRAddClose(closeBtn); }
        function frPickPerson(opt) {
            const personId = opt.getAttribute('data-person-id');
            const panel = opt.closest('.fr-add-panel');
            const type = panel && panel.getAttribute('data-fr-type');
            if (type && personId) paFRAddPickPerson(type, personId);
        }
        function frSaveAddPanel(btn) {
            const panel = btn.closest('.fr-add-panel');
            if (!panel) return;
            const type = panel.getAttribute('data-fr-type');
            const personPicker = panel.querySelector('.fr-person-picker');
            const rolePicker   = panel.querySelector('.fr-role-picker');
            const personId   = personPicker?.getAttribute('data-person-id');
            const personName = personPicker?.querySelector('.ee-contact-picker-value')?.textContent?.trim();
            const role       = rolePicker?.querySelector('.ee-contact-picker-value')?.textContent?.trim();
            const errors = [];
            if (!personId || !personName || personName === 'Search or add a contact') {
                errors.push(personPicker.querySelector('.ee-input-wrap'));
            }
            if (!role || /^Select /.test(role)) {
                errors.push(rolePicker.querySelector('.ee-input-wrap'));
            }
            if (errors.length) {
                errors.forEach(w => w && w.classList.add('is-error'));
                return;
            }
            // Persist the relationship to peopleStore (single source of truth).
            // Anchor (Plan Owner = Sarah, id 'sj') gets a direct link entry;
            // the linked person gets an inverse-type entry so cross-record
            // propagation works (per spec 2.4.1: relationships are bidirectional).
            // Specific role is stored on the anchor side; the inverse side gets
            // a placeholder role the user can refine via Edit later (gender
            // clarification flow per spec 2.4.4 is deferred).
            const INVERSE_TYPE = {
                spouse:   'spouse',
                child:    'parent',
                parent:   'child',
                sibling:  'sibling',
                pet:      'pet-of',
                extended: 'extended'
            };
            // ANCHOR = whoever's record we're editing — Sarah ('sj') on
            // profile.html, viewed person on record.html. (Violetka 2026-05-16
            // POV fix: previously hardcoded 'sj' → all relationships from
            // record.html got wired to Sarah by mistake.)
            const anchorId = window.__paViewedPersonRealId || 'sj';
            const anchor = window.peopleStore && (Array.isArray(window.peopleStore)
                ? window.peopleStore.find(p => p.id === anchorId)
                : window.peopleStore[anchorId]);
            const linked = window.peopleStore && (Array.isArray(window.peopleStore)
                ? window.peopleStore.find(p => p.id === personId)
                : window.peopleStore[personId]);
            if (anchor) {
                anchor.relationships = anchor.relationships || [];
                // Find-or-update (not push) — Violetka 2026-05-16 audit fix I2:
                // legacy duplicate guard was (toId, type), which the engine's
                // dedupe (keyed by toId only) silently strips. Use toId only.
                let anchorRel = anchor.relationships.find(r => r && r.toId === personId);
                if (!anchorRel) { anchorRel = { toId: personId }; anchor.relationships.push(anchorRel); }
                if (type) anchorRel.type = type;
                if (role) anchorRel.specificRole = role;
            }
            if (linked) {
                linked.relationships = linked.relationships || [];
                // Inverse — use paComputeInverseRel for FULL inverse (type +
                // gendered specificRole). Was a hardcoded INVERSE_TYPE table
                // missing step/adopted/foster variants (Violetka 2026-05-16
                // audit fix C2).
                const anchorGender = (anchor && anchor.gender ? anchor.gender : '').toLowerCase();
                const inv = (typeof window.paComputeInverseRel === 'function')
                    ? window.paComputeInverseRel(type, role, anchorGender)
                    : null;
                const invType = inv ? inv.type : (INVERSE_TYPE[type] || type);
                let invRel = linked.relationships.find(r => r && r.toId === anchorId);
                if (!invRel) { invRel = { toId: anchorId }; linked.relationships.push(invRel); }
                if (invType) invRel.type = invType;
                if (inv && inv.specificRole) invRel.specificRole = inv.specificRole;
            }
            if (typeof window.paSaveSession === 'function') window.paSaveSession();
            // Render a Linked Summary Card in the matching group.
            const titleMap = {
                spouse:   'Spouse / Partner',
                child:    'Children',
                parent:   'Parents',
                sibling:  'Siblings',
                pet:      'Pets',
                extended: 'Extended Family'
            };
            const groupTitle = titleMap[type];
            const initials = personName.split(/\s+/).map(s => s[0] || '').slice(0,2).join('').toUpperCase();
            const card = document.createElement('div');
            card.className = 'ee-person-card ee-view-only';
            card.setAttribute('data-fr-link', personId);
            card.setAttribute('data-person-id', personId);
            card.style.margin = '10px 0';
            card.style.cursor = 'pointer';
            card.setAttribute('onclick', `if(typeof openPersonRecord==='function')openPersonRecord('${personId}')`);
            card.innerHTML = `
                <div class="ee-person-avatar"><span class="emc-avatar-initials">${escHtml(initials)}</span></div>
                <div class="ee-person-info">
                    <div class="ee-person-name">${escHtml(personName)}</div>
                    <div class="ee-person-role">Your ${escHtml(role)}</div>
                </div>`;
            // Insert before the +Add button (so cards appear above, button stays last)
            const btnEl = panel.previousElementSibling || document.querySelector(`[onclick*="frAddMember('${type}')"]`);
            const parent = panel.parentNode;
            parent.insertBefore(card, btnEl || panel);
            // Close panel + restore +Add button
            frCloseAddPanel(panel.querySelector('.anef-close'));
            // Toast for confirmation
            try { window.dispatchEvent(new CustomEvent('toast', { detail: { msg: `${personName} added as ${role}` } })); } catch {}
        }
        window.frAddMember = frAddMember;
        window.frCloseAddPanel = frCloseAddPanel;
        window.frPickPerson = frPickPerson;
        window.frSaveAddPanel = frSaveAddPanel;
        // Phase 2A.3 — new flow helpers
        window.paFRAddClose            = paFRAddClose;
        window.paFRAddOpenPicker       = paFRAddOpenPicker;
        window.paFRAddFilterPicker     = paFRAddFilterPicker;
        window.paFRAddPickPerson       = paFRAddPickPerson;
        window.paFRAddCreateNew        = paFRAddCreateNew;
        // Step 2 — Configure inline
        window.paFRAddRenderConfigurePanel = paFRAddRenderConfigurePanel;
        window.paFRAddHandleTypeChange     = paFRAddHandleTypeChange;
        window.paFRAddHandleRoleChange     = paFRAddHandleRoleChange;
        window.paFRAddRefreshTimeline      = paFRAddRefreshTimeline;
        window.paFRAddSaveNew              = paFRAddSaveNew;
        // Step 3 — Create New Profile inline
        window.paFRAddRenderCreateNewPanel  = paFRAddRenderCreateNewPanel;
        window.paFRAddHandleCreateTypeChange = paFRAddHandleCreateTypeChange;
        window.paFRAddHandleCreateRoleChange = paFRAddHandleCreateRoleChange;
        window.paFRAddSaveCreateNew         = paFRAddSaveCreateNew;
        window.paFRAddSaveCreateNewCanonical = paFRAddSaveCreateNewCanonical;
        window.paFRAddPickStatus            = paFRAddPickStatus;
        window.paFRAddPickLifeStatus        = paFRAddPickLifeStatus;
        window.paFRAddPickProfileImage      = paFRAddPickProfileImage;
        window.paFRAddHandleProfileImage    = paFRAddHandleProfileImage;
        // F&R card-row menu actions — explicit window exports so inline
        // onclick handlers AND other scripts (peopleDirectory.js etc.) can
        // call them reliably from outside this bootstrap scope. (Violetka
        // 2026-05-16: ... menus on family.html .pd-card weren't firing
        // because `frOpenMenu` was not on window.)
        window.frOpenMenu                   = frOpenMenu;
        window.frOpenProfile                = frOpenProfile;
        window.frShare                      = frShare;
        window.frRemove                     = frRemove;
        window.frDelete                     = frDelete;
        // Render persisted (user-added) Family relationships on page load.
        // Walks Sarah's peopleStore.relationships and inserts a Linked Summary
        // Card for any relationship NOT already represented by a static
        // fr-member-card[data-person-id] in the DOM. Idempotent (skips cards
        // already wired by paUpgradeFrMemberCards).
        function paRenderPersistedFamilyCards() {
            if (!Array.isArray(window.peopleStore)) return;
            const anchor = window.peopleStore.find(p => p.id === 'sj');
            if (!anchor || !Array.isArray(anchor.relationships)) return;
            anchor.relationships.forEach(rel => {
                if (!rel || !rel.toId || !rel.type) return;
                // Skip seed-rendered relationships \u2014 they already have a
                // static fr-member-card with id="fr-card-NAME". paUpgradeFrMemberCards
                // sets data-person-id on those, so we check both.
                const linkedPerson = window.peopleStore.find(p => p.id === rel.toId);
                if (!linkedPerson) return;
                const already = document.querySelector(`.fr-member-card[data-person-id="${rel.toId}"], .ee-person-card[data-person-id="${rel.toId}"]`);
                if (already) return;
                // Find the +Add button for this relationship type \u2014 user-added
                // cards live in the same group. fr-member-card vs ee-person-card
                // is incidental; both are accepted by openPersonRecord routing.
                const addBtn = document.querySelector(`[onclick*="frAddMember('${rel.type}')"]`);
                if (!addBtn) return;
                const initials = (linkedPerson.name || '').split(/\s+/).map(s => s[0] || '').slice(0,2).join('').toUpperCase();
                const card = document.createElement('div');
                card.className = 'ee-person-card ee-view-only';
                card.setAttribute('data-fr-link', rel.toId);
                card.setAttribute('data-person-id', rel.toId);
                card.style.margin = '10px 0';
                card.style.cursor = 'pointer';
                card.setAttribute('onclick', `if(typeof openPersonRecord==='function')openPersonRecord('${rel.toId}')`);
                const roleLabel = rel.role ? `Your ${escHtml(rel.role)}` : escHtml(linkedPerson.role || rel.type);
                card.innerHTML = `
                    <div class="ee-person-avatar"><span class="emc-avatar-initials">${escHtml(initials)}</span></div>
                    <div class="ee-person-info">
                        <div class="ee-person-name">${escHtml(linkedPerson.name)}</div>
                        <div class="ee-person-role">${roleLabel}</div>
                    </div>`;
                addBtn.parentNode.insertBefore(card, addBtn);
            });
        }
