        // ========== ACCORDION TOGGLE ==========
        // Profile tabs — sliding pill animation
        (function() {
            const tabsContainer = document.getElementById('profileTabs');
            const pill = document.getElementById('tabsPill');
            const tabs = tabsContainer ? tabsContainer.querySelectorAll('.profile-tab') : [];

            function movePill(tab) {
                if (!pill || !tab) return;
                pill.style.left = tab.offsetLeft + 'px';
                pill.style.width = tab.offsetWidth + 'px';
            }

            // Mark first/last VISIBLE tabs with .pa-tab-edge-first / .pa-tab-edge-last
            // so CSS can apply the 20px breathing margin only to the actual visible
            // edges. .profile-tab:first-child won't match (the pill div is :first-child)
            // and .profile-tab:last-child sometimes matches a display:none Memorial
            // Page when the record is not deceased. JS keeps these classes in sync.
            // Violetka 2026-05-18.
            function paUpdateTabEdges() {
                if (!tabsContainer) return;
                var visible = Array.from(tabsContainer.querySelectorAll('.profile-tab'))
                    .filter(function(t){ return getComputedStyle(t).display !== 'none'; });
                tabsContainer.querySelectorAll('.profile-tab').forEach(function(t){
                    t.classList.remove('pa-tab-edge-first');
                    t.classList.remove('pa-tab-edge-last');
                });
                if (visible.length > 0) {
                    visible[0].classList.add('pa-tab-edge-first');
                    visible[visible.length - 1].classList.add('pa-tab-edge-last');
                }
            }
            window.paUpdateTabEdges = paUpdateTabEdges;
            paUpdateTabEdges();

            // Initialize pill position (with delay fallback for hidden pages)
            setTimeout(() => {
                paUpdateTabEdges();
                const at = document.querySelector('.profile-tab.active');
                if (pill && at && at.offsetWidth > 0) {
                    pill.style.transition = 'none';
                    pill.style.left = at.offsetLeft + 'px';
                    pill.style.width = at.offsetWidth + 'px';
                    requestAnimationFrame(() => { pill.style.transition = 'left 0.3s ease-out, width 0.3s ease-out'; });
                }
            }, 300);
            // Initialize pill position
            if (tabs.length > 0) {
                const activeTab = tabsContainer.querySelector('.profile-tab.active');
                if (activeTab) {
                    // Set initial position without animation
                    pill.style.transition = 'none';
                    movePill(activeTab);
                    // Re-enable animation after initial position
                    requestAnimationFrame(() => {
                        requestAnimationFrame(() => {
                            pill.style.transition = 'left 0.3s ease-out, width 0.3s ease-out';
                        });
                    });
                }
            }
            
            tabs.forEach(tab => {
                tab.addEventListener('click', function(e) {
                    var tabName = this.getAttribute('data-tab');
                    var hasHref = this.tagName === 'A' && this.getAttribute('href') && this.getAttribute('href') !== '#';
                    // If the tab is an <a href="...html">, let the browser navigate to that page.
                    // The pill animation runs naturally on page load (movePill is called above
                    // for the active tab on init), so cross-page tabs feel consistent.
                    if (hasHref) return;
                    // Otherwise (e.g. data-tab without href, or href="#"), do in-page switch.
                    var target = document.querySelector('[data-tab-content="' + tabName + '"]');
                    if (target) {
                        e.preventDefault();
                        var self = this;
                        tabs.forEach(t => t.classList.remove('active'));
                        self.classList.add('active');
                        // Defer the offsetWidth read to the next paint so the
                        // browser has re-rendered the active tab at its FINAL
                        // bold-weight + 30px-padding width. Reading synchronously
                        // sometimes returns the previous-weight width and the
                        // pill ends up 1-2px narrow (Violetka 2026-05-18:
                        // "тряба да кликна 2 пути за да стане пила в правилни
                        // размер" — fixed by double rAF so first click is correct).
                        requestAnimationFrame(function(){
                            requestAnimationFrame(function(){ movePill(self); });
                        });
                        document.querySelectorAll('.profile-tab-content').forEach(function(c) {
                            c.style.display = 'none';
                            c.classList.remove('active');
                        });
                        var dn = (tabName === 'overview') ? 'contents' : 'block';
                        target.style.display = dn;
                        target.classList.add('active');

                        // Life Story tab → render this person's filtered event
                        // stream (same Timeline events, scoped to people who
                        // include this record). Edits here sync back to the
                        // Family Timeline because both use the same source
                        // (peopleStore + relationship.dates + Timeline custom
                        // events).
                        if (tabName === 'life-story') {
                            var personId = window.__paViewedPersonRealId || 'sj';
                            var streamRoot = document.getElementById('lifeStoryStream');
                            if (streamRoot && window.paRenderLifeStory) {
                                window.paRenderLifeStory(personId, streamRoot);
                            }
                        }
                    }
                });
            });
        })();

        // ── ACCORDION — mutual exclusion with unsaved guard ──────────
        function accordionHasUnsaved(section) {
            // EI card in edit mode
            if (section.classList.contains('essential-info-card') && section.classList.contains('editing')) {
                return eiHasChanges();
            }
            // CI section in edit mode
            var ciSec = section.querySelector('.ci-section.ci-editing');
            if (ciSec) return ciHasChanges(ciSec.id);
            return false;
        }

        function accordionForceClose(section) {
            section.classList.remove('editing'); // EI edit mode
            if (section.id === 'essentialInfoCard') releaseEditMode('essential-info');
            section.querySelectorAll('.ci-section.ci-editing').forEach(function(s) {
                s.classList.remove('ci-editing');
            });
            section.classList.remove('open');
        }

        function accordionSaveAndClose(section) {
            if (section.classList.contains('essential-info-card') && section.classList.contains('editing')) {
                saveEssentialInfo();
            }
            var ciSec = section.querySelector('.ci-section.ci-editing');
            if (ciSec) {
                var saveFns = { 'ci-emails': saveCiEmails, 'ci-phones': saveCiPhones, 'ci-addresses': saveCiAddresses, 'ci-social': saveCiSocial };
                var fn = saveFns[ciSec.id];
                if (fn) fn();
            }
            section.classList.remove('open');
        }

        function accordionSaveAndSwitch(fromSection, toSection) {
            if (fromSection.classList.contains('essential-info-card') && fromSection.classList.contains('editing')) {
                saveEssentialInfo();
            }
            var ciSec = fromSection.querySelector('.ci-section.ci-editing');
            if (ciSec) {
                var saveFns = { 'ci-emails': saveCiEmails, 'ci-phones': saveCiPhones, 'ci-addresses': saveCiAddresses, 'ci-social': saveCiSocial };
                var fn = saveFns[ciSec.id];
                if (fn) fn();
            }
            fromSection.classList.remove('open');
            toSection.classList.add('open');
        }

        function getAccordionTitle(section) {
            var t = section.querySelector('.accordion-title');
            return t ? t.textContent.trim() : 'this section';
        }

        function toggleAccordion(header) {
            var section = header.parentElement;
            var wasOpen = section.classList.contains('open');
            var title = getAccordionTitle(section);

            // Find currently open sibling card
            var container = section.parentElement;
            var openOther = null;
            container.querySelectorAll('.accordion-section.open').forEach(function(s) {
                if (s !== section) openOther = s;
            });

            if (wasOpen) {
                // ── Closing current card ──
                if (accordionHasUnsaved(section)) {
                    showSystemPopup({
                        title: 'Unsaved Changes',
                        body: 'You have unsaved changes in "' + title + '". Save before closing?',
                        actionLabel: 'Save',
                        discardLabel: "Don't Save",
                        onAction: function() { accordionSaveAndClose(section); },
                        onDiscard: function() { accordionForceClose(section); }
                    });
                } else {
                    // No edit mode or no changes — close silently
                    accordionForceClose(section);
                }
                return;
            }

            // ── Opening a new card ──
            // RULE: every card opens in View Mode. Edit Mode is only entered
            // explicitly via the Edit button inside the card.
            // See DESIGN_SYSTEM_LIVE.md → "Record Card State Rule".
            if (openOther && accordionHasUnsaved(openOther)) {
                var otherTitle = getAccordionTitle(openOther);
                showSystemPopup({
                    title: 'Unsaved Changes',
                    body: 'You have unsaved changes in "' + otherTitle + '". Save before switching to "' + title + '"?',
                    actionLabel: 'Save',
                    discardLabel: "Don't Save",
                    onAction: function() { accordionSaveAndSwitch(openOther, section); ensureViewModeOnOpen(section); },
                    onDiscard: function() {
                        accordionForceClose(openOther);
                        section.classList.add('open');
                        ensureViewModeOnOpen(section);
                    }
                });
            } else {
                if (openOther) { accordionForceClose(openOther); }
                section.classList.add('open');
                ensureViewModeOnOpen(section);
            }
        }

        // Guarantees the card that just opened is in View Mode.
        // Strips any stale .editing / .ci-editing and releases the edit guard.
        function ensureViewModeOnOpen(section) {
            if (!section) return;
            if (section.classList.contains('editing')) {
                section.classList.remove('editing');
            }
            section.querySelectorAll('.ci-section.ci-editing').forEach(function(s) {
                s.classList.remove('ci-editing');
            });
            if (section.id === 'essentialInfoCard') releaseEditMode('essential-info');
        }

