        // ========== AI RESIZE (both dashboard & col4) ==========
        (function() {
            /* Drag a .ai-resize handle to stretch the parent .ai-card or
               .ai-card-col4 vertically. Image (.ai-image-bg, inset:0) grows
               with the card; video (.ai-video, top:50% translateY(-50%))
               stays centered. Chat (.ai-chat, flex:1) absorbs the new space.
               Per Violetka 2026-05-24: "prozorea da mobe da si se dyrpa
               nadolu… vidoeto da se pozicionira w sredata". */
            let isDragging = false, startY, startH, targetCard;
            function getResizeTarget(e) {
                const el = e.target.closest('.ai-resize');
                if (!el) return null;
                return el.closest('.ai-card-col4') || el.closest('.ai-card');
            }
            function applyResize(card, dy) {
                const isCol4 = card.classList.contains('ai-card-col4');
                const max = isCol4 ? window.innerHeight * 0.85 : window.innerHeight * 0.9;
                const min = isCol4 ? 400 : 400;   // never shrink below XD baseline
                const newH = Math.max(min, Math.min(max, startH + dy));
                card.style.height = newH + 'px';
                card.style.maxHeight = newH + 'px';
                card.style.minHeight = newH + 'px';
                // Remember the user's manual pick so paAiAutoGrowCard()
                // (input-driven auto-expand) doesn't shrink it back when
                // they clear the input.
                card.dataset.userMinHeight = String(newH);
                // Let chat absorb new space (override any preset max-height).
                const chat = card.querySelector('.ai-chat');
                if (chat) chat.style.maxHeight = 'none';
            }
            document.addEventListener('mousedown', (e) => {
                targetCard = getResizeTarget(e);
                if (!targetCard) return;
                isDragging = true; startY = e.clientY; startH = targetCard.offsetHeight;
                targetCard.classList.add('ai-resizing');
                document.body.style.cursor = 'ns-resize'; document.body.style.userSelect = 'none';
                e.preventDefault();
            });
            document.addEventListener('mousemove', (e) => {
                if (!isDragging || !targetCard) return;
                applyResize(targetCard, e.clientY - startY);
            });
            document.addEventListener('mouseup', () => {
                if (!isDragging) return;
                if (targetCard) targetCard.classList.remove('ai-resizing');
                isDragging = false; targetCard = null;
                document.body.style.cursor = ''; document.body.style.userSelect = '';
            });
            document.addEventListener('touchstart', (e) => {
                targetCard = getResizeTarget(e);
                if (!targetCard) return;
                isDragging = true; startY = e.touches[0].clientY; startH = targetCard.offsetHeight;
                targetCard.classList.add('ai-resizing');
                e.preventDefault();
            }, { passive: false });
            document.addEventListener('touchmove', (e) => {
                if (!isDragging || !targetCard) return;
                applyResize(targetCard, e.touches[0].clientY - startY);
            }, { passive: false });
            document.addEventListener('touchend', () => {
                if (targetCard) targetCard.classList.remove('ai-resizing');
                isDragging = false; targetCard = null;
            });
        })();

        // Close sidebar on window resize to desktop
        window.addEventListener('resize', () => {
            if (window.innerWidth >= 1280) {
                closeSidebar();
            }
        });

        /* Mobile AI card resize is now handled by the universal IIFE above
           via document-level event delegation (mousedown + touchstart) —
           the old per-handle attachment was redundant and caused double-
           resize on touch. Removed 2026-05-25. */

        function filterAlbum(el, cat) {
            el.parentElement.querySelectorAll('.ei-radio-item').forEach(function(r) { r.classList.remove('selected'); });
            el.classList.add('selected');
        }

        function paBtnTouch(el, on) {
            if (on) {
                el.classList.add('active');
            } else {
                setTimeout(() => el.classList.remove('active'), 250);
            }
        }
        function getPlanColor() {
            var strip = document.getElementById('planStripProfile');
            if (!strip) return '#61C553';
            if (strip.classList.contains('plan-individual')) return '#61C553';
            if (strip.classList.contains('plan-family')) return '#FF9500';
            if (strip.classList.contains('plan-premium')) return '#FF2C55';
            return '#61C553';
        }
        function activatePlanBtn(on) {
            var btn = document.getElementById('planStripBtn');
            var label = document.getElementById('planAction');
            var dash = document.getElementById('planDash');
            var arrow = document.getElementById('planArrow');
            if (!btn || !label || !dash || !arrow) return;
            var color = getPlanColor();
            if (on) {
                btn.style.setProperty('--pill-w', '138px');
                btn.style.setProperty('--pill-bg', '#FFFFFF');
                label.style.color = color;
                dash.style.background = color;
                dash.style.width = '20px';
                arrow.style.color = color;
            } else {
                btn.style.removeProperty('--pill-w');
                btn.style.removeProperty('--pill-bg');
                label.style.color = '';
                dash.style.background = '';
                dash.style.width = '';
                arrow.style.color = '';
            }
        }
        function cyclePlan() {
            var strip = document.getElementById('planStripProfile');
            if (!strip) return;
            // Remove active state after click
            var right = strip.querySelector('.plan-strip-right');
            if (right) { right.classList.remove('touching'); }
            var left = strip.querySelector('.plan-strip-left');
            var action = document.getElementById('planAction');
            if (strip.classList.contains('plan-individual')) {
                strip.classList.remove('plan-individual');
                strip.classList.add('plan-family');
                left.innerHTML = '<strong>Family Plan</strong><small>Sharing and family features enabled</small>';
                action.textContent = 'Upgrade';
            } else if (strip.classList.contains('plan-family')) {
                strip.classList.remove('plan-family');
                strip.classList.add('plan-premium');
                left.innerHTML = '<strong>Premium Plan</strong><small>More space and more features</small>';
                action.textContent = 'Manage';
            } else {
                strip.classList.remove('plan-premium');
                strip.classList.add('plan-individual');
                left.innerHTML = '<strong>Individual Plan</strong><small>Limited features active</small>';
                action.textContent = 'Upgrade';
            }
        }


    // ═══════════════════════════════════════════
    // ENTRY FORMS — open / close / category switch
    // ═══════════════════════════════════════════
    const FORM_MAP = {
        essential:  { btn: 'esAddBtn',     form: 'esEntryForm' },
        medical:    { btn: 'medAddBtn',    form: 'medEntryForm' },
        education:  { btn: 'eduAddBtn',    form: 'educationEntryForm' },
        employment: { btn: 'empAddBtn',    form: 'employmentEntryForm' },
        beliefs:    { btn: 'belAddBtn',    form: 'beliefsEntryForm' },
    };

    function openEntryForm(card) {
        const m = FORM_MAP[card];
        if (!m) return;
        const btn  = document.getElementById(m.btn);
        const form = document.getElementById(m.form);
        if (!form) return;
        // Close all open forms first
        document.querySelectorAll('.entry-form-wrap.open').forEach(f => f.classList.remove('open'));
        document.querySelectorAll('.add-entry-btn.hidden').forEach(b => b.classList.remove('hidden'));
        form.classList.add('open');
        if (btn) btn.classList.add('hidden');
        setTimeout(() => form.scrollIntoView({ behavior: 'smooth', block: 'nearest' }), 50);
    }

    function closeEntryForm(card) {
        const m = FORM_MAP[card];
        if (!m) return;
        const btn  = document.getElementById(m.btn);
        const form = document.getElementById(m.form);
        if (form) form.classList.remove('open');
        if (btn)  btn.classList.remove('hidden');
    }

    function saveEntryForm(el) {
        // Find which form this is in
        const form = el.closest('.entry-form-wrap');
        if (!form) return;
        form.classList.remove('open');
        // Re-show add btn
        const card = form.closest('.accordion-inner');
        if (card) {
            const addBtn = card.querySelector('.add-entry-btn');
            if (addBtn) addBtn.classList.remove('hidden');
        }
        showToast('Entry saved successfully!');
    }

