    function lscEditPopulateRoleLayer1(form, dir) {
        if (!form) return;
        const list = form.querySelector('.lsc-edit-rolelayer1-suggestions');
        if (!list) return;
        const opts = dir === 'family' ? LSC_EDIT_ROLES_FAMILY : LSC_EDIT_ROLES_NETWORK_EDU;
        list.innerHTML = opts.map(r =>
            `<div class="ee-contact-option" onclick="lscEditPickRoleLayer1(this,${JSON.stringify(r).replace(/"/g,'&quot;')})"><span class="ee-contact-option-name">${escHtml(r)}</span></div>`
        ).join('');
    }
    function lscEditPopulateRoleLayer2(form, layer1) {
        if (!form) return;
        const host = form.querySelector('.lsc-edit-rolelayer2-host');
        const picker = form.querySelector('.lsc-edit-rolelayer2-picker');
        const list = form.querySelector('.lsc-edit-rolelayer2-suggestions');
        const textRow = form.querySelector('.lsc-edit-rolelayer2-text');
        if (!host || !picker || !list || !textRow) return;
        const dir = (form.querySelector('.lsc-edit-dir-btn.active')?.getAttribute('data-dir')) || 'network';
        // Reset any prior picker value when Layer 1 changes. PET FORM uses
        // "Select Species" instead of "Select Specific Role" (Violetka 2026-05-15:
        // "Specific Role лейбъла за пет форма е друго нещо — Species").
        const isPetForm = form.classList.contains('pet-form');
        const placeholderLabel = isPetForm ? 'Select Species' : 'Select Specific Role';
        const pickerValueEl = picker.querySelector('.ee-contact-picker-value');
        if (pickerValueEl) {
            pickerValueEl.textContent = placeholderLabel;
            pickerValueEl.classList.remove('has-value');
        }
        picker.classList.remove('has-value');
        // Reset free-text input value when Layer 1 changes
        const textInput = textRow.querySelector('.lsc-edit-rolelayer2-input');
        if (textInput) textInput.value = '';
        // Hide the row entirely if Layer 1 not yet picked
        if (!layer1) { host.style.display = 'none'; return; }
        host.style.display = '';
        // Family branch: dropdown picker with predefined sub-options
        if (dir === 'family') {
            const opts = LSC_EDIT_LAYER2_FAMILY[layer1] || [];
            // Use lscEditPickRoleLayer2 wrapper so we can trigger date-fields
            // rendering after the option is picked (selectContact alone only
            // sets the value text but doesn't know about relationship dates).
            list.innerHTML = opts.map(r =>
                `<div class="ee-contact-option" onclick="lscEditPickRoleLayer2(this,${JSON.stringify(r).replace(/"/g,'&quot;')})"><span class="ee-contact-option-name">${escHtml(r)}</span></div>`
            ).join('');
            picker.style.display = opts.length ? '' : 'none';
            textRow.style.display = 'none';
            // Clear any prior dates row (Layer 2 reset)
            lscEditRenderRelationshipDates(form, '');
        } else {
            // Network branch: free-text input (per spec — user types in)
            picker.style.display = 'none';
            textRow.style.display = '';
            // No date fields for Network
            lscEditRenderRelationshipDates(form, '');
        }
    }
    // Layer 2 selection wrapper: sets the picker value via selectContact +
