// Family members ... menu
let fmlOpenMenuId = null;
function fmlOpenMenu(id, e) {
    e.stopPropagation();
    // close existing
    if (fmlOpenMenuId) {
        const old = document.getElementById('fml-menu-' + fmlOpenMenuId);
        if (old) old.remove();
    }
    if (fmlOpenMenuId === id) { fmlOpenMenuId = null; return; }
    fmlOpenMenuId = id;
    const menu = document.createElement('div');
    menu.id = 'fml-menu-' + id;
    menu.style.cssText = 'position:absolute;right:48px;top:10px;background:#fff;border-radius:16px;box-shadow:0 8px 30px rgba(0,0,0,0.18);padding:8px 0;z-index:999;min-width:180px;';
    const items = [
        { label: 'Open Record', icon: '👤' },
        { label: 'Update Relationship', icon: '🔗' },
        { label: 'Add Family', icon: '➕' },
        { label: 'Update Life Status', icon: '📋' },
    ];
    items.forEach(item => {
        const el = document.createElement('div');
        el.style.cssText = 'padding:10px 18px;font:400 14px/17px Inter,sans-serif;cursor:pointer;display:flex;align-items:center;gap:10px;color:#000;';
        el.onmouseenter = () => el.style.background = 'rgba(0,0,0,0.04)';
        el.onmouseleave = () => el.style.background = '';
        el.textContent = item.icon + ' ' + item.label;
        el.onclick = (ev) => { ev.stopPropagation(); menu.remove(); fmlOpenMenuId = null; };
        menu.appendChild(el);
    });
    // Append to fml-card parent
    const btn = e.currentTarget;
    const card = btn.closest('.fml-card');
    if (card) { card.style.position = 'relative'; card.appendChild(menu); }
    // Close on outside click
    setTimeout(() => {
        document.addEventListener('click', function _close() {
            menu.remove(); fmlOpenMenuId = null;
            document.removeEventListener('click', _close);
        }, { once: true });
    }, 0);
}

