/* ── Auto-grow textareas ──────────────────────────────────────────────
   Textareas with class .ei-autogrow grow their height to fit content.
   Critical: when the containing panel is hidden (display:none), scrollHeight
   returns 0 — do NOT set height in that case or textarea becomes invisible
   and unwritable. When the edit panel opens we call eiInitAutogrow again,
   which re-runs the sizing (bypassing the bound-guard).                 */
function eiAutogrow(ta) {
    if (!ta) return;
    // Only resize when visible; offsetParent is null for display:none ancestors.
    if (!ta.offsetParent && ta !== document.activeElement) return;
    var prev = ta.style.height;
    ta.style.height = 'auto';
    var h = ta.scrollHeight;
    if (h > 0) {
        ta.style.height = h + 'px';
    } else {
        ta.style.height = prev || '';
    }
}
function eiInitAutogrow(root) {
    var scope = root || document;
    scope.querySelectorAll('textarea.ei-autogrow').forEach(function(ta) {
        if (!ta.dataset.autogrowBound) {
            ta.dataset.autogrowBound = '1';
            ta.addEventListener('input', function(){ eiAutogrow(ta); });
            ta.addEventListener('focus', function(){ eiAutogrow(ta); });
        }
        // Always try to resize (will no-op if still hidden).
        eiAutogrow(ta);
    });
}
document.addEventListener('DOMContentLoaded', function(){ eiInitAutogrow(); });
// Re-run when edit panel opens (textareas may be hidden at load)
window.eiInitAutogrow = eiInitAutogrow;

document.addEventListener('DOMContentLoaded', function() {
    // Default-open the Me, Family & Network group ONLY on records that
    // belong to it (profile / record-*). Other top-level pages (vault,
    // tasks, marketplace, settings, family-tree, etc.) already mark their
    // own nav-item active in their HTML \u2014 don't override that here.
    var alreadyActive = document.querySelector('.nav-item.active');
    var path = location.pathname.replace(/\.html$/, '').replace(/^\//, '');
    var isMeRecord = /^(profile|family|network)$/.test(path) || /^record-/.test(path);
    if (!alreadyActive && isMeRecord) {
        var meBtn = document.querySelector('[onclick*="me-sub"]');
        if (meBtn) {
            meBtn.classList.add('active');
            var sub = document.getElementById('me-sub');
            if (sub) {
                sub.classList.add('open');
                sub.style.maxHeight = 'none'; // sync visible state with class
            }
        }
    }
    // Right panel: show progress on dashboard, AI card on inner pages
    // Robust detection — works with or without .html extension, with or without trailing /
    function _paFixRightPanel() {
        var progressSection = document.querySelector('#rightPanel > div:first-child');
        var aiCol4 = document.getElementById('aiCardCol4');
        var pathClean = location.pathname.replace(/\.html$/, '').replace(/\/$/, '');
        var isDashboard = pathClean === '' || pathClean === '/index' || document.title.indexOf('Dashboard') === 0;
        if (progressSection) progressSection.style.display = isDashboard ? 'flex' : 'none';
        if (aiCol4) aiCol4.style.display = isDashboard ? 'none' : 'flex';
    }
    _paFixRightPanel();
    // Defensive — re-apply after any later handlers that may override
    setTimeout(_paFixRightPanel, 100);
    setTimeout(_paFixRightPanel, 500);
    // Set tab pill
    requestAnimationFrame(function() {
        var tabsPill = document.getElementById('tabsPill');
        var activeTab = document.querySelector('.profile-tab.active');
        if (tabsPill && activeTab) {
            tabsPill.style.transition = 'none';
            tabsPill.style.left = activeTab.offsetLeft + 'px';
            tabsPill.style.width = activeTab.offsetWidth + 'px';
            requestAnimationFrame(function() {
                tabsPill.style.transition = 'left 0.3s ease-out, width 0.3s ease-out';
            });
        }
    });

    /* ── Document Preview: sidebar expand / collapse ── */
    var docSidebar = document.getElementById('docSidebar');
    if (docSidebar) {
        docSidebar.addEventListener('click', function() {
            docSidebar.classList.toggle('expanded');
        });
    }
});

