// Select a blood type from the dropdown — updates the entry below (creates one
// if it doesn't yet exist, e.g. after user deleted the previous Blood Type
// record) and closes the dropdown. The EMC pill above rebuilds via syncEmcBlood
// so its visual state (normal vs .is-empty placeholder) stays in sync with the
// actual data-group entry. Display rule: "Unknown/Not sure" → "Unknown" on the
// pill only (kept full inside the entry / edit pad).
function emcSetBlood(el, value) {
    const pad = document.getElementById('emcBloodEditPad');
    const valueEl = pad?.querySelector('.emc-edit-pad-value');
    const input = pad?.querySelector('.emc-edit-pad-input');
    if (valueEl) valueEl.textContent = value;     // full text in edit dropdown
    if (input) input.classList.remove('open');
    // Find the existing Blood Type entry (if any). Accept both singular &
    // legacy plural title defensively.
    const titles = [...document.querySelectorAll('.data-group-title')];
    const bloodTitle = titles.find(t => {
        const txt = t.textContent.trim();
        return txt === 'Blood Type' || txt === 'Blood Types';
    });
    if (!bloodTitle) return;
    let existingRow = null;
    let cur = bloodTitle.nextElementSibling;
    while (cur && !cur.classList.contains('data-group-title')) {
        if (cur.classList.contains('entry-row')) { existingRow = cur; break; }
        cur = cur.nextElementSibling;
    }
    const display = value === 'Unknown/Not sure' ? 'Unknown' : value;
    if (existingRow) {
        // Update in place — title + data-entry JSON + expand body value
        const titleEl = existingRow.querySelector('.entry-title');
        if (titleEl) titleEl.textContent = display;
        try {
            const data = JSON.parse(existingRow.getAttribute('data-entry') || '{}');
            data.category = data.category || 'Blood Type';
            data.fields   = data.fields   || [];
            const f = data.fields.find(x => x.label === 'Blood Type');
            if (f) f.value = value;
            else data.fields.unshift({ label: 'Blood Type', value: value, required: true });
            existingRow.setAttribute('data-entry', JSON.stringify(data));
            // Re-render the expand body so view/edit modes pick up the new value
            const body = existingRow.nextElementSibling;
            if (body && body.classList.contains('entry-expand-body')) {
                body.removeAttribute('data-built');
                body.innerHTML = '';
                if (typeof window.buildAllMedicalEntries === 'function') window.buildAllMedicalEntries();
            }
        } catch {}
    } else {
        // No entry existed (user had deleted it previously) — create one now.
        if (typeof window.addMedicalEntry === 'function') {
            window.addMedicalEntry({
                groupTitle: 'Blood Type',
                icon: 'img/drop.svg',
                title: display,
                type: 'Blood Type',
                sub: 'Added today',
                badge: '',
                badgeText: '',
                entryData: {
                    category: 'Blood Type',
                    fields: [{ label: 'Blood Type', value: value, required: true }]
                }
            });
        }
    }
    // Final step — rebuild the EMC pill + snapshot so visual state matches data
    if (typeof window.syncEmcSnapshot === 'function') window.syncEmcSnapshot();
    if (typeof window.updateEmergencyPreparednessScore === 'function') window.updateEmergencyPreparednessScore();
}

// Generic toggle for emc-edit-pad dropdowns — closes any sibling dropdown
