// Add Medical Condition toggle — tap "Add Medical Condition" pill to open form.
function emcConditionAdd(trigger, open) {
    const btn = [...document.querySelectorAll('.emc-add-btn')].find(b => {
        const t = b.querySelector('.emc-add-btn-text');
        return t && t.textContent.trim() === 'Add Medical Condition';
    });
    const pad = document.getElementById('emcConditionAddPad');
    if (!btn || !pad) return;
    if (open) {
        btn.style.display = 'none';
        pad.classList.add('open');
    } else {
        // Full reset — so the NEXT open starts in pristine State 1 (159px, dropdown
        // only). Without this, residual inline height from emcConditionRelayout
        // (set when the user added 2–3 med pads) lingered and re-opened the pad
        // as a huge empty box. Additional cloned med pads are removed; primary
        // med pad values + dosage + Other-custom text are cleared.
        btn.style.display = '';
        pad.classList.remove('open');
        pad.classList.remove('has-condition');
        pad.classList.remove('has-other-condition');
        pad.style.height = '';                           // clear inline height from relayout
        pad.querySelectorAll('.emc-meds-pad.is-additional').forEach(p => p.remove()); // drop clones
        pad.querySelectorAll('.emc-meds-pad').forEach(p => { p.style.top = ''; });   // reset top on primary
        const addBtnMed = pad.querySelector('.emc-add-med-btn');
        if (addBtnMed) addBtnMed.style.top = '';
        pad.querySelectorAll('.emc-edit-pad-input.open').forEach(i => i.classList.remove('open'));
        pad.querySelectorAll('.emc-edit-pad-value').forEach(v => v.textContent = '');
        pad.querySelectorAll('.emc-edit-pad-text').forEach(t => { if (t.tagName === 'INPUT') t.value = ''; });
        const otherInput = document.getElementById('emcConditionOtherInput');
        if (otherInput) otherInput.value = '';
    }
}

// Select a Condition — closes dropdown, sets value, and progressively reveals
// the Medications section + Save button (.has-condition modifier on pad).
// Context-aware dropdown content per Condition (matches prototype's CONDITION_MAP
// + Supplements/Preventive list). When user picks a condition, medication options,
// intake options, and dosage placeholder all adapt to be clinically relevant.
const MED_PROFILE_BY_CONDITION = {
    'Hypertension':     { meds: ['Lisinopril','Amlodipine','Losartan','Hydrochlorothiazide','Other'],
                          intakes: ['Once daily','Twice daily','Before bed','As Needed (PRN)','Other'],
                          dosagePlaceholder: 'e.g., 10 mg, 1 tablet' },
    'Diabetes Type 1':  { meds: ['Insulin Glargine','Insulin Lispro','Humalog','Novolog','Other'],
                          intakes: ['Before meals','Once daily','Twice daily','As Needed (PRN)','Other'],
                          dosagePlaceholder: 'e.g., 10 units, 1 injection' },
    'Diabetes Type 2':  { meds: ['Metformin','Jardiance','Glimepiride','Ozempic','Other'],
                          intakes: ['Once daily','Twice daily','With meals','As Needed (PRN)','Other'],
                          dosagePlaceholder: 'e.g., 500 mg, 1 tablet' },
    'Asthma':           { meds: ['Albuterol','Salbutamol','Fluticasone','Symbicort','Other'],
                          intakes: ['As Needed (PRN)','Twice daily','Three times daily','Every 8 hours','Before bed','Other'],
                          dosagePlaceholder: 'e.g., 2 puffs, 1 inhaler' },
    'Epilepsy':         { meds: ['Levetiracetam','Lamotrigine','Valproate','Topiramate','Other'],
                          intakes: ['Twice daily','Three times daily','Every 8 hours','Before bed','Other'],
                          dosagePlaceholder: 'e.g., 500 mg, 1 tablet' },
    'Supplements / Preventive Medication':
                        { meds: ['Vitamin D3','Vitamin B12','Omega-3 / Fish Oil','Magnesium','Iron','Calcium','Multivitamin','Probiotic','Zinc','Vitamin C','CoQ10','Other'],
                          intakes: ['Once daily','Twice daily','With meals','Before bed','As Needed (PRN)','Other'],
                          dosagePlaceholder: 'e.g., 1000 IU, 1 capsule' },
    // Fallback for "Other" condition or any unmapped value — generic list
    '_default':         { meds: ['Other'],
                          intakes: ['Once daily','Twice daily','Three times daily','Every 8 hours','As Needed (PRN)','Before bed','Other'],
                          dosagePlaceholder: 'Set Dosage' }
};
function applyCondMedProfile(value) {
    const pad = document.getElementById('emcConditionAddPad');
    if (!pad) return;
    const profile = MED_PROFILE_BY_CONDITION[value] || MED_PROFILE_BY_CONDITION._default;
    // Repopulate EVERY medication row (first + any added via emcAddMedicationPad)
    const medPads = pad.querySelectorAll('.emc-meds-pad');
    medPads.forEach(medPad => {
        // Medication dropdown
        const medDropdown = medPad.querySelector('.emc-meds-field--m .emc-blood-dropdown');
        if (medDropdown) {
            medDropdown.innerHTML = profile.meds.map(m =>
                `<div class="emc-blood-opt" onclick="event.stopPropagation();emcSetMedication(this,${JSON.stringify(m).replace(/"/g,'&quot;')})">${m}</div>`
            ).join('');
        }
        // Intake dropdown
        const intakeDropdown = medPad.querySelector('.emc-meds-field--i .emc-blood-dropdown');
        if (intakeDropdown) {
            intakeDropdown.innerHTML = profile.intakes.map(o =>
                `<div class="emc-blood-opt" onclick="event.stopPropagation();emcSetIntake(this,${JSON.stringify(o).replace(/"/g,'&quot;')})">${o}</div>`
            ).join('');
        }
        // Dosage placeholder (context-specific example)
        const dosageInput = medPad.querySelector('.emc-meds-field--d input');
        if (dosageInput) dosageInput.placeholder = profile.dosagePlaceholder;
    });
}
function emcSetCondition(el, value) {
    const input = el.closest('.emc-edit-pad-input');
    const valueEl = input && input.querySelector('.emc-edit-pad-value');
    const pad = document.getElementById('emcConditionAddPad');
    if (valueEl) valueEl.textContent = value;
    if (input) input.classList.remove('open');
    if (pad) {
        pad.classList.add('has-condition');
        // Toggle "Other → Custom Condition" text field (XD: shown when Condition = Other)
        pad.classList.toggle('has-other-condition', value === 'Other');
        if (value === 'Other') {
            // Auto-focus the custom text input so user can type immediately
            const input = document.getElementById('emcConditionOtherInput');
            if (input) setTimeout(() => input.focus(), 0);
        }
        // Repopulate medication/intake/dosage options to be clinically relevant
        applyCondMedProfile(value);
    }
}

