// Clone the primary medication inner pad and insert it after the last medication pad.
// Each clone is tagged .is-additional so its X close button appears. The outer pad,
// "Add Medication" button, and Save button shift downward to accommodate.
// Inner pad 317 tall + 20 gap = 337 per added pad.
function emcAddMedicationPad() {
    const pad = document.getElementById('emcConditionAddPad');
    if (!pad) return;
    const pads = pad.querySelectorAll('.emc-meds-pad');
    const primary = pads[0];
    if (!primary) return;
    const last = pads[pads.length - 1];
    const clone = primary.cloneNode(true);
    clone.classList.add('is-additional');
    // Clear all selected values + close any open dropdowns + clear dosage input
    clone.querySelectorAll('.emc-edit-pad-value').forEach(v => v.textContent = '');
    clone.querySelectorAll('.emc-edit-pad-input.open').forEach(i => i.classList.remove('open'));
    const dosage = clone.querySelector('.emc-edit-pad-text');
    if (dosage) dosage.value = '';
    // Position clone 337px below the last medication pad (317 pad + 20 gap)
    const lastTop = parseInt(last.style.top || getComputedStyle(last).top, 10) || 194;
    clone.style.top = (lastTop + 337) + 'px';
    primary.parentNode.insertBefore(clone, last.nextSibling);
    emcConditionRelayout();
}

// Remove an additional medication pad and reflow positions
function emcRemoveMedicationPad(closeEl) {
    const padEl = closeEl.closest('.emc-meds-pad');
    if (!padEl || !padEl.classList.contains('is-additional')) return;
    padEl.remove();
    emcConditionRelayout();
}

// Reposition Add Medication button, Save button, and outer pad height based on medication count
function emcConditionRelayout() {
    const pad = document.getElementById('emcConditionAddPad');
    if (!pad) return;
    const medsPads = pad.querySelectorAll('.emc-meds-pad');
    const count = medsPads.length;
    // Re-stack pads so tops are 194, 531, 868, ...
    medsPads.forEach((p, idx) => { p.style.top = (194 + idx * 337) + 'px'; });
    // Add Medication button sits 20px below the last medication pad bottom
    // last pad bottom = 194 + count*337 - 20 = 174 + count*337; +20 gap → top = 194 + count*337
    const addBtn = pad.querySelector('.emc-add-med-btn');
    const addBtnTop = 194 + count * 337;
    if (addBtn) addBtn.style.top = addBtnTop + 'px';
    // Outer pad height = addBtnTop + 60 (button) + 20 gap + 60 (save) + 20 bottom
    pad.style.height = (addBtnTop + 160) + 'px';
}

// Save a new Medical Condition from the EMC quick-add pad. Collects:
//   1) Condition name (top field, "Other → Custom Condition" override)
//   2) Every embedded Medications sub-pad (name + intake + dosage), each of
//      which becomes a LINKED child entry in the Medications & Supplements
//      data-group (single source of truth for the EMC med-list).
// Result: condition pill appears in the "Medical Conditions" pill-row above;
// every medication that has at least a name is auto-created as an entry in the
// "Medications & Supplements" data-group below, with linkedFrom=conditionId so
// deleting the parent condition cascades to its medications.
function emcConditionSave() {
    const pad = document.getElementById('emcConditionAddPad');
    if (!pad) return;
    // (1) Condition name
    let value = pad.querySelector('.emc-edit-pad-field--1 .emc-edit-pad-value').textContent.trim();
    if (pad.classList.contains('has-other-condition')) {
        const custom = document.getElementById('emcConditionOtherInput');
        const customValue = custom ? custom.value.trim() : '';
        if (!customValue) return;  // required — block save
        value = customValue;
    }
    if (!value) return;
    // (2) Collect every embedded Medications sub-pad (primary + additional clones).
    // A med pad has three fields: m (Medication), i (Intake), d (Dosage text input).
    // A med is considered "present" if it has at least a name. Intake/dosage are
    // optional at quick-add time — user can fill them later in Edit mode.
    const medPads = pad.querySelectorAll('.emc-meds-pad');
    const meds = [];
    medPads.forEach(medPad => {
        const name   = medPad.querySelector('.emc-meds-field--m .emc-edit-pad-value')?.textContent.trim() || '';
        const intake = medPad.querySelector('.emc-meds-field--i .emc-edit-pad-value')?.textContent.trim() || '';
        const dosage = medPad.querySelector('.emc-meds-field--d input')?.value.trim() || '';
        if (name) meds.push({ name, intake, dosage });
    });
    // (3) Emergency Medical Card pill-row — append the condition pill (above).
    const labels = [...document.querySelectorAll('.emc-section-label')];
    const condLabel = labels.find(l => {
        const t = l.textContent.trim();
        return t === 'Medical Conditions' || t === 'Medical Conditions and Medications';
    });
    const pillRow = condLabel && condLabel.nextElementSibling;
    if (pillRow && pillRow.classList.contains('emc-pill-row')) {
        const pill = document.createElement('span');
        pill.className = 'emc-condition-pill';
        pill.textContent = value;
        pillRow.appendChild(pill);
    }
    // (4) Medical Conditions data-group — meds go INSIDE the condition entry as
    // a structured array (not as separate linked entries). See rule 2026-04-24
    // in saveAnefEntry. The EMC med-list aggregates this array + any standalone
    // Medications & Supplements entries via syncEmcConditions.
    const newRow = addMedicalEntry({
        groupTitle: 'Medical Conditions',
        icon: 'img/pill.png',
        title: value,
        type: 'Medical Conditions',
        sub: 'Added today',
        badge: '',
        badgeText: '',
        entryData: {
            category: 'Medical Condition',
            fields: [{ label: 'Condition', value: value, required: true }],
            ...(meds.length ? { meds } : {})
        }
    });
    emcConditionAdd(null, false);
    // Option B hand-off — auto-open the new entry in Edit mode so user can
    // add Location / File / Contacts / Notes without leaving the card.
    if (typeof window.expandEntryInEditMode === 'function') window.expandEntryInEditMode(newRow);
}

// ─────────────────────────────────────────────────────────────
// Medications & Supplements EMC quick-add — independent of conditions.
// Same pattern as Allergy: show/hide pad, dropdown→set value, Save creates
// both the EMC med-item and an entry-row in the Medications & Supplements
// data-group. Entry has NO linkedFrom (standalone). "Other" reveals a custom
// text input below (same pattern as Allergen Other).
// ─────────────────────────────────────────────────────────────
function emcMedicationAdd(trigger, open) {
    const btn = [...document.querySelectorAll('.emc-add-btn')].find(b => {
        const t = b.querySelector('.emc-add-btn-text');
        return t && t.textContent.trim() === 'Add Medications & Supplements';
    });
    const pad = document.getElementById('emcMedicationAddPad');
    if (!btn || !pad) return;
    if (open) {
        btn.style.display = 'none';
        pad.classList.add('open');
    } else {
        btn.style.display = '';
        pad.classList.remove('open');
        pad.classList.remove('has-other-med');
        pad.querySelectorAll('.emc-edit-pad-input.open').forEach(i => i.classList.remove('open'));
        pad.querySelectorAll('.emc-edit-pad-value').forEach(v => v.textContent = '');
        const other = document.getElementById('emcMedOtherInput');
        if (other) other.value = '';
        const dose = document.getElementById('emcMedDosageInput');
        if (dose) dose.value = '';
    }
}
// Select a standalone medication — sets value + toggles Other→Custom field
function emcSetStandaloneMed(el, value) {
    const input = el.closest('.emc-edit-pad-input');
    const valueEl = input && input.querySelector('.emc-edit-pad-value');
    const pad = document.getElementById('emcMedicationAddPad');
    if (valueEl) valueEl.textContent = value;
    if (input) input.classList.remove('open');
    if (pad) {
        pad.classList.toggle('has-other-med', value === 'Other');
        if (value === 'Other') {
            const other = document.getElementById('emcMedOtherInput');
            if (other) setTimeout(() => other.focus(), 0);
        }
    }
}
// Save a standalone Medications & Supplements entry
function emcMedicationSave() {
    const pad = document.getElementById('emcMedicationAddPad');
    if (!pad) return;
    let medValue    = pad.querySelector('.emc-edit-pad-field--1 .emc-edit-pad-value').textContent.trim();
    const intakeValue = pad.querySelector('.emc-edit-pad-field--2 .emc-edit-pad-value').textContent.trim();
    const dosageValue = (document.getElementById('emcMedDosageInput')?.value || '').trim();
    // Required: medication + intake; if Other → custom text is required instead of "Other"
    if (!medValue || !intakeValue) return;
    if (pad.classList.contains('has-other-med')) {
        const customValue = (document.getElementById('emcMedOtherInput')?.value || '').trim();
        if (!customValue) return;
        medValue = customValue;
    }
    // Build entry and add to the Medications & Supplements data-group. The
    // .emc-med-list will auto-rebuild via syncEmcSnapshot since addMedicalEntry
    // triggers it — so no manual DOM insertion is needed.
    const medFields = [
        { label: 'Medication Name', value: medValue, required: true },
        { label: 'Intake', value: intakeValue, required: true }
    ];
    if (dosageValue) medFields.push({ label: 'Dosage', value: dosageValue });
    const newRow = addMedicalEntry({
        groupTitle: 'Medications & Supplements',
        icon: (window.ANEF_CATEGORY_META && window.ANEF_CATEGORY_META['Medications & Supplements']?.icon) || 'img/pill.png',
        title: medValue,
        type: 'Medications & Supplements',
        sub: 'Added today',
        badge: '',
        badgeText: '',
        entryData: {
            category: 'Medications & Supplements',
            fields: medFields
            // NO linkedFrom — standalone medication (not tied to a condition)
        }
    });
    emcMedicationAdd(null, false);
    // Option B hand-off — auto-open the new entry in Edit mode
    if (typeof window.expandEntryInEditMode === 'function') window.expandEntryInEditMode(newRow);
}
window.emcMedicationAdd = emcMedicationAdd;
window.emcSetStandaloneMed = emcSetStandaloneMed;
window.emcMedicationSave = emcMedicationSave;

