// Save a new allergy from the Add Allergy form → create a new .emc-allergy-bar
// inserted above the + Add Allergy pill. Width reflects severity level.
function emcAllergySave() {
    const pad = document.getElementById('emcAllergyAddPad');
    if (!pad) return;
    const allergenValue = pad.querySelector('.emc-edit-pad-field--1 .emc-edit-pad-value').textContent.trim();
    const severityValue = pad.querySelector('.emc-edit-pad-field--2 .emc-edit-pad-value').textContent.trim();
    const isOther = pad.classList.contains('has-other');
    const customValue = isOther ? document.getElementById('emcAllergenOtherInput').value.trim() : '';
    // Validation: need allergen + severity; if Other then also need custom text
    if (!allergenValue || !severityValue) return;
    if (isOther && !customValue) return;
    const displayName = isOther ? customValue : allergenValue;
    // Width by severity (380 total) — Mild 190, Moderate 253, Severe 316, Life-Threatening 380
    const widthMap = { 'Mild': 190, 'Moderate': 253, 'Severe': 316, 'Life-Threatening': 380 };
    const width = widthMap[severityValue] || 190;
    // Build DOM matching existing .emc-allergy-bar markup
    const bar = document.createElement('div');
    bar.className = 'emc-allergy-bar';
    bar.setAttribute('onclick', 'event.stopPropagation();');
    bar.innerHTML = `<div class="emc-allergy-fill" style="width:${width}px;"><span class="emc-allergy-dot"></span><span class="emc-allergy-name">${displayName}</span><span class="emc-allergy-level">${severityValue}</span></div>`;
    // Insert above the + Add Allergy pill
    const addBtn = document.querySelector('.emc-add-btn');
    if (addBtn) addBtn.parentNode.insertBefore(bar, addBtn);
    // Also insert a full Entry Row Card in the Allergies data-group below —
    // returns the new row so Option B can expand it into Edit mode after close.
    const newRow = emcInsertAllergyEntryRow(displayName, severityValue);
    // Close & reset the form
    emcAllergyAdd(null, false);
    // Option B hand-off — auto-open the new entry in Edit mode
    if (typeof window.expandEntryInEditMode === 'function') window.expandEntryInEditMode(newRow);
}

// ─────────────────────────────────────────────────────────────
// Shared helper — append a new medical entry row + expand body at the end of its
// data-group, using the SAME locked template as static entries (data-entry JSON
// → buildEntryExpandBodyHTML via buildAllMedicalEntries). Ensures parity between
// user-added entries and pre-existing ones (Blood Type / Peanuts / Asthma / …).
// opts:
//   groupTitle   → e.g. "Allergies", "Medical Conditions", "Medical Devices & Implants"
//   icon         → img path for .entry-icon-glyph (e.g. "img/shield-allergy.png")
//   title        → collapsed-row .entry-title
//   type         → collapsed-row .entry-type (e.g. "Allergy · Severe")
//   sub          → collapsed-row .entry-sub  (e.g. "Added today")
//   badge        → "digital" | "location" | "both" — status badge class
//   badgeText    → "Digital File" | "Location" | "Digital File & Location"
//   entryData    → the data-entry JSON object (category, fields, etc.)
// ─────────────────────────────────────────────────────────────
function addMedicalEntry(opts) {
    const titles = [...document.querySelectorAll('.data-group-title')];
    const groupTitle = titles.find(t => t.textContent.trim() === opts.groupTitle);
    if (!groupTitle) return null;
    // Locate the LAST element that still belongs to this group
    //   (last entry-row + optional entry-expand-body, or the group-title itself
    //    if the group is currently empty).
    let cursor = groupTitle.nextElementSibling;
    let insertAfter = groupTitle;
    while (cursor && !cursor.classList.contains('data-group-title')) {
        if (cursor.classList.contains('entry-row') || cursor.classList.contains('entry-expand-body')) {
            insertAfter = cursor;
        }
        cursor = cursor.nextElementSibling;
    }
    // Build new entry-row with data-entry JSON attribute
    const row = document.createElement('div');
    row.className = 'entry-row';
    row.setAttribute('onclick', 'toggleEntryExpand(this)');
    row.setAttribute('data-entry', JSON.stringify(opts.entryData || {}));
    row.innerHTML = `
        <div class="entry-icon"><img class="entry-icon-glyph" src="${opts.icon}" alt=""></div>
        <div class="entry-info">
            <div class="entry-title">${opts.title}</div>
            <div class="entry-type">${opts.type}</div>
            <div class="entry-sub">${opts.sub || 'Added today'}</div>
        </div>
        ${opts.badgeText ? `<div class="data-right"><span class="data-badge ${opts.badge || 'digital'}">${opts.badgeText}</span></div>` : ''}
        <div class="entry-menu" onclick="event.stopPropagation()">
            <div class="entry-menu-dots" onclick="toggleEntryMenu(this)"><span></span><span></span><span></span></div>
            <div class="entry-menu-dropdown">
                <div class="entry-menu-item" onclick="handleEntryAction('edit',this)">
                    <span class="entry-menu-item-text">Edit</span>
                    <div class="entry-menu-item-circle"><svg class="icon-edit" viewBox="0 0 21.5 19.5" fill="none"><path d="M-898,710.879h0Zm-8.889-4.206L-893,693.532a2.428,2.428,0,0,1,1.667-.654,2.465,2.465,0,0,1,.9.17,2.348,2.348,0,0,1,.764.484,2.206,2.206,0,0,1,.511.723,2.12,2.12,0,0,1,.18.854,2.117,2.117,0,0,1-.18.854,2.219,2.219,0,0,1-.511.724l-13.888,13.141L-908,710.879Z" transform="translate(908.75 -692.129)" fill="none" stroke="#000" stroke-linecap="round" stroke-linejoin="round" stroke-width="1.5"/></svg></div>
                </div>
                <div class="entry-menu-item" onclick="handleEntryAction('archive',this)">
                    <span class="entry-menu-item-text">Archive</span>
                    <div class="entry-menu-item-circle"><svg class="icon-archive" viewBox="0 0 21.5 19.5" fill="none" xmlns="http://www.w3.org/2000/svg"><path d="M20.712,7.841l-.641,11.6a2.374,2.374,0,0,1-2.3,2.311H6.734a2.374,2.374,0,0,1-2.3-2.311l-.641-11.6m6.41,4.091h4.1M3.4,7.841H21.1A1.193,1.193,0,0,0,22.25,6.614V4.977A1.193,1.193,0,0,0,21.1,3.75H3.4A1.193,1.193,0,0,0,2.25,4.977V6.614A1.193,1.193,0,0,0,3.4,7.841Z" transform="translate(-1.5 -3)" fill="none" stroke="#000" stroke-linecap="round" stroke-linejoin="round" stroke-width="1.5"/></svg></div>
                </div>
                <div class="entry-menu-item" onclick="handleEntryAction('delete',this)">
                    <span class="entry-menu-item-text">Delete</span>
                    <div class="entry-menu-item-circle"><svg class="icon-trash" viewBox="0 0 19.722 21.5" fill="none"><path d="M15.739,9.173,15.362,18.4m-5.223,0L9.761,9.173M20.635,5.881c.373.053.744.11,1.115.17m-1.115-.169L19.47,20.119a2.4,2.4,0,0,1-2.448,2.13H8.478a2.4,2.4,0,0,1-2.448-2.13L4.865,5.881m15.77,0q-1.889-.268-3.794-.407M3.75,6.05c.371-.061.742-.117,1.115-.169m0,0q1.889-.268,3.794-.407m8.182,0V4.534a2.3,2.3,0,0,0-2.28-2.257q-1.81-.054-3.622,0a2.3,2.3,0,0,0-2.28,2.257v.939m8.182,0a56.462,56.462,0,0,0-8.182,0" transform="translate(-2.889 -1.499)" fill="none" stroke="#000" stroke-linecap="round" stroke-linejoin="round" stroke-width="1.5"/></svg></div>
                </div>
            </div>
        </div>`;
    const body = document.createElement('div');
    body.className = 'entry-expand-body';
    // Insert row + body after the last element in the group
    insertAfter.parentNode.insertBefore(row, insertAfter.nextSibling);
    row.parentNode.insertBefore(body, row.nextSibling);
    // Populate expand body via locked template
    if (typeof window.buildAllMedicalEntries === 'function') window.buildAllMedicalEntries();
    // Sync EMC snapshot (new allergy/condition/device → pill appears at the top)
    if (typeof window.syncEmcSnapshot === 'function') window.syncEmcSnapshot();
    // Re-compute Emergency Preparedness Score (a new non-archived entry may move the %)
    if (typeof window.updateEmergencyPreparednessScore === 'function') window.updateEmergencyPreparednessScore();
    return row;
}
// Allergy: create a new entry-row from EMC quick-add. Only the fields actually
// captured in the quick-add pad are populated — location / file / person / notes
// stay empty so View mode hides those sections per XD ("Only populated fields
// are displayed"). User adds the rest in Edit mode.
function emcInsertAllergyEntryRow(allergen, severity) {
    return addMedicalEntry({
        groupTitle: 'Allergies',
        icon: 'img/shield-allergy.png',
        title: allergen,
        type: 'Allergies',
        sub: 'Added today',
        badge: '',              // no status badge until location/file added
        badgeText: '',
        entryData: {
            category: 'Allergy',
            fields: [
                { label: 'Allergen', value: allergen, required: true },
                { label: 'Severity', value: severity, required: true }
            ]
            // NO location / file / person / notes — user fills them in Edit mode
        }
    });
}
window.addMedicalEntry = addMedicalEntry;

// ===== Canonical Entry Title Formatter (cross-record aware) =====
// Per Violetka 2026-05-11: stored entry.title INCLUDES owner prefix from
// creation time ("Sarah's Passport — Bulgaria"). Title is the same whether
// viewed on owner's record OR projected as Linked Entry on someone else's
// record — because the document IS owned by the original record (Sarah's
// passport stays "Sarah's Passport" everywhere it's referenced).
//
// This function is now a passthrough — kept for API compatibility with the
// render call sites. Future logic could re-apply prefix dynamically if owner
// is renamed, but for now stored title is the source of truth.
window.paFormatEntryTitle = function paFormatEntryTitle(entry, viewingPersonId) {
    if (!entry) return '';
    return entry.title || '(Untitled)';
};

// ===== Live Auto-Fill for Entry Name input =====
// As the user picks Category and fills the distinguishing conditional field,
// the Entry Name input auto-fills with "[OwnerFirstName]'s [Category] — [Distinguisher]".
// Examples:
//   profile.html → "Sarah's Passport — Bulgaria"
//   record.html (John's record) → "John's Driver's License — Spain"
// User can click cursor in the input and edit at any time; auto-fill backs off
// once the user has typed (detected via 'input' event on the input).
window.paUpdateEntryNameAutoFill = function paUpdateEntryNameAutoFill() {
    const form = document.querySelector('.entry-form-wrap.open[data-category]');
    if (!form) return;
    const input = form.querySelector('#anefEntryNameInput, .anef-entry-name-input');
    if (!input) return;
    // User has manually typed — never overwrite their input
    if (input.dataset.userEdited === 'true') return;

    const category = form.getAttribute('data-category');
    if (!category) return;

    // Owner first name — derived from the record being viewed
    const ownerId = (typeof window.paGetCurrentOwnerId === 'function')
        ? window.paGetCurrentOwnerId()
        : 'sj';
    const owner = (typeof window.peopleById === 'function') ? window.peopleById(ownerId) : null;
    const firstName = owner && owner.name ? owner.name.split(/\s+/)[0] : '';

    // Per-category distinguisher field (same map as save-time fallback).
    const ESSENTIAL_DISTINGUISHERS = {
        'Passport':                            'Country of Issue',
        'National ID Card':                    'Country of Issue',
        'Driver’s License':               'Country of Issue',
        'Birth Certificate':                   'Country of Issue',
        'Residence Permit':                    'Country of Issue',
        'EU Blue Card':                        'Issuing Country',
        'Visa':                                'Visa Type',
        'Work Permit':                         'Employer / Sponsor',
        'Social Security / National Insurance':'Type',
        'Citizenship Certificate':             'Country of Issue',
        'Refugee Status Document':             'Status',
        'Marriage Certificate':                'Spouse Full Name',
        'Death Certificate':                   'Decedent Full Name',
        'Name Change Document':                'New Full Name',
        'Other':                               'Describe Document Type'
    };
    const distLabel = ESSENTIAL_DISTINGUISHERS[category];
    let distValue = '';
    if (distLabel) {
        // Find the conditional field matching this label and read its current value
        const fieldWraps = form.querySelectorAll('.anef-field');
        const fieldDefs = (window.ANEF_CONDITIONAL && window.ANEF_CONDITIONAL[category]) || [];
        const idx = fieldDefs.findIndex(d => d.label === distLabel);
        if (idx >= 0 && fieldWraps[idx]) {
            const wrap = fieldWraps[idx];
            const valueEl = wrap.querySelector('.ee-contact-picker-value');
            const inputEl = wrap.querySelector('input.anef-text-input:not(.anef-custom-input), input.ee-contact-picker-input');
            const customEl = wrap.querySelector('input.anef-custom-input');
            const picked = valueEl && valueEl.textContent.trim() !== fieldDefs[idx].placeholder && valueEl.textContent.trim() !== fieldDefs[idx].label
                ? valueEl.textContent.trim() : '';
            const typed = inputEl ? inputEl.value.trim() : '';
            const customTyped = customEl ? customEl.value.trim() : '';
            distValue = picked === 'Other' ? customTyped : (picked || typed);
        }
    }

    // Build the canonical title
    let autoTitle = '';
    if (category === 'Other' && distValue) {
        // For "Other" we just use the user's free-text description
        autoTitle = firstName ? (firstName + '’s ' + distValue) : distValue;
    } else if (firstName) {
        autoTitle = firstName + '’s ' + category;
        if (distValue) autoTitle += ' — ' + distValue;
    } else {
        autoTitle = category;
        if (distValue) autoTitle += ' — ' + distValue;
    }

    // Update input value and remember it so live re-builds don't trigger
    // "user has typed" detection.
    input.value = autoTitle;
    input.dataset.autoBuilt = autoTitle;
};

// Wire input listeners so the auto-fill backs off as soon as the user types.
// Idempotent — guarded with _entryNameWired.
window.paWireEntryNameAutoFill = function paWireEntryNameAutoFill(form) {
    if (!form) form = document.querySelector('.entry-form-wrap.open[data-category]');
    if (!form || form._entryNameWired) return;
    form._entryNameWired = true;
    const input = form.querySelector('#anefEntryNameInput, .anef-entry-name-input');
    if (input) {
        input.addEventListener('input', function() {
            // If user has changed value to something other than last auto-built,
            // mark as user-edited (won't auto-update further).
            if (input.value !== input.dataset.autoBuilt) {
                input.dataset.userEdited = 'true';
            }
            // If user clears the input back to empty, allow auto-fill to resume
            if (input.value === '') {
                input.dataset.userEdited = 'false';
                window.paUpdateEntryNameAutoFill();
            }
        });
    }
    // Re-run auto-fill whenever any conditional field changes (input, change, click)
    const trigger = function() { setTimeout(window.paUpdateEntryNameAutoFill, 0); };
    form.addEventListener('input', trigger, true);
    form.addEventListener('change', trigger, true);
    form.addEventListener('click', trigger, true);
};

// ===== Inject one entriesStore entry into the matching Overview card =====
// Standalone helper so record.html can render the viewed person's entries
// directly into the Overview cards (Education / Employment / Medical / Beliefs).
//
// Mirrors the row-injection logic from saveCanonicalEntry. Idempotent — skips
// if a row with the same data-entry-id already exists.
window.paInjectEntryRowFromStore = function paInjectEntryRowFromStore(entry, opts) {
    if (!entry || !entry.groupTitle) return;
    // Skip if a row for this entry id already exists
    if (entry.id && document.querySelector('.entry-row[data-entry-id="' + CSS.escape(entry.id) + '"]')) return;

    opts = opts || {};
    const isLinked = !!opts.isLinked;

    function esc(s){return String(s == null ? '' : s).replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;').replace(/"/g,'&quot;').replace(/'/g,'&#39;');}

    // Determine viewing context for title formatting.
    // For record.html: viewing person = the record being viewed.
    // For profile.html: viewing person = 'sj' (Sarah / Plan Owner).
    // For linked entries, the viewing person is whoever the entry is being projected to.
    const viewingPersonId = opts.viewingPersonId
        || (typeof window.paGetCurrentOwnerId === 'function' ? window.paGetCurrentOwnerId() : 'sj');
    // Format title — adds "[Owner FirstName]'s " prefix when entry is linked
    // (owner differs from viewing record). Owned entries get plain title.
    const title       = (typeof window.paFormatEntryTitle === 'function')
                        ? window.paFormatEntryTitle(entry, viewingPersonId)
                        : (entry.title || '(Untitled)');
    const category    = entry.subcategory || entry.category || '';
    const dateLabel   = entry.dateLabel || 'Updated';
    const date        = entry.date || (entry.dateAdded ? String(entry.dateAdded).slice(0,10) : '');
    const hasFile     = !!entry.file || (Array.isArray(entry.files) && entry.files.length) || !!entry.hasFile;
    const hasLoc      = !!entry.location || !!entry.hasLocation;
    const badgeClass  = hasFile && hasLoc ? 'both' : hasFile ? 'digital' : hasLoc ? 'location' : '';
    const badgeText   = hasFile && hasLoc ? 'Digital File &amp; Location' : hasFile ? 'Digital File' : hasLoc ? 'Location' : '';
    // Expiry status dot — color-coded per reminder severity (red <30d / orange
    // <60d / green <180d / hidden otherwise). Inserted as prefix on doc-meta.
    let expiryDot = '';
    if (typeof window.paFindExpiryMilestone === 'function' && typeof window.paReminderSeverity === 'function') {
        const expM = window.paFindExpiryMilestone(entry);
        if (expM) {
            const MONTHS = ['January','February','March','April','May','June','July','August','September','October','November','December'];
            const y = parseInt(expM.year, 10);
            const mi = expM.month ? MONTHS.indexOf(expM.month) : 0;
            const d = expM.day ? parseInt(expM.day, 10) : 1;
            if (!isNaN(y) && mi >= 0) {
                const expDate = new Date(y, mi, d);
                const todayMid = new Date(); todayMid.setHours(0,0,0,0);
                const expMid = new Date(expDate); expMid.setHours(0,0,0,0);
                const daysLeft = Math.round((expMid - todayMid) / 86400000);
                const sev = window.paReminderSeverity(daysLeft);
                if (sev !== 'none') expiryDot = '<span class="pa-expiry-dot ' + sev + '"></span>';
            }
        }
    }
    const dateLine    = date ? (expiryDot + esc(dateLabel) + ': ' + esc(date)) : '';

    // Owner prefix is now in the title for linked entries — breadcrumb removed.
    // (Previous "From: [Owner]" line is redundant once title carries the prefix.)
    const fromSourceLine = '';

    // Find the matching .data-group-title element by exact text match
    // For linked entries, skip the .data-group-linked-subtitle separator
    const titleEls = Array.from(document.querySelectorAll('.data-group-title'))
        .filter(t => (t.textContent || '').trim() === entry.groupTitle && !t.classList.contains('data-group-linked-subtitle'));
    if (!titleEls.length) return;

    // Build action menu — linked entries only get "View Source" (Edit / Archive / Delete hidden via CSS)
    const rowMenu = isLinked
        ? '<div class="doc-menu" onclick="event.stopPropagation();toggleDD(this)"><div class="doc-menu-dots"><span></span><span></span><span></span></div><div class="doc-dropdown"><div class="doc-dropdown-trigger-row"><div class="doc-menu-inner"><div class="doc-menu-dots"><span></span><span></span><span></span></div></div></div><div class="dd-row" onclick="event.stopPropagation();if(typeof openPersonRecord===\'function\')openPersonRecord(\'' + esc(entry.ownerId) + '\')"><span class="dd-row-label">View Source</span><div class="dd-row-icon"><svg viewBox="0 0 20 18" fill="none" stroke="#000" stroke-width="1.5" stroke-linecap="round" stroke-linejoin="round"><path d="M1 9c2.5-5 6-7 9-7s6.5 2 9 7c-2.5 5-6 7-9 7s-6.5-2-9-7zm9 3a3 3 0 100-6 3 3 0 000 6z"/></svg></div></div></div></div>'
        : '<div class="doc-menu" onclick="event.stopPropagation();toggleDD(this)"><div class="doc-menu-dots"><span></span><span></span><span></span></div><div class="doc-dropdown"><div class="doc-dropdown-trigger-row"><div class="doc-menu-inner"><div class="doc-menu-dots"><span></span><span></span><span></span></div></div></div><div class="dd-row dd-row-edit" onclick="event.stopPropagation();paDocDropdownEditClick(this)"><span class="dd-row-label">Edit</span><div class="dd-row-icon"><svg viewBox="0 0 20 18" fill="none" stroke="#000" stroke-width="1.5" stroke-linecap="round" stroke-linejoin="round"><path d="M14.5 1.5l2 2L5 15H3v-2L14.5 1.5z"/></svg></div></div><div class="dd-row" onclick="event.stopPropagation();paArchiveEntryRow(this)"><span class="dd-row-label">Archive</span><div class="dd-row-icon"><svg viewBox="0 0 21.5 19.5" fill="none" stroke="#000" stroke-width="1.5" stroke-linecap="round" stroke-linejoin="round"><path d="M20.7 7.8L20 19.4a2.4 2.4 0 01-2.3 2.3H6.7a2.4 2.4 0 01-2.3-2.3L3.7 7.8m6.4 4.1h4.1M3.4 7.8h17.7a1.2 1.2 0 001.2-1.2V5a1.2 1.2 0 00-1.2-1.2H3.4A1.2 1.2 0 002.2 5v1.6a1.2 1.2 0 001.2 1.2z"/></svg></div></div><div class="dd-row" onclick="event.stopPropagation();paDeleteEntryRow(this)"><span class="dd-row-label">Delete</span><div class="dd-row-icon"><svg viewBox="0 0 19.7 21.5" fill="none" stroke="#000" stroke-width="1.5" stroke-linecap="round" stroke-linejoin="round"><path d="M15.7 9.2L15.4 18.4M10.1 18.4L9.8 9.2M3.75 6.05c.37-.06.74-.12 1.12-.17m0 0L6.03 20.1a2.4 2.4 0 002.45 2.13h8.54a2.4 2.4 0 002.45-2.13L20.63 5.88m0 0c-1.26-.18-2.53-.31-3.79-.41m-8.18 0V4.53a2.3 2.3 0 012.28-2.26q1.81-.05 3.62 0a2.3 2.3 0 012.28 2.26v.94"/></svg></div></div></div></div>';

    titleEls.forEach(titleEl => {
        let anchor;
        if (isLinked) {
            // Linked rows go AFTER the canonical .data-group-linked-subtitle separator.
            // Find or create the separator inside THIS group (between titleEl and next group title).
            let separator = null;
            let lastSibling = titleEl;
            let n = titleEl.nextElementSibling;
            while (n) {
                if (n.classList && n.classList.contains('data-group-title') && !n.classList.contains('data-group-linked-subtitle')) break;
                if (n.classList && n.classList.contains('data-group-linked-subtitle')) { separator = n; break; }
                lastSibling = n;
                n = n.nextElementSibling;
            }
            if (!separator) {
                separator = document.createElement('div');
                separator.className = 'data-group-title data-group-linked-subtitle';
                separator.textContent = 'Linked Entries';
                lastSibling.parentNode.insertBefore(separator, lastSibling.nextSibling);
            }
            // Now walk past any existing linked entry rows already inserted after the separator
            anchor = separator;
            let m = separator.nextElementSibling;
            while (m && m.classList && (m.classList.contains('entry-row') || m.classList.contains('entry-expand-body'))) {
                anchor = m;
                m = m.nextElementSibling;
            }
        } else {
            // Walk past +Add button, entry-form-wrap, and any empty-state pads
            // so the new entry lands AFTER all of them (canonical order:
            // group-title → +Add → form-wrap → empty-state → owned entries → subtitle → linked entries).
            anchor = titleEl;
            let n = titleEl.nextElementSibling;
            while (n && (n.classList.contains('emc-add-entry-btn') || n.classList.contains('entry-form-wrap') || n.classList.contains('card-empty-state') || n.classList.contains('emc-empty-state'))) {
                anchor = n;
                n = n.nextElementSibling;
            }
            // Continue past existing OWNED rows (not linked subtitle / linked rows) so each new owned row is appended at end of owned section
            while (n && n.classList && n.classList.contains('entry-row') && !n.classList.contains('is-linked')) {
                anchor = n;
                n = n.nextElementSibling;
                if (n && n.classList && n.classList.contains('entry-expand-body')) {
                    anchor = n;
                    n = n.nextElementSibling;
                }
            }
        }

        const row = document.createElement('div');
        row.className = 'doc-row entry-row' + (isLinked ? ' is-linked' : '');
        // setAttribute stores the value as a string verbatim — DOMtokenList /
        // HTML-entity encoding only applies when serializing back to HTML, not
        // for live attribute reads. So plain JSON.stringify is correct here;
        // getAttribute('data-entry') will return the same JSON string and
        // JSON.parse will succeed. The previous .replace(/"/g, '&quot;') broke
        // parsing because getAttribute does NOT decode HTML entities.
        row.setAttribute('data-entry', JSON.stringify(entry));
        if (entry.id) row.setAttribute('data-entry-id', entry.id);
        if (isLinked) row.setAttribute('data-linked', 'true');
        row.setAttribute('onclick', 'paEsRowClick(this, event)');
        row.innerHTML = '\
            <div class="doc-icon"><img class="doc-icon-glyph" src="img/document.png" alt=""></div>\
            <div class="doc-info">\
                <div class="doc-title">' + esc(title) + '</div>\
                <div class="doc-type">' + esc(category) + '</div>\
                ' + (dateLine ? '<div class="doc-meta">' + dateLine + '</div>' : '') + '\
                ' + fromSourceLine + '\
            </div>\
            ' + (badgeText ? '<div class="data-right"><span class="data-badge ' + badgeClass + '">' + badgeText + '</span></div>' : '') + '\
            ' + rowMenu;

        const body = document.createElement('div');
        body.className = 'entry-expand-body' + (isLinked ? ' is-linked' : '');
        anchor.parentNode.insertBefore(body, anchor.nextSibling);
        anchor.parentNode.insertBefore(row, body);
    });
};

// ===== Inject entriesStore data into Print Document fragments =====
// The print document (print-document.html) fetches static HTML fragments
// from /print/*.html. Those fragments contain XD-exported absolutely-positioned
// spans with hardcoded text — they cannot be live-edited from JS the usual
// way. Instead, every text element that should reflect the user's data has a
// `data-print-field` attribute pointing back to the entry in entriesStore via
// `data-print-entry-id`. After all fragments are loaded, this function walks
// every `[data-print-field]` element and replaces its textContent (or, for
// boolean visibility cases, sets `display`) based on the current entry value.
//
// This makes the print document a READ-ONLY projection of entriesStore — any
// edit in profile.html → re-print → updated print.
//
// Supported `data-print-field` values:
//   title                       → entry.title
//   subcategory                 → entry.subcategory
//   dateLine                    → `${entry.dateLabel}: ${entry.date}` (Expiry Date: Oct 14, 2028)
//   dateUpdatedLine             → "Updated {date} by {updatedBy||'You'}" (when dateLabel === 'Updated')
//   location                    → entry.location || 'Not Specified'
//   locationDetails             → entry.locationDetails || 'No location details'
//   notes                       → entry.notes
//   fileName                    → entry.files[0].name (or hide parent if no file)
//   fileUploaded                → "Uploaded {entry.files[0].uploaded}" (or hide if no file)
//   statusBadgeText             → "Digital File & Location" / "Digital File" / "Location"
//   statusBadgeColor (style)    → background color of the dot/circle based on file/location combo
//
// Special attributes:
//   data-print-show-if-file     → hide element if !entry.files.length (file-only blocks)
//   data-print-show-if-location → hide element if !entry.hasLocation
//   data-print-hide-if-file     → hide element if entry.files.length (location-only blocks)
window.paInjectPrintData = function paInjectPrintData() {
    if (!Array.isArray(window.entriesStore)) return;
    var byId = {};
    window.entriesStore.forEach(function(e) { if (e && e.id) byId[e.id] = e; });

    document.querySelectorAll('[data-print-entry-id]').forEach(function(el) {
        var entryId = el.getAttribute('data-print-entry-id');
        var entry = byId[entryId];
        if (!entry) return;

        // Per-element field replacement (one attribute per element).
        var field = el.getAttribute('data-print-field');
        if (field) {
            var val = paPrintResolveField(entry, field);
            if (val !== null && val !== undefined) el.textContent = val;
        }

        // Color/style fields (e.g. status dot background).
        var styleField = el.getAttribute('data-print-style');
        if (styleField === 'statusColor') {
            var col = paPrintStatusColor(entry);
            if (col && el.style) el.style.background = col;
        }
        if (styleField === 'statusBorder') {
            var col2 = paPrintStatusColor(entry);
            if (col2 && el.style) el.style.borderColor = col2;
        }

        // Visibility toggles for whole sub-blocks (file card, location detail card, etc.)
        var showIf = el.getAttribute('data-print-show-if');
        if (showIf) {
            var ok = paPrintShowIfTest(entry, showIf);
            el.style.display = ok ? '' : 'none';
        }
    });

    // Wholesale entry-block removal — when an entry slot was reserved in the
    // print template but the corresponding entry no longer exists in entriesStore
    // (user archived/deleted it), the whole block should disappear.
    document.querySelectorAll('[data-print-entry-id]').forEach(function(el) {
        var entryId = el.getAttribute('data-print-entry-id');
        if (!byId[entryId] && el.hasAttribute('data-print-remove-if-missing')) {
            el.style.display = 'none';
        }
    });
};

// Resolver — single source of truth for what `data-print-field` values mean.
function paPrintResolveField(entry, field) {
    switch (field) {
        case 'title':           return entry.title || '';
        case 'subcategory':     return entry.subcategory || '';
        case 'dateLine':
            // Canonical: "{dateLabel}: {date}"  — exactly what the entry-row
            // renders too (paInjectEntryRowFromStore / paRenderDocumentsList).
            if (!entry.date) return '';
            var lbl = entry.dateLabel || 'Updated';
            // Special-case "Updated" date label → "Updated {date} by {You}"
            // (no colon, with trailing actor — matches the print XD template).
            if (lbl.toLowerCase() === 'updated') {
                var actor = entry.updatedBy || 'You';
                return 'Updated ' + entry.date + ' by ' + actor;
            }
            return lbl + ': ' + entry.date;
        case 'location':        return entry.location || 'Not Specified';
        case 'locationDetails': return entry.locationDetails || 'No location details';
        case 'notes':           return entry.notes || '';
        case 'fileName':
            return entry.files && entry.files[0] ? entry.files[0].name :
                   (entry.file ? entry.file.name : '');
        case 'fileUploaded':
            var f = (entry.files && entry.files[0]) || entry.file;
            return f && f.uploaded ? 'Uploaded ' + f.uploaded : '';
        case 'statusBadgeText':
            var hasFile = !!(entry.files && entry.files.length) || !!entry.file || !!entry.hasFile;
            var hasLoc  = !!entry.location || !!entry.hasLocation;
            if (hasFile && hasLoc) return 'Digital File & Location';
            if (hasFile)            return 'Digital File';
            if (hasLoc)             return 'Location';
            return '';
        default: return null;
    }
}
function paPrintStatusColor(entry) {
    var hasFile = !!(entry.files && entry.files.length) || !!entry.file || !!entry.hasFile;
    var hasLoc  = !!entry.location || !!entry.hasLocation;
    if (hasFile && hasLoc) return '#61C553'; // green — both
    if (hasFile)            return '#667EEA'; // blue — file only
    if (hasLoc)             return '#FF9500'; // orange — location only
    return 'rgba(0,0,0,0.3)';
}
function paPrintShowIfTest(entry, kind) {
    var hasFile = !!(entry.files && entry.files.length) || !!entry.file || !!entry.hasFile;
    var hasLoc  = !!entry.location || !!entry.hasLocation;
    switch (kind) {
        case 'file':       return hasFile;
        case 'location':   return hasLoc;
        case 'noFile':     return !hasFile;
        case 'noLocation': return !hasLoc;
        case 'notes':      return !!(entry.notes && entry.notes.trim());
        default: return true;
    }
}

// ===== File Preview Modal — full-screen overlay for entry-attached files =====
// Opens when user clicks the file row inside an entry's expand body (view
// mode). Reuses the canonical .doc-sidebar pattern from print-document.html
// (glassmorphic 300px sidebar + back arrow + avatar + sections + download/
// print buttons at the bottom). The right side hosts a large gray placeholder
// where the real PDF / image render will live in a later iteration.
//
// Trigger: <div class="file-list-row" onclick="paOpenFilePreview(this)">
// Close:   X button, Esc key, click outside the modal-shell.
window.paOpenFilePreview = function paOpenFilePreview(fileRowEl) {
    if (!fileRowEl) return;
    var body = fileRowEl.closest('.entry-expand-body');
    if (!body) return;
    var row = body.previousElementSibling;
    if (!row || !row.classList.contains('entry-row')) return;
    var data;
    try { data = JSON.parse(row.getAttribute('data-entry') || '{}'); }
    catch(_e) { return; }
    var fileIdx = parseInt(fileRowEl.getAttribute('data-file-index') || '0', 10);
    var file = (Array.isArray(data.files) && data.files[fileIdx]) || data.file;
    if (!file) return;
    paBuildFilePreviewModal(data, file);
};

window.paCloseFilePreview = function paCloseFilePreview() {
    // Mirror open: remove .doc-preview-mode body class (restores page UI)
    // + remove the .doc-preview element we appended.
    var preview = document.getElementById('paFpDocPreview');
    if (preview) preview.remove();
    // Only drop .doc-preview-mode if WE added it (don't strip on print-doc page).
    if (document.body.hasAttribute('data-pa-fp-added-mode')) {
        document.body.classList.remove('doc-preview-mode');
        document.body.removeAttribute('data-pa-fp-added-mode');
    }
    document.removeEventListener('keydown', _paFilePreviewKey);
};

// Defensive cleanup — runs once at script load. If a previous session
// somehow left .doc-preview-mode + data-pa-fp-added-mode on body WITHOUT
// the actual modal element being present (e.g., user navigated away mid-
// modal, browser back, script error), the visibility:hidden rules would
// still apply and the user would see entry rows / expand bodies / accordion
// sections as INVISIBLE — including the .ee-edit-trigger pencil button.
// This was the root cause of Violetka reporting "I can't press Edit on
// existing entries". Strips the orphan flag so page UI is restored.
// 2026-05-12.
(function paFpCleanupStaleModalState() {
    if (typeof document === 'undefined' || !document.body) return;
    var hasFlag = document.body.hasAttribute('data-pa-fp-added-mode');
    var modalEl = document.getElementById('paFpDocPreview');
    if (hasFlag && !modalEl) {
        document.body.classList.remove('doc-preview-mode');
        document.body.removeAttribute('data-pa-fp-added-mode');
        console.warn('[paFp] Cleaned up orphan modal state flag at page load.');
    }
})();

function _paFilePreviewKey(ev) {
    if (ev.key === 'Escape') window.paCloseFilePreview();
}

/**
 * Canonical entry-icon picker — mirrors the local `pickGlyph` used inside
 * the Documents tab renderer (line ~5367). Exposed globally so anywhere
 * we need to render an entry's identity icon (file preview modal,
 * print pages, future widgets) we use the SAME mapping logic instead of
 * duplicating it. Returns { src, size: {w, h} } where size is the
 * intended display size for the icon glyph.
 *
 * Rule: entry.icon override → identity/vital/relationship/status docs use
 * document.png → blood/allergy/medical/education/employment/membership/
 * beliefs/hobbies/interests have category-specific glyphs → fallback to
 * document.png.
 *
 * 2026-05-12 — added for file preview modal "Entry context" section icon.
 */
window.paPickEntryIcon = function paPickEntryIcon(entry) {
    var cat = String((entry && entry.subcategory) || '').toLowerCase();
    var grp = String((entry && entry.groupTitle) || '').toLowerCase();
    if (entry && entry.icon) return { src: entry.icon, w: 20, h: 16 };
    // Documents that look like passports / IDs / certificates use the
    // canonical document.png. Short-circuited before generic keyword
    // matches so "Birth Certificate" doesn't fall into the education branch.
    if (grp.indexOf('identity') >= 0 || grp.indexOf('vital documents') >= 0
        || grp.indexOf('relationship') >= 0 || grp.indexOf('status documents') >= 0) {
        return { src: 'img/document.png', w: 16, h: 20 };
    }
    if (grp === 'blood type' || cat === 'blood type') return { src: 'img/drop.svg', w: 16, h: 20 };
    if (grp === 'allergies' || cat === 'allergies') return { src: 'img/shield-allergy.png', w: 18, h: 20 };
    if (grp.indexOf('medical') >= 0 || cat.indexOf('medical') >= 0) return { src: 'img/pill.png', w: 20, h: 20 };
    if (grp.indexOf('educ') >= 0 || grp.indexOf('certif') >= 0
        || cat.indexOf('bachelor') >= 0 || cat.indexOf('master') >= 0 || cat.indexOf('phd') >= 0) {
        return { src: 'img/education.png', w: 20, h: 18 };
    }
    if (grp.indexOf('employ') >= 0) return { src: 'img/goal.png', w: 20, h: 20 };
    if (grp.indexOf('member') >= 0 || grp.indexOf('affil') >= 0) return { src: 'img/crown.png', w: 24, h: 20 };
    if (grp === 'beliefs' || cat === 'beliefs') return { src: 'img/heart.png', w: 20, h: 18 };
    if (grp === 'hobbies' || cat === 'hobbies') return { src: 'img/star.png', w: 20, h: 20 };
    if (grp === 'interests' || cat === 'interests') return { src: 'img/puzzle.png', w: 20, h: 20 };
    return { src: 'img/document.png', w: 16, h: 20 };
};

function paBuildFilePreviewModal(entry, file) {
    function esc(s) { return String(s == null ? '' : s).replace(/[&<>"']/g, function(c) { return ({'&':'&amp;','<':'&lt;','>':'&gt;','"':'&quot;',"'":'&#39;'})[c]; }); }
    // Owner — Plan Owner (sj) gets "PlanAfter" subtitle; others get their plan.
    var owner = (typeof window.peopleById === 'function') ? window.peopleById(entry.ownerId || 'sj') : null;
    var ownerName  = owner ? owner.name : 'Sarah Johnson';
    var ownerPhoto = owner && owner.photo ? owner.photo : '';
    // Role label matches print-document.html canonical: "Plan Owner" for sj,
    // otherwise the person's peopleStore role (Husband / Daughter / Mother / …).
    var ownerSub   = entry.ownerId === 'sj'
        ? 'Plan Owner'
        : ((owner && (owner.role || owner.relationship)) || (ownerName.split(' ')[0] + '’s Record'));
    var initials   = String(ownerName).split(' ').map(function(n) { return n.charAt(0); }).join('').slice(0, 2).toUpperCase();
    // Location in the Platform (3 levels). Sub label swaps for non-owner records.
    var CARD_LABEL = {
        essential:  'Essential Info',
        family:     'Family & Relationships',
        medical:    'Medical Info',
        education:  'Education',
        employment: 'Employment & Affiliations',
        beliefs:    'Beliefs, Hobbies & Interests'
    };
    var pathL1 = 'Me, Family & Network';
    var pathL2 = entry.ownerId === 'sj' ? 'My Profile' : (ownerName.split(' ')[0] + '’s Record');
    var pathL3 = CARD_LABEL[entry.cardKey] || (entry.cardKey || 'Card');
    // Per XD spec: PDF.png with @2x retina pair (.svg variant kept as legacy).
    var fileType = String(file.type || 'PDF').toUpperCase();
    var iconSrc  = 'img/' + fileType + '.png';
    var iconSrc2x = 'img/' + fileType + '@2x.png';
    // Entry-type icon for the second glass circle (mirrors what's shown on
    // the entry row in Documents tab / overview cards). Per Violetka
    // 2026-05-12: same icon per card + entry type — NOT generic document.png.
    // NOTE: NOT all entry icons have @2x retina variants (document.png,
    // shield-allergy.png, pill.png, education.png ship without @2x). Using
    // srcset with a missing @2x file causes the browser to render a
    // broken-image placeholder on retina screens. So we skip srcset
    // entirely here and rely on the 1x src — the icon is small (16-24px)
    // and the upscale loss is imperceptible.
    var entryIcon = window.paPickEntryIcon(entry);
    var entryIconSrc = entryIcon.src;

    var avatarInner = ownerPhoto
        ? '<img class="doc-sb-photo" src="' + esc(ownerPhoto) + '" alt="' + esc(ownerName) + '">'
        : '<span class="doc-sb-initials">' + esc(initials) + '</span>';

    // Create the .doc-preview element verbatim from print-document.html.
    // The .doc-preview IS the modal — no extra wrapper. Inside it: sidebar +
    // viewer, exactly mirroring the print-document.html structure.
    var preview = document.createElement('div');
    preview.id = 'paFpDocPreview';
    preview.className = 'doc-preview';

    preview.innerHTML = [
            '<div class="doc-sidebar expanded" id="paFpSidebar">',
                '<button class="doc-sb-btn doc-sb-back" onclick="event.stopPropagation();paFpToggleSidebar()" title="Expand / collapse">',
                    '<svg xmlns="http://www.w3.org/2000/svg" width="12" height="10" viewBox="0 0 13.81 12.121"><path d="M18.95,23l4.8-5m0,0-4.8-5m4.8,5h-12" transform="translate(-11 -11.94)" fill="none" stroke="#000" stroke-linecap="round" stroke-linejoin="round" stroke-width="1.5"/></svg>',
                '</button>',
                '<div class="doc-sb-avatar" onclick="event.stopPropagation();paFpExpandIfCollapsed()">',
                    '<div class="doc-sb-avatar-wrap">',
                        avatarInner,
                    '</div>',
                '</div>',
                '<span class="doc-sb-name">' + esc(ownerName) + '</span>',
                '<span class="doc-sb-role">' + esc(ownerSub) + '</span>',
                '<div class="doc-sb-divider"></div>',
                // Selected file card — direct child of .doc-sidebar (NOT inside
                // .doc-sb-select) so its edge-to-edge white band can stretch the
                // full sidebar width via align-self: stretch. Putting it inside
                // .doc-sb-select would clip it because that wrapper has
                // overflow:hidden + 20px horizontal margin.
                // Click in collapsed mode → expand sidebar (canonical pattern).
                '<div class="pa-fp-filecard" onclick="event.stopPropagation();paFpExpandIfCollapsed()">',
                    '<img class="pa-fp-filecard-icon" src="' + iconSrc + '" srcset="' + iconSrc + ' 1x, ' + iconSrc2x + ' 2x" alt="">',
                    '<span class="pa-fp-filecard-name">' + esc(file.name) + '</span>',
                '</div>',
                // .doc-sb-select stops click propagation so internal interactive
                // elements (chevrons, scroll, etc.) don't accidentally expand the
                // sidebar — BUT the section icons inside it have their own
                // explicit onclick that calls paFpExpandIfCollapsed (collapsed
                // mode only), so the icons remain clickable as tap-to-expand
                // affordances. In expanded mode the icons do nothing on click.
                '<div class="doc-sb-select" onclick="event.stopPropagation()">',
                    // Location in the Platform — small gray section label per XD
                    '<div class="pa-fp-section">',
                        '<div class="pa-fp-section-head">',
                            '<span class="pa-fp-section-icon" onclick="event.stopPropagation();paFpExpandIfCollapsed()"><img src="img/in-folder.png" srcset="img/in-folder.png 1x, img/in-folder@2x.png 2x" width="20" height="16" alt=""></span>',
                            '<span class="pa-fp-section-label">Location in the Platform</span>',
                        '</div>',
                        '<ul class="pa-fp-path-list">',
                            '<li><span class="pa-fp-dot pa-fp-dot-lg"></span><span class="pa-fp-path-text-bold">' + esc(pathL1) + '</span></li>',
                            '<li><span class="pa-fp-dot pa-fp-dot-sm"></span><span class="pa-fp-path-text">' + esc(pathL2) + '</span></li>',
                            '<li><span class="pa-fp-dot pa-fp-dot-sm"></span><span class="pa-fp-path-text">' + esc(pathL3) + '</span></li>',
                        '</ul>',
                    '</div>',
                    // Entry context — Inter 600 16/24 title per XD.
                    // Icon = canonical entry-type icon per card + subcategory
                    // (passport→document.png, allergies→shield-allergy.png,
                    // medical→pill.png, education→education.png, etc.).
                    // Click in collapsed mode → expand sidebar.
                    '<div class="pa-fp-section">',
                        '<div class="pa-fp-section-head">',
                            '<span class="pa-fp-section-icon" onclick="event.stopPropagation();paFpExpandIfCollapsed()"><img src="' + entryIconSrc + '" width="' + entryIcon.w + '" height="' + entryIcon.h + '" alt=""></span>',
                            '<span class="pa-fp-section-title">' + esc(entry.title || '(Untitled)') + '</span>',
                        '</div>',
                        '<div class="pa-fp-entry-row">',
                            '<span class="pa-fp-entry-value">' + esc(entry.subcategory || '—') + '</span>',
                            '<span class="pa-fp-entry-label">Document Type</span>',
                        '</div>',
                        '<div class="pa-fp-entry-row">',
                            '<span class="pa-fp-entry-value">' + esc(entry.groupTitle || '—') + '</span>',
                            '<span class="pa-fp-entry-label">Group / Category</span>',
                        '</div>',
                        '<div class="pa-fp-entry-row">',
                            '<span class="pa-fp-entry-value">' + esc(entry.location || '—') + '</span>',
                            '<span class="pa-fp-entry-label">Location of the Original</span>',
                        '</div>',
                    '</div>',
                '</div>',
                // Bottom Download + Print rows (canonical .doc-sb-btn-row)
                '<div class="doc-sb-btn-row doc-sb-btn-row-first" onclick="event.stopPropagation();window.print()">',
                    '<button class="doc-sb-download" title="Download">',
                        '<svg xmlns="http://www.w3.org/2000/svg" width="20" height="20" viewBox="0 0 21.5 21.5"><path d="M3,18v2.5A2.5,2.5,0,0,0,5.5,23h15A2.5,2.5,0,0,0,23,20.5V18m-5-5-5,5m0,0L8,13m5,5V3" transform="translate(-2.25 -2.25)" fill="none" stroke="#000" stroke-linecap="round" stroke-linejoin="round" stroke-width="1.5"/></svg>',
                    '</button>',
                    '<span class="doc-sb-label">Download</span>',
                '</div>',
                '<div class="doc-sb-btn-row" onclick="event.stopPropagation();window.print()">',
                    '<button class="doc-sb-print" title="Print">',
                        '<svg xmlns="http://www.w3.org/2000/svg" width="20" height="20" viewBox="0 0 21.5 21.5"><path d="M7.133,14.126q-.4.046-.8.1m.8-.1a51.026,51.026,0,0,1,11.733,0m-11.733,0L6.711,18.4m12.156-4.278q.4.046.8.1m-.8-.1.422,4.278m0,0,.254,2.588a1.1,1.1,0,0,1-.322.883,1.3,1.3,0,0,1-.923.376H7.7a1.194,1.194,0,0,1-1.244-1.258L6.711,18.4m12.576,0H20.5A2.41,2.41,0,0,0,23,16.1V9.641A2.3,2.3,0,0,0,20.959,7.41q-1.06-.146-2.126-.253M6.711,18.4H5.5A2.41,2.41,0,0,1,3,16.1V9.641A2.3,2.3,0,0,1,5.041,7.41q1.06-.146,2.126-.253m11.667,0a58.4,58.4,0,0,0-11.667,0m11.667,0V3.4a1.205,1.205,0,0,0-1.25-1.154H8.417A1.205,1.205,0,0,0,7.167,3.4V7.157" transform="translate(-2.25 -1.5)" fill="none" stroke="#000" stroke-linecap="round" stroke-linejoin="round" stroke-width="1.5"/></svg>',
                    '</button>',
                    '<span class="doc-sb-label">Print</span>',
                '</div>',
            '</div>', // /doc-sidebar
            '<div class="doc-viewer pa-fp-viewer">',
                '<button class="doc-close" onclick="paCloseFilePreview()" aria-label="Close">',
                    '<svg viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="1.5" stroke-linecap="round"><circle cx="12" cy="12" r="10" stroke-opacity="0.3"/><line x1="15" y1="9" x2="9" y2="15"/><line x1="9" y1="9" x2="15" y2="15"/></svg>',
                '</button>',
                '<div class="pa-fp-preview-label">Document<br>Preview</div>',
            '</div>' // /doc-viewer
    ].join('');
    document.body.appendChild(preview);
    // Add .doc-preview-mode (canonical) — same hide-page-UI mechanism the
    // standalone print-document.html page uses. Track that WE added it so
    // close logic doesn't strip it on print-doc itself.
    if (!document.body.classList.contains('doc-preview-mode')) {
        document.body.classList.add('doc-preview-mode');
        document.body.setAttribute('data-pa-fp-added-mode', '1');
    }
    document.addEventListener('keydown', _paFilePreviewKey);
}

// Toggle sidebar collapse / expand. Mirrors print-document.html docSbBackClick.
window.paFpToggleSidebar = function paFpToggleSidebar() {
    var sb = document.getElementById('paFpSidebar');
    if (sb) sb.classList.toggle('expanded');
};

// One-way EXPAND when collapsed — used by all the icon-circle click handlers
// (avatar, file card, location, entry context). Per Violetka 2026-05-12:
// when the sidebar is collapsed (80px), clicking any of the icons opens
// it back to 300px. Once expanded, the icons no longer have an action
// (the .doc-sb-back arrow is the canonical collapse control). One-way
// only — never collapses on click of these icons.
window.paFpExpandIfCollapsed = function paFpExpandIfCollapsed() {
    var sb = document.getElementById('paFpSidebar');
    if (sb && !sb.classList.contains('expanded')) {
        sb.classList.add('expanded');
    }
};

// ===== Render print-document entry blocks (SSOT-driven) =====
// Each entry on the print document is a single <div class="print-entry-slot"
// data-print-entry-id="..."> placeholder. This function fills its inner HTML
// from window.entriesStore — title, structured fields, location, file, linked
// contacts, notes. The whole block hides on display:none when excluded via
// the print-customize tree (one slot, one ID — no element-by-element tagging).
//
// Per Violetka 2026-05-12: NEW print layout — drops the "Location in Platform"
// vault breadcrumb (meaningless on paper) in favour of structured fields +
// real file preview + linked contact summary cards.
window.paRenderPrintEntries = function paRenderPrintEntries() {
    if (!Array.isArray(window.entriesStore)) return;
    var byId = {};
    window.entriesStore.forEach(function(e) { if (e && e.id) byId[e.id] = e; });

    document.querySelectorAll('.print-entry-slot[data-print-entry-id]').forEach(function(slot) {
        var id = slot.getAttribute('data-print-entry-id');
        var entry = byId[id];
        if (!entry || entry.archived) {
            slot.innerHTML = '';
            return;
        }
        slot.innerHTML = paBuildPrintEntryHTML(entry);
    });
    // After all entries render, insert a full-page document preview after
    // the parent page for every entry that has at least one attached file.
    // Idempotent — guard with data-pa-doc-pages-inserted on the parent page.
    paInsertDocumentPages();
};

// Insert one full .print-page after each entry-page that has files. Each
// file gets its own preview page. Inherits data-print-entry-id +
// data-print-page-cards from the source entry so it follows the exclusion
// logic (hides when the entry is unchecked OR its card is fully excluded).
function paInsertDocumentPages() {
    var anyInserted = false;
    document.querySelectorAll('.print-entry-slot[data-print-entry-id]').forEach(function(slot) {
        // Guard — don't re-insert if we've already done it for this slot.
        if (slot.getAttribute('data-pa-doc-page-inserted') === '1') return;
        var id = slot.getAttribute('data-print-entry-id');
        var entry = (window.entriesStore || []).find(function(e) { return e && e.id === id; });
        if (!entry || entry.archived) return;
        var files = Array.isArray(entry.files) && entry.files.length ? entry.files
                  : entry.file ? [entry.file] : [];
        if (!files.length) return;
        var parentPage = slot.closest('.print-page');
        if (!parentPage) return;
        // The CARD this preview-page belongs to — same as the entry's card.
        var cardKey = entry.cardKey || (parentPage.getAttribute('data-print-page-cards') || 'always-show');
        // Insert one preview page per file, immediately after the parent page.
        // Build in reverse so insertion order matches file order.
        files.slice().reverse().forEach(function(file) {
            var docPage = paBuildPrintDocumentPage(entry, file, cardKey);
            parentPage.parentNode.insertBefore(docPage, parentPage.nextSibling);
            anyInserted = true;
        });
        slot.setAttribute('data-pa-doc-page-inserted', '1');
    });
    // After inserting all doc pages, sync the plan owner avatar on each new
    // page + fill any data-print-now timestamps. The .print-owner-avatar
    // elements just inserted aren't covered by the page-init sync (that ran
    // before we existed), so we trigger it explicitly here.
    if (anyInserted) {
        paSyncOwnerAvatarsOnNewDocPages();
        paFillPrintNowTimestamps();
    }
}

// Sync the plan owner photo onto avatars in newly inserted print doc pages.
// Reuses localStorage.planOwnerPhoto as the source of truth (same as the
// page-init sync). If no photo is stored, the initials placeholder remains.
function paSyncOwnerAvatarsOnNewDocPages() {
    try {
        var url = localStorage.getItem('planOwnerPhoto');
        if (!url) return;
        document.querySelectorAll('.print-doc-preview-page .print-owner-avatar').forEach(function(el) {
            if (el.getAttribute('data-pa-owner-synced') === '1') return;
            el.src = url;
            el.style.display = 'block';
            el.setAttribute('data-pa-owner-synced', '1');
            // Hide the sibling initials placeholder if present.
            var siblings = el.parentNode ? el.parentNode.children : [];
            for (var i = 0; i < siblings.length; i++) {
                if (siblings[i] !== el && siblings[i].classList && siblings[i].classList.contains('print-profile-initials')) {
                    siblings[i].style.display = 'none';
                }
            }
        });
    } catch (_e) { /* localStorage unavailable — ignore */ }
}

// Fill data-print-now="date" / "time" placeholders on dynamically inserted
// print pages. Mirrors what print-document.html does on page init for the
// static pages — but only targets elements that haven't been filled yet.
function paFillPrintNowTimestamps() {
    var now = new Date();
    var months = ['January','February','March','April','May','June','July','August','September','October','November','December'];
    var dateStr = months[now.getMonth()] + ' ' + now.getDate() + ', ' + now.getFullYear();
    var hh = String(now.getHours()).padStart(2, '0');
    var mm = String(now.getMinutes()).padStart(2, '0');
    var timeStr = hh + ':' + mm;
    document.querySelectorAll('.print-doc-preview-page [data-print-now="date"]').forEach(function(el) {
        if (el.getAttribute('data-pa-now-filled') === '1') return;
        el.textContent = dateStr;
        el.setAttribute('data-pa-now-filled', '1');
    });
    document.querySelectorAll('.print-doc-preview-page [data-print-now="time"]').forEach(function(el) {
        if (el.getAttribute('data-pa-now-filled') === '1') return;
        el.textContent = timeStr;
        el.setAttribute('data-pa-now-filled', '1');
    });
}

// ─────────────────────────────────────────────────────────────────────
// Print Document Preview page — XD-locked 2026-05-12 (Option A: print-page
// mirror of the File Preview Modal, adapted for paper).
//
// Each attached file gets its own .print-page (A4, 1200×1840). The page
// mirrors EXACTLY the canonical print-content-page template used by every
// other content page (cover, personal, contact, family, documents, etc.):
//   Header: logo pill + section title + plan owner avatar + name pad
//   LEFT column (120/672): "Attached Document" heading + description
//   RIGHT column (520/160): File card + Location in Platform + Entry context
//   Footer: disclaimer + Document Created date/time + Page number
//
// The right column mirrors the File Preview Modal sidebar 1:1 — same
// file card (white edge-to-edge band), same Location in the Platform
// 3-bullet path, same Entry context (icon + title + 3 metadata rows).
// Difference vs the modal: no glass blur (print can't render backdrop-
// filter), more solid backgrounds, canonical platform shadow.
//
// Reuses paPickEntryIcon → same icon as the modal + entry row card.
// Preserves data-print-entry-id + data-print-page-cards so the Customize
// tree exclusion logic continues to work.
//
// Per Violetka 2026-05-12: "create this print preview for every file
// uploaded in Sarah's entries" → Option A confirmed.
// ─────────────────────────────────────────────────────────────────────
function paBuildPrintDocumentPage(entry, file, cardKey) {
    function esc(s) { return String(s == null ? '' : s).replace(/[&<>"']/g, function(c) { return ({'&':'&amp;','<':'&lt;','>':'&gt;','"':'&quot;',"'":'&#39;'})[c]; }); }
    var page = document.createElement('div');
    page.className = 'print-page print-content-page print-doc-preview-page';
    page.setAttribute('data-print-entry-id', entry.id);
    page.setAttribute('data-print-page-cards', cardKey);

    // File metadata
    var filename = (file && file.name) || (entry.title + '.pdf');
    var fileType = String((file && file.type) || 'PDF').toUpperCase();
    var fileIconSrc = '../img/' + fileType + '.png';

    // Entry-type icon — same logic as the modal (paPickEntryIcon).
    // Path is relative to /print/ — so prepend "../" to the img/ folder.
    var entryIcon = window.paPickEntryIcon(entry);
    var entryIconSrc = '../' + entryIcon.src;

    // Owner — Plan Owner gets "PlanAfter" / "My Profile" record path.
    var owner = (typeof window.peopleById === 'function') ? window.peopleById(entry.ownerId || 'sj') : null;
    var ownerName = owner ? owner.name : 'Sarah Johnson';
    var ownerInitials = String(ownerName).split(' ').map(function(n) { return n.charAt(0); }).join('').slice(0, 2).toUpperCase();
    var ownerPhoto = owner && owner.photo ? owner.photo : '';

    // Canonical card labels — same as modal.
    var CARD_LABEL = {
        essential:  'Essential Info',
        family:     'Family & Relationships',
        medical:    'Medical Info',
        education:  'Education',
        employment: 'Employment & Affiliations',
        beliefs:    'Beliefs, Hobbies & Interests'
    };
    var pathL1 = 'Me, Family & Network';
    var pathL2 = entry.ownerId === 'sj' ? 'My Profile' : (ownerName.split(' ')[0] + '’s Record');
    var pathL3 = CARD_LABEL[entry.cardKey] || (entry.cardKey || 'Card');

    // Unique gradient ID for the logo pill — every print page must have
    // a unique one or SVG will reuse the first one on the page.
    var gradId = 'print-logo-grad-doc-' + (entry.id || 'x') + '-' + (file && file.name ? file.name.replace(/[^a-z0-9]/gi, '') : 'f');

    // Inline avatar HTML — photo if present, otherwise initials.
    var avatarHtml = ownerPhoto
        ? '<img class="print-owner-avatar" src="' + esc(ownerPhoto) + '" alt="' + esc(ownerName) + '">' +
          '<span class="print-profile-initials" style="display:none;">' + esc(ownerInitials) + '</span>'
        : '<img class="print-owner-avatar" src="" alt="' + esc(ownerName) + '" style="display:none;">' +
          '<span class="print-profile-initials" style="display:flex;">' + esc(ownerInitials) + '</span>';

    page.innerHTML = ''
        + '<div class="print-inner">'

        +   '<!-- Logo pill (unique gradient ID per page) -->'
        +   '<div class="print-page-pill">'
        +     '<div class="logo-pill">'
        +       '<svg class="logo-outline" xmlns="http://www.w3.org/2000/svg" width="215" height="60" viewBox="0 0 215 60"><defs><linearGradient id="' + gradId + '" x1="0.463" x2="0.537" y2="1" gradientUnits="objectBoundingBox"><stop offset="0" stop-color="#fff"/><stop offset="0.184" stop-color="#fff" stop-opacity="0"/><stop offset="0.825" stop-color="#fff" stop-opacity="0"/><stop offset="1" stop-color="#fff"/></linearGradient></defs><path d="M30,1A29.008,29.008,0,0,0,18.712,56.721,28.817,28.817,0,0,0,30,59H185A29.008,29.008,0,0,0,196.288,3.279,28.817,28.817,0,0,0,185,1H30m0-1H185a30,30,0,0,1,0,60H30A30,30,0,0,1,30,0Z" fill="url(#' + gradId + ')"/></svg>'
        +       '<svg class="logo-text-svg" xmlns="http://www.w3.org/2000/svg" width="155" height="20" viewBox="0 0 155 20"><path d="M-556.741-472.732a8.936,8.936,0,0,1-1.918-2.587l1.134-1.564a7.587,7.587,0,0,0,1.905,1.648,5.108,5.108,0,0,0,2.581.65,3.914,3.914,0,0,0,2.255-.674,4.737,4.737,0,0,0,1.616-1.925,6.788,6.788,0,0,0,.6-2.936,6.44,6.44,0,0,0-.543-2.744,4.5,4.5,0,0,0-1.5-1.817,3.829,3.829,0,0,0-2.2-.65,3.7,3.7,0,0,0-2.316.866,10.8,10.8,0,0,0-2.171,2.443c-.482.71-.989,1.5-1.5,2.347l-1.061,1.769a36.988,36.988,0,0,1-2.2,3.321,10.694,10.694,0,0,1-2.762,2.635,6.147,6.147,0,0,1-3.389.951,5.7,5.7,0,0,1-3.57-1.191,7.644,7.644,0,0,1-2.4-3.309,13.046,13.046,0,0,1-.844-4.886,12.674,12.674,0,0,1,.82-4.8,7.33,7.33,0,0,1,2.316-3.177,5.46,5.46,0,0,1,3.389-1.143,5.918,5.918,0,0,1,4.052,1.769,8.942,8.942,0,0,1,1.918,2.7l-1.085,1.5a8.009,8.009,0,0,0-1.978-1.733,5.107,5.107,0,0,0-2.581-.65,3.947,3.947,0,0,0-2.231.674,4.6,4.6,0,0,0-1.628,1.925,6.793,6.793,0,0,0-.6,2.936,6.476,6.476,0,0,0,.543,2.744,4.4,4.4,0,0,0,1.5,1.817,3.775,3.775,0,0,0,2.195.65,3.585,3.585,0,0,0,2.34-.891,12.358,12.358,0,0,0,2.171-2.443c.495-.71,1-1.516,1.508-2.359l1-1.661.109-.181c.711-1.155,1.435-2.226,2.147-3.189a10.615,10.615,0,0,1,2.762-2.66,6.081,6.081,0,0,1,3.377-.951,5.629,5.629,0,0,1,3.546,1.191,7.8,7.8,0,0,1,2.376,3.309v.012a13.04,13.04,0,0,1,.844,4.885,12.846,12.846,0,0,1-.82,4.826,7.241,7.241,0,0,1-2.292,3.177A5.457,5.457,0,0,1-552.677-471,5.94,5.94,0,0,1-556.741-472.732Z" transform="translate(575 491)" fill="#000"/></svg>'
        +     '</div>'
        +   '</div>'

        +   '<span class="print-section-title">My Profile</span>'

        +   '<!-- LEFT column header: photo + name pad + Verified -->'
        +   '<div class="print-profile-photo">' + avatarHtml + '</div>'
        +   '<div class="print-name-pad"></div>'
        +   '<span class="print-name-text">' + esc(ownerName) + '</span>'
        +   '<span class="print-name-role">' + (entry.ownerId === 'sj' ? 'Plan Owner' : esc((owner && (owner.role || owner.relationship)) || '')) + '</span>'
        +   '<span class="print-verified-text">Verified</span>'
        +   '<img class="print-check-badge" src="../img/check-badge.png" alt="">'
        +   '<div class="print-plan-bar"></div>'

        +   '<!-- LEFT column: page heading + description -->'
        +   '<span style="position:absolute;top:672px;left:120px;width:320px;height:132px;font:normal normal 600 36px/44px \'Inter\',sans-serif;color:#000000;">Attached Document</span>'
        +   '<span style="position:absolute;top:834px;left:120px;width:320px;height:240px;font:normal normal normal 16px/24px \'Inter\',sans-serif;color:#000000;">This file is stored digitally in your Plan and can be accessed through the platform. Use the Location below to navigate to it inside PlanAfter, or refer to the Entry context for the original document\'s metadata and where the physical copy is kept.</span>'

        +   '<!-- RIGHT column: File card + Location + Entry context (mirrors File Preview Modal) -->'

        +   '<!-- File card — solid white pad, 600×60, PDF icon + filename -->'
        +   '<div class="print-fp-filecard">'
        +     '<img class="print-fp-filecard-icon" src="' + fileIconSrc + '" alt="">'
        +     '<span class="print-fp-filecard-name">' + esc(filename) + '</span>'
        +   '</div>'

        +   '<!-- Section 1: Location in the Platform -->'
        +   '<div class="print-fp-section print-fp-section-location">'
        +     '<div class="print-fp-section-head">'
        +       '<span class="print-fp-section-icon"><img src="../img/in-folder.png" srcset="../img/in-folder.png 1x, ../img/in-folder@2x.png 2x" width="20" height="16" alt=""></span>'
        +       '<span class="print-fp-section-label">Location in the Platform</span>'
        +     '</div>'
        +     '<ul class="print-fp-path-list">'
        +       '<li><span class="print-fp-dot print-fp-dot-lg"></span><span class="print-fp-path-text-bold">' + esc(pathL1) + '</span></li>'
        +       '<li><span class="print-fp-dot print-fp-dot-sm"></span><span class="print-fp-path-text">' + esc(pathL2) + '</span></li>'
        +       '<li><span class="print-fp-dot print-fp-dot-sm"></span><span class="print-fp-path-text">' + esc(pathL3) + '</span></li>'
        +     '</ul>'
        +   '</div>'

        +   '<!-- Section 2: Entry context — entry-type icon + title + 3 metadata rows -->'
        +   '<div class="print-fp-section print-fp-section-entry">'
        +     '<div class="print-fp-section-head">'
        +       '<span class="print-fp-section-icon"><img src="' + entryIconSrc + '" width="' + entryIcon.w + '" height="' + entryIcon.h + '" alt=""></span>'
        +       '<span class="print-fp-section-title">' + esc(entry.title || '(Untitled)') + '</span>'
        +     '</div>'
        +     '<div class="print-fp-entry-row">'
        +       '<span class="print-fp-entry-value">' + esc(entry.subcategory || '—') + '</span>'
        +       '<span class="print-fp-entry-label">Document Type</span>'
        +     '</div>'
        +     '<div class="print-fp-entry-row">'
        +       '<span class="print-fp-entry-value">' + esc(entry.groupTitle || '—') + '</span>'
        +       '<span class="print-fp-entry-label">Group / Category</span>'
        +     '</div>'
        +     '<div class="print-fp-entry-row">'
        +       '<span class="print-fp-entry-value">' + esc(entry.location || '—') + '</span>'
        +       '<span class="print-fp-entry-label">Location of the Original</span>'
        +     '</div>'
        +   '</div>'

        +   '<!-- Footer: disclaimer + Document Created + Page number -->'
        +   '<span class="print-page-disclaimer">This document contains personal data and sensitive information, its use is at your own risk.</span>'
        +   '<span style="position:absolute;top:1803px;left:120px;width:4px;height:4px;border-radius:50%;background:#000000;"></span>'
        +   '<span class="print-footer-label" style="top:1796px;left:134px;">Document Created:</span>'
        +   '<span class="print-footer-value" data-print-now="date" style="top:1820px;left:120px;">March 16, 2026</span>'
        +   '<span style="position:absolute;top:1822px;left:247px;font:normal normal normal 14px/17px \'Inter\',sans-serif;color:#000000;opacity:0.5;">|</span>'
        +   '<span class="print-footer-value" data-print-now="time" style="top:1820px;left:262px;">18:24</span>'
        +   '<!-- Page number — left blank, page numbering is recomputed by paRenumberPages() after all doc pages are inserted. -->'
        +   '<span style="position:absolute;top:1829px;left:1004px;width:4px;height:4px;border-radius:50%;background:#000000;"></span>'
        +   '<span style="position:absolute;top:1822px;left:1018px;font:normal normal normal 14px/17px \'Inter\',sans-serif;color:#000000;">Page:</span>'
        +   '<span class="print-page-num" style="position:absolute;top:1820px;left:1065px;font:normal normal 600 16px/20px \'Inter\',sans-serif;color:#000000;text-align:right;">—</span>'
        +   '<span style="position:absolute;top:1822px;left:1085px;font:normal normal normal 14px/17px \'Inter\',sans-serif;color:#000000;opacity:0.5;">/</span>'
        +   '<span class="print-page-total" style="position:absolute;top:1820px;left:1100px;font:normal normal 600 16px/20px \'Inter\',sans-serif;color:#000000;text-align:right;">—</span>'

        + '</div>';
    return page;
}

// Build the canonical print-entry block HTML for ONE entry.
// Renders ONLY the data the owner has actually entered. No invented copy.
// Sections rendered conditionally:
//   • Status (top-right) + Header (always)
//   • Document Details — entry.fields[] (only if any non-empty)
//   • Where the Original Is — entry.location + locationDetails (only if has)
//   • Attached File — entry.files[0] (only if has)
//   • Linked Contacts — entry.relatedTo[] mapped via peopleStore (only if any)
//   • Notes — entry.notes (only if has)
function paBuildPrintEntryHTML(entry) {
    function esc(s) { return String(s == null ? '' : s).replace(/[&<>"']/g, function(c) { return ({'&':'&amp;','<':'&lt;','>':'&gt;','"':'&quot;',"'":'&#39;'})[c]; }); }
    var hasFile = !!entry.file || (Array.isArray(entry.files) && entry.files.length) || !!entry.hasFile;
    var hasLoc  = !!entry.location || !!entry.hasLocation;
    var statusText = hasFile && hasLoc ? 'Digital File &amp; Location'
                   : hasFile           ? 'Digital File'
                   : hasLoc            ? 'Location'
                   : '';
    var statusColor = hasFile && hasLoc ? '#61C553'
                    : hasFile           ? '#667EEA'
                    : hasLoc            ? '#FF9500'
                    : 'rgba(0,0,0,0.3)';
    var dateLine = '';
    if (entry.date) {
        var lbl = entry.dateLabel || 'Updated';
        if (lbl.toLowerCase() === 'updated') {
            var actor = entry.updatedBy || 'You';
            dateLine = 'Updated ' + entry.date + ' by ' + actor;
        } else {
            dateLine = lbl + ': ' + entry.date;
        }
    }
    var subtitleParts = [];
    if (entry.subcategory) subtitleParts.push(esc(entry.subcategory));
    if (dateLine) subtitleParts.push(esc(dateLine));
    var subtitle = subtitleParts.join(' &middot; ');

    var html = ''
        + (statusText ? '<div class="print-entry-status">' + statusText + ' <span class="print-entry-status-dot" style="background:' + statusColor + '"></span></div>' : '')
        + '<div class="print-entry-head">'
        +   '<div class="print-entry-circle" style="border-color:' + statusColor + '">'
        +     '<img src="img/document.png" alt="">'
        +   '</div>'
        +   '<div class="print-entry-headbody">'
        +     '<span class="print-entry-title">' + esc(entry.title || '(Untitled)') + '</span>'
        +     (subtitle ? '<span class="print-entry-subtitle">' + subtitle + '</span>' : '')
        +   '</div>'
        + '</div>';

    // Section: Document Details — structured fields
    var fields = Array.isArray(entry.fields) ? entry.fields.filter(function(f) { return f && f.label && f.value; }) : [];
    if (fields.length) {
        html += '<div class="print-entry-section">';
        html +=   '<span class="print-entry-section-eyebrow">Document Details</span>';
        fields.forEach(function(f) {
            html += '<div class="print-entry-field">'
                 +    '<span class="print-entry-field-value">' + esc(f.value) + '</span>'
                 +    '<span class="print-entry-field-label">' + esc(f.label) + '</span>'
                 +  '</div>';
        });
        html += '</div>';
    }

    // Section: Where the Original Is — location + details
    if (hasLoc && entry.location) {
        html += '<div class="print-entry-section">';
        html +=   '<span class="print-entry-section-eyebrow">Where the Original Is</span>';
        html +=   '<div class="print-entry-field">';
        html +=     '<span class="print-entry-field-value">' + esc(entry.location) + '</span>';
        html +=     '<span class="print-entry-field-label">Location of the original document</span>';
        html +=   '</div>';
        if (entry.locationDetails) {
            html += '<div class="print-entry-notes" style="margin-top:14px">' + esc(entry.locationDetails) + '</div>';
        }
        html += '</div>';
    }

    // Section: Attached File — first file with preview placeholder
    var f0 = (entry.files && entry.files[0]) || entry.file;
    if (hasFile && f0) {
        html += '<div class="print-entry-section">';
        html +=   '<span class="print-entry-section-eyebrow">Attached File</span>';
        html +=   '<div class="print-entry-file">';
        html +=     '<div class="print-entry-file-icon"><img src="img/PDF.svg" alt="PDF"></div>';
        html +=     '<div class="print-entry-file-body">';
        html +=       '<span class="print-entry-file-name">' + esc(f0.name || (entry.title + '.pdf')) + '</span>';
        html +=       '<div class="print-entry-file-preview">First page preview</div>';
        html +=     '</div>';
        html +=   '</div>';
        html += '</div>';
    }

    // Section: Linked Contacts — relatedTo[] mapped to peopleStore.
    // Option C inline summary: avatar + name + role + ONE phone + ONE email
    // + cross-reference to Critical Contacts (P3) for full details. Keeps
    // the entry compact while still actionable for an heir who reads only
    // this entry. Multiple phones/emails/address/DOB are reserved for P3.
    var related = Array.isArray(entry.relatedTo) ? entry.relatedTo : [];
    if (related.length) {
        html += '<div class="print-entry-section">';
        html +=   '<span class="print-entry-section-eyebrow">Linked Contacts</span>';
        related.forEach(function(pid) {
            var p = (typeof window.peopleById === 'function') ? window.peopleById(pid) : null;
            if (!p) return;
            var initials = String((p.name || '?')).split(' ').map(function(n) { return n.charAt(0); }).join('').slice(0, 2).toUpperCase();
            var avatarInner = p.photo
                ? '<img src="' + esc(p.photo) + '" alt="">'
                : esc(initials);
            var phone = _paFirstPhone(p);
            var email = _paFirstEmail(p);
            var role = p.role || p.relationship || '';
            html += '<div class="print-entry-contact">';
            html +=   '<div class="print-entry-contact-avatar">' + avatarInner + '</div>';
            html +=   '<div class="print-entry-contact-body">';
            html +=     '<span class="print-entry-contact-name">' + esc(p.name || '(Unnamed)') + '</span>';
            if (role)  html += '<span class="print-entry-contact-role">' + esc(role) + '</span>';
            if (phone) html += '<span class="print-entry-contact-line"><span class="print-entry-contact-label">Phone</span> ' + esc(phone) + '</span>';
            if (email) html += '<span class="print-entry-contact-line"><span class="print-entry-contact-label">Email</span> ' + esc(email) + '</span>';
            html +=     '<span class="print-entry-contact-xref">&rarr; Full details on page 3 (Critical Contacts)</span>';
            html +=   '</div>';
            html += '</div>';
        });
        html += '</div>';
    }

    // Section: Notes
    if (entry.notes && entry.notes.trim()) {
        html += '<div class="print-entry-section">';
        html +=   '<span class="print-entry-section-eyebrow">Notes</span>';
        html +=   '<div class="print-entry-notes">' + esc(entry.notes) + '</div>';
        html += '</div>';
    }
    return html;
}

// ===== Render ALL entries owned by a given person into Overview cards =====
// Used by record.html to populate the Overview tab with the viewed person's
// own entries. Calls paInjectEntryRowFromStore for each entry, then runs the
// canonical post-injection passes so expand-bodies + empty states are correct.
window.paRenderOverviewEntriesForPerson = function paRenderOverviewEntriesForPerson(personId) {
    if (!personId || !Array.isArray(window.entriesStore)) return;
    // Owned entries — created on THIS record (editable here)
    const own = window.entriesStore.filter(function(e) { return e && e.ownerId === personId && !e.archived; });
    own.forEach(function(e) {
        try { window.paInjectEntryRowFromStore(e, { isLinked: false }); } catch(err) { console.warn('[paRenderOverviewEntriesForPerson] inject owned failed', e.id, err); }
    });
    // Linked entries — created in OTHER records but reference this person via
    // relatedTo[] / linkedContactIds[]. Read-only projection rendered under a
    // "Linked Entries" subtitle. Per Violetka 2026-05-11: cross-record visibility
    // is via subtitle WITHIN the same card group (NOT a separate tab).
    const linked = window.entriesStore.filter(function(e) {
        if (!e || e.archived) return false;
        if (e.ownerId === personId) return false; // already rendered above
        const related = e.relatedTo || e.linkedContactIds || [];
        return Array.isArray(related) && related.indexOf(personId) !== -1;
    });
    linked.forEach(function(e) {
        try { window.paInjectEntryRowFromStore(e, { isLinked: true }); } catch(err) { console.warn('[paRenderOverviewEntriesForPerson] inject linked failed', e.id, err); }
    });
    // Post-injection passes — populate expand bodies, refresh empty states.
    if (typeof window.buildAllMedicalEntries === 'function') {
        try { window.buildAllMedicalEntries(); } catch(err) {}
    }
    if (typeof window.paUpdateAllEmptyStates === 'function') {
        try { window.paUpdateAllEmptyStates(); } catch(err) {}
    }
    if (typeof window.paHideEmptyCardGroups === 'function') {
        try { window.paHideEmptyCardGroups(); } catch(err) {}
    }
};

// ===== Universal Life-Status Sync =====
// On every page load, walk all elements that represent a person and update their
// life-dot color + In-Memory styling based on the canonical peopleStore.lifeStatus.
//
// Element conventions supported (all canonical):
//   [data-person-id="jj"]     — direct id reference (preferred)
//   [data-person="emma"]      — name slug (legacy in family.html / network.html)
//
// Inside each matched wrapper, we tag the element with data-life-status="..."
// (which the universal CSS rules in _shared.css consume to color the inner
// .lsc-life-dot / .ee-person-life-dot / .ftree-life-dot / .ei-life-dot) AND
// for the legacy .ftree-life-dot pattern (uses .alive / .deceased class names),
// we directly swap classes so existing CSS keeps working.
//
// This is idempotent — safe to call repeatedly after edits/saves to refresh.
window.paSyncLifeDots = function paSyncLifeDots() {
    if (!Array.isArray(window.peopleStore)) return;
    var people = window.peopleStore;
    function findPerson(token) {
        if (!token) return null;
        var t = String(token).toLowerCase().trim();
        // 1) exact id match
        var hit = people.find(function(p){ return p.id === t; });
        if (hit) return hit;
        // 2) firstName.toLowerCase() match (handles "emma", "liam", "sarah", "ben")
        hit = people.find(function(p){ return (p.firstName || '').toLowerCase() === t; });
        if (hit) return hit;
        // 3) hyphenated name slug match (e.g. "john-smith" → "John Smith")
        var slug = t.replace(/-/g, ' ');
        hit = people.find(function(p){ return (p.name || '').toLowerCase() === slug; });
        if (hit) return hit;
        // 4) firstName + lastName slug ("ben white" / "ben-white")
        hit = people.find(function(p){
            var s = ((p.firstName || '') + ' ' + (p.familyName || '')).toLowerCase().trim();
            return s === slug;
        });
        return hit || null;
    }
    function statusOf(p) {
        if (!p) return 'living';
        var s = (p.lifeStatus || (p.alive === false ? 'Deceased' : 'Living')).toLowerCase();
        if (s !== 'deceased' && s !== 'unknown') s = 'living';
        return s;
    }
    document.querySelectorAll('[data-person-id], [data-person]').forEach(function(wrap) {
        var token = wrap.getAttribute('data-person-id') || wrap.getAttribute('data-person');
        var person = findPerson(token);
        if (!person) return;
        var status = statusOf(person);
        wrap.setAttribute('data-life-status', status);
        wrap.classList.toggle('pa-in-memory', status === 'deceased');
        // Legacy .ftree-life-dot uses .alive/.deceased class names — swap them
        wrap.querySelectorAll('.ftree-life-dot').forEach(function(d) {
            d.classList.remove('alive', 'deceased', 'unknown');
            d.classList.add(status === 'living' ? 'alive' : status);
        });
        // Legacy .ftree-card-deceased / .ftree-card-living wrapper variants
        wrap.classList.toggle('ftree-card-deceased', status === 'deceased');
    });
};
// ===== Universal Person-Avatar Sync =====
// Walks every [data-person-id] / [data-person] wrapper and updates the
// inner photo + initials state based on peopleStore. Solves the problem
// where summary cards / tree avatars hardcoded broken filenames like
// img/sarah.png that don't exist — now the photo always comes from the
// canonical peopleStore record.
//
// For Plan Owner (id 'sj'), respects window.planOwnerPhoto (the localStorage-
// backed override) so user-uploaded photo flows through.
//
// Idempotent — safe to call on every render.
window.paSyncPersonAvatars = function paSyncPersonAvatars() {
    if (!Array.isArray(window.peopleStore)) return;
    var people = window.peopleStore;
    function findPerson(token) {
        if (!token) return null;
        var t = String(token).toLowerCase().trim();
        var hit = people.find(function(p){ return p.id === t; });
        if (hit) return hit;
        hit = people.find(function(p){ return (p.firstName || '').toLowerCase() === t; });
        if (hit) return hit;
        var slug = t.replace(/-/g, ' ');
        hit = people.find(function(p){ return (p.name || '').toLowerCase() === slug; });
        if (hit) return hit;
        hit = people.find(function(p){
            var s = ((p.firstName || '') + ' ' + (p.familyName || '')).toLowerCase().trim();
            return s === slug;
        });
        return hit || null;
    }
    function resolvePhoto(person) {
        if (!person) return '';
        // Plan Owner: prefer the live planOwnerPhoto (user upload via localStorage)
        if (person.id === 'sj' && typeof window.planOwnerPhoto === 'string' && window.planOwnerPhoto) return window.planOwnerPhoto;
        // Otherwise: peoplePhoto helper or person.photo directly
        return (typeof window.peoplePhoto === 'function' ? window.peoplePhoto(person) : null) || person.photo || '';
    }
    document.querySelectorAll('[data-person-id], [data-person]').forEach(function(wrap) {
        var token = wrap.getAttribute('data-person-id') || wrap.getAttribute('data-person');
        var person = findPerson(token);
        if (!person) return;
        var photo = resolvePhoto(person);
        // Update every img inside this wrapper that's NOT a child wrapper's
        // own person-img (rare nested case — defensive querySelectorAll skips
        // imgs that have a closer [data-person] ancestor inside the wrap).
        // Per-person crop (applies on top of the photo so reposition persists
        // everywhere this person's avatar appears: summary cards, family tree,
        // network list, header in their own record, etc.). Defaults centered.
        var perCropX = person.cropX != null ? person.cropX : 50;
        var perCropY = person.cropY != null ? person.cropY : 50;
        var perScale = person.scale != null ? person.scale : 1;
        var perPos   = perCropX + '% ' + perCropY + '%';
        var perSc    = 'scale(' + perScale + ')';
        wrap.querySelectorAll('img').forEach(function(img) {
            // Skip imgs that live in a NESTED data-person wrapper
            var nestedAncestor = img.parentElement && img.parentElement.closest('[data-person-id], [data-person]');
            if (nestedAncestor && nestedAncestor !== wrap) return;
            // Skip life-dot or icon imgs (not avatars)
            if (img.classList.contains('ftree-life-dot') || img.classList.contains('icon')) return;
            if (photo) {
                img.src = photo;
                img.style.display = '';
                img.style.objectFit = 'cover';
                img.style.objectPosition = perPos;
                img.style.transform = perSc;
                img.style.transformOrigin = 'center center';
                img.removeAttribute('data-pa-no-photo');
            } else {
                img.removeAttribute('src');
                img.style.display = 'none';
                img.setAttribute('data-pa-no-photo', '1');
            }
        });
        // If no photo, expose initials span (if any) — convention: an inline
        // sibling element with class containing 'initials' or 'monogram'.
        wrap.querySelectorAll('.lsc-avatar-monogram, .ee-person-monogram, .emc-avatar-initials, .ftree-initials, .lsc-initials').forEach(function(el) {
            if (photo) {
                el.style.display = 'none';
            } else {
                el.style.display = '';
                if (!el.textContent.trim()) {
                    el.textContent = (typeof window.peopleInitials === 'function') ? window.peopleInitials(person) : '';
                }
            }
        });
    });
    // After syncing all avatars, re-run the clipping pass so any newly-rendered
    // IMG (e.g. one whose src was just set + appeared) gets its .pa-avatar-clip
    // wrapper. This guarantees zoomed photos NEVER leak past the small circle
    // on any surface — including dynamic content rendered after page load.
    if (typeof window.paEnsureAvatarClipping === 'function') {
        try { window.paEnsureAvatarClipping(document); } catch (e) {}
    }
};

// ===== Universal fit-text-on-one-line helper =====
// Violetka 2026-05-18: "тук леко намаляваме едва забележимо шрифта за да го
// съберем на един ред както и навсякъде където не се събира на един ред".
//
// Long role labels ("Biological Grandmother", "Adopted Step-Father", "Maternal
// Great-Grandmother", "Your Brother-in-Law") must never wrap to two lines on
// a compact summary card. We measure the rendered text width against the
// container's content-box width and decrement font-size by 0.5 px until it
// fits or hits a hard floor (default 10 px). Short roles ("Mother", "Son")
// don't trigger any change since they fit at the canonical size on first try.
//
// Usage: pair with .pa-fit-on-one-line (or any element with white-space:nowrap)
// and call paFitTextOnOneLine(el) on every render of that element.
window.paFitTextOnOneLine = function paFitTextOnOneLine(el, opts) {
    if (!el || el.nodeType !== 1) return;
    opts = opts || {};
    var minFont = typeof opts.minFontPx === 'number' ? opts.minFontPx : 10;
    var maxStep = typeof opts.maxSteps === 'number' ? opts.maxSteps : 12; // safety cap
    // Reset any previous shrink so we measure from the canonical size first.
    el.style.fontSize = '';
    el.style.whiteSpace = 'nowrap';
    var canonical = parseFloat(getComputedStyle(el).fontSize);
    if (!canonical || !isFinite(canonical)) return;
    // Available width = parent content-box (the card's info column typically).
    var parent = el.parentElement;
    if (!parent) return;
    var pcs = getComputedStyle(parent);
    var avail = parent.clientWidth
              - parseFloat(pcs.paddingLeft || 0)
              - parseFloat(pcs.paddingRight || 0);
    if (avail <= 0) return;
    var current = canonical;
    var step = 0;
    while (el.scrollWidth > avail && current > minFont && step < maxStep) {
        current -= 0.5;
        el.style.fontSize = current + 'px';
        step++;
    }
    // No need to keep an explicit style when we never shrunk — keeps DOM tidy.
    if (current === canonical) el.style.fontSize = '';
};

// Fit every .ftree-role within a given root (defaults to the family tree canvas).
// Called automatically after the renderer paints cards. Cheap — only iterates
// the role labels and only those that overflow actually mutate their style.
window.paFitFtreeRoles = function paFitFtreeRoles(root) {
    root = root || document.getElementById('ftreeCanvas') || document;
    var roleNodes = root.querySelectorAll('.ftree-role');
    for (var i = 0; i < roleNodes.length; i++) {
        window.paFitTextOnOneLine(roleNodes[i]);
    }
    // Same one-row guarantee for the date+age meta line. Deceased dates
    // ("Feb 5, 1918 – Nov 2, 1998 · Age 80") are ~33 chars and overflow
    // the 151px card width. Lower minFontPx to 8 so dates always fit on
    // one row even at the narrowest summary-card widths. Violetka
    // 2026-05-21: "датите да се събират на един ред".
    var metaNodes = root.querySelectorAll('.ftree-meta');
    for (var j = 0; j < metaNodes.length; j++) {
        window.paFitTextOnOneLine(metaNodes[j], { minFontPx: 8 });
    }
};


// Hover handler — when hovering an .ftree-card, BFS the relationship graph from
// that person back to the anchor (Sarah / sj) and brighten those line paths.
window.paInstallFamilyTreeHover = window.paInstallFamilyTreeHover || function() {
    var canvas = document.getElementById('ftreeCanvas');
    var svg = document.getElementById('ftreeLines');
    if (!canvas || !svg) return;
    var SLUG_TO_ID = {
        'sarah':'sj', 'john':'jj', 'emma':'em', 'liam':'li', 'lisa':'ls', 'noah':'no',
        'mary':'ms', 'robert':'rs', 'enzo':'enzo', 'jack':'jd',
        'jane':'jds', 'john-smith':'jsm', 'ben':'bw'
    };
    function pathToAnchor(personId, anchorId) {
        if (personId === anchorId) return [];
        // BFS through peopleStore.relationships graph
        var people = window.peopleStore || [];
        var queue = [{ id: personId, path: [] }];
        var seen = {}; seen[personId] = true;
        while (queue.length) {
            var cur = queue.shift();
            var p = people.find(function(x) { return x.id === cur.id; });
            if (!p) continue;
            var neighbors = (p.relationships || []).map(function(r) { return r.toId; });
            // Reverse — anyone with us in their relationships
            people.forEach(function(other) {
                (other.relationships || []).forEach(function(r) {
                    if (r.toId === cur.id && neighbors.indexOf(other.id) === -1) {
                        neighbors.push(other.id);
                    }
                });
            });
            for (var i = 0; i < neighbors.length; i++) {
                var nbId = neighbors[i];
                if (seen[nbId]) continue;
                seen[nbId] = true;
                var newPath = cur.path.concat([[cur.id, nbId]]);
                if (nbId === anchorId) return newPath;
                queue.push({ id: nbId, path: newPath });
            }
        }
        return [];
    }
    canvas.addEventListener('mouseover', function(e) {
        var card = e.target.closest && e.target.closest('.ftree-card');
        if (!card) return;
        // Resolve personId from data-person (slug OR direct id, depending on renderer) or
        // data-person-id (injected cards). Violetka 2026-05-18: the new _data/familyTree.js
        // renderer writes the peopleStore id directly into data-person (e.g. data-person="sj"),
        // so try SLUG_TO_ID first, then fall through to treating the value AS the id.
        var slugOrId = card.getAttribute('data-person');
        var pid = SLUG_TO_ID[slugOrId] || slugOrId || card.getAttribute('data-person-id');
        if (!pid) return;
        // Anchor — first .ftree-card-anchor in DOM (sj)
        var anchorCard = canvas.querySelector('.ftree-card-anchor');
        var anchorSlugOrId = anchorCard ? anchorCard.getAttribute('data-person') : 'sarah';
        var anchorId = SLUG_TO_ID[anchorSlugOrId] || anchorSlugOrId || (anchorCard && anchorCard.getAttribute('data-person-id')) || 'sj';
        if (pid === anchorId) return; // hovering anchor itself
        var hops = pathToAnchor(pid, anchorId);
        hops.forEach(function(pair) {
            var p1 = pair[0], p2 = pair[1];
            svg.querySelectorAll('path').forEach(function(path) {
                var f = path.getAttribute('data-from');
                var t = path.getAttribute('data-to');
                if ((f === p1 && t === p2) || (f === p2 && t === p1)) {
                    path.classList.add('highlight');
                }
            });
        });
    });
    canvas.addEventListener('mouseout', function(e) {
        var card = e.target.closest && e.target.closest('.ftree-card');
        if (!card) return;
        svg.querySelectorAll('path.highlight').forEach(function(path) {
            path.classList.remove('highlight');
        });
    });
};

// Auto-run on page load + redraw when the Family Tree tab becomes visible.
// The tree canvas can be in a hidden tab on first paint, so getBoundingClientRect
// returns zeros. We watch for the canvas becoming visible (size > 0) and redraw.
function paFamilyTreeReady() {
    var canvas = document.getElementById('ftreeCanvas');
    if (!canvas) return false;
    var rect = canvas.getBoundingClientRect();
    return rect.width > 100 && rect.height > 100;
}
function paFamilyTreeRedraw() {
    if (window.paInjectNewFamilyMembersIntoTree) window.paInjectNewFamilyMembersIntoTree();
    // Line drawing intentionally removed (Violetka 2026-05-18): the previous
    // paDrawFamilyTreeLines + makeArch + step/former-spouse helpers were torn
    // out so Violetka can drop in a clean replacement. paRenderTreeLines (in
    // _data/familyTree.js) is now a no-op stub that just empties the SVG.
    if (window.paRenderTreeLines && window.__paTreeLayout) {
        try { window.paRenderTreeLines(window.__paTreeLayout); } catch (e) {}
    }
    if (window.paInstallFamilyTreeHover && !window.__paTreeHoverInstalled) {
        window.paInstallFamilyTreeHover();
        window.__paTreeHoverInstalled = true;
    }
    // Shrink long role labels ("Biological Grandmother", "Adopted Step-Father")
    // so they fit on a single line inside the compact 240 px tree card. Cheap
    // — only nodes that overflow at canonical 12 px actually mutate their style.
    if (window.paFitFtreeRoles) window.paFitFtreeRoles();
}
// Inject family members from peopleStore into the hardcoded Family Tree
// generation rows. Hardcoded children/parents/grandparents stay; any
// peopleStore Family record NOT already in the tree gets appended to its
// proper generation row based on relationship type (Layer 1 / rel.type).
// Per Violetka 2026-05-13: Victor (Layer 1=Children) should appear at the
// Children level in family-tree visualization alongside Emma/Liam/Lisa/Noah.
// Relationship Engine — XD-LOCKED Violetka 2026-05-13 spec 2.2.3 §1-3.
// On every save/create/edit/delete:
//   TIER A (auto-create, no confirmation): logically certain links.
//     • Bidirectional inverse of toId='sj' link
//       (Victor → Sarah.Children  ⟺  Sarah → Victor.Parents)
//   TIER B (suggested, needs confirmation): plausible but not guaranteed.
//     • Sarah's spouse (John) → SUGGEST new child as Children
//     • Sarah's other children (Emma/Liam/Lisa/Noah) → SUGGEST new child as Siblings
//     • Sarah's parents (Mary/Robert) → SUGGEST new child as Grandchildren
//
// ALL writes go through ensureRel / ensureSuggestion which check existing
// entries by toId/fromId BEFORE adding — so multiple engine passes never
// create duplicates.
// ────────────────────────────────────────────────────────────────────────────
// paComputeInverseRel — SHARED inverse helper. Given a relationship type +
// specificRole + the relationship-OWNER's gender, returns the corresponding
// inverse for the OTHER person's perspective.
//
// Example: Sarah (female) says "Victor is my Child / Biological Son".
//   paComputeInverseRel('Children', 'Biological Son', 'female')
//     → { type: 'Parents', specificRole: 'Biological Mother' }
//   meaning Victor's record should read "Sarah is my Parent / Biological Mother".
//
// Used by:
//   • saveContactEdit — to compute the OTHER side of a freshly-created rel.
//   • paRelationshipEngine — migration pass for legacy wrong-direction data.
//   • paInjectFamilyMembersIntoFRCard — to label suggested cards correctly.
// ────────────────────────────────────────────────────────────────────────────
// ──────────────────────────────────────────────────────────────────────────
// paNormalizeRelType — convert form Layer 1 strings ("Children",
// "Spouses / Partners", "Former Partner / Spouse", "Pets") into the canonical
// lowercase-singular edge type ("child", "spouse", "former-spouse", "pet-of")
// that the rest of the data layer expects (paGroupRelationships uses these,
// the seed stores these, paInverseEdgeType maps these).
//
// If the input is already a canonical edge type (lowercase singular), returns
// it unchanged. Used by saveContactEdit + engine migration so EVERYWHERE the
// rel.type is the SAME format across new + legacy data.
// ──────────────────────────────────────────────────────────────────────────
// ──────────────────────────────────────────────────────────────────────────
// paCleanupOrphanRelationships — single source of truth for relationship
// hygiene. Walks the entire peopleStore and removes any relationship link
// (and suggested-relationship link) whose target person no longer exists.
//
// WHY this exists:
//   Earlier versions of openDeleteRecordModal did NOT cascade-clean the
//   relationships array on the REMAINING persons after deleting a target.
//   Result: Sarah's relationships could contain a {toId:'X'} pointing to
//   a person ID that's no longer in peopleStore — an ORPHAN reference.
//   Orphans are invisible (no card rendered) but COUNTED in stats →
//   "7 Number of Children" while only 6 cards visible. Bug reported by
//   Violetka on 2026-05-14.
//
// WHEN it runs:
//   • Inside paRelationshipEngine — first pass on every engine run, so any
//     orphan that slipped through is wiped on next save/load/delete.
//   • Inside openDeleteRecordModal doDelete — called right after splice so
//     orphans are killed BEFORE the engine even runs.
//   • Safe to call from any consumer as a defensive guard.
//
// RETURN: { relsRemoved, sugsRemoved } — for logging / tests.
// IDEMPOTENT: a second call after a clean run does nothing.
// ──────────────────────────────────────────────────────────────────────────
// ──────────────────────────────────────────────────────────────────────────
// Per-Card Read Mode expanded panel (Phase 2A.1) — single source of truth
// for read-only relationship details. Triggered from frToggleMember when
// frEditMode === false. Renders into the .fr-expand-panel container that's
// already in the DOM for each .fr-card-wrap.
//
// Per spec 2.2.1.B + Violetka 2026-05-14 screenshots:
//   • Relationship Type + Specific Role — value-above-label canonical pattern
//   • "Relationship Timeline" section title (centered)
//   • Each populated milestone:
//       - "Marriage Date - Sep 28, 2005"  (label + date inline in title)
//       - Rounded read-only Details & Notes container (only if non-empty)
//   • If NO populated milestones for a role with milestones defined →
//     small muted text "No timeline details added yet."
//   • If role has NO milestones at all (Biological Son/Daughter etc.) →
//     skip the Timeline section entirely.
//   • "Hide Details" glass pill button at the bottom — collapse trigger.
// ──────────────────────────────────────────────────────────────────────────

